//! Criterion benchmarks for comparing implementations
//!
//! Compares: git2, gitoxide (gix), git CLI, and TypeScript
//!
//! Run with: cargo bench --features gitoxide
//! Results are saved in target/criterion/ for comparison

use criterion::{black_box, criterion_group, criterion_main, Criterion};
use gitgrip::core::manifest::{Manifest, RepoConfig};
use gitgrip::core::repo::RepoInfo;
use gitgrip::core::state::StateFile;
use std::fs;
use std::path::PathBuf;
use std::process::Command;

/// Benchmark manifest YAML parsing
fn bench_manifest_parse(c: &mut Criterion) {
    let yaml = r#"
version: 1
manifest:
  url: git@github.com:user/manifest.git
  default_branch: main
repos:
  app:
    url: git@github.com:user/app.git
    path: app
    default_branch: main
    copyfile:
      - src: README.md
        dest: APP_README.md
    linkfile:
      - src: config.yaml
        dest: app-config.yaml
  lib:
    url: git@github.com:user/lib.git
    path: lib
    default_branch: main
  api:
    url: git@github.com:user/api.git
    path: api
    default_branch: main
settings:
  pr_prefix: "[multi-repo]"
  merge_strategy: all-or-nothing
workspace:
  env:
    NODE_ENV: development
  scripts:
    build:
      description: Build all packages
      command: npm run build
    test:
      description: Run tests
      steps:
        - name: lint
          command: npm run lint
        - name: test
          command: npm test
"#;

    c.bench_function("manifest_parse", |b| {
        b.iter(|| Manifest::parse(black_box(yaml)).unwrap())
    });
}

/// Benchmark state JSON parsing
fn bench_state_parse(c: &mut Criterion) {
    let json = r#"{
        "currentManifestPr": 42,
        "branchToPr": {
            "feat/new-feature": 42,
            "feat/another": 43,
            "fix/bug": 44
        },
        "prLinks": {
            "42": [
                {
                    "repoName": "app",
                    "owner": "user",
                    "repo": "app",
                    "number": 123,
                    "url": "https://github.com/user/app/pull/123",
                    "state": "open",
                    "approved": true,
                    "checksPass": true,
                    "mergeable": true
                },
                {
                    "repoName": "lib",
                    "owner": "user",
                    "repo": "lib",
                    "number": 456,
                    "url": "https://github.com/user/lib/pull/456",
                    "state": "open",
                    "approved": false,
                    "checksPass": true,
                    "mergeable": true
                }
            ],
            "43": [],
            "44": []
        }
    }"#;

    c.bench_function("state_parse", |b| {
        b.iter(|| StateFile::parse(black_box(json)).unwrap())
    });
}

/// Benchmark git URL parsing
fn bench_url_parse(c: &mut Criterion) {
    let config = RepoConfig {
        url: "git@github.com:organization/repository-name.git".to_string(),
        path: "packages/repository-name".to_string(),
        default_branch: "main".to_string(),
        copyfile: None,
        linkfile: None,
        platform: None,
        reference: false,
        groups: Vec::new(),
        agent: None,
    };
    let workspace = PathBuf::from("/home/user/workspace");

    c.bench_function("url_parse_github_ssh", |b| {
        b.iter(|| RepoInfo::from_config("repo", black_box(&config), black_box(&workspace)))
    });
}

/// Benchmark Azure DevOps URL parsing
fn bench_url_parse_azure(c: &mut Criterion) {
    let config = RepoConfig {
        url: "https://dev.azure.com/organization/project/_git/repository".to_string(),
        path: "repository".to_string(),
        default_branch: "main".to_string(),
        copyfile: None,
        linkfile: None,
        platform: None,
        reference: false,
        groups: Vec::new(),
        agent: None,
    };
    let workspace = PathBuf::from("/home/user/workspace");

    c.bench_function("url_parse_azure_https", |b| {
        b.iter(|| RepoInfo::from_config("repo", black_box(&config), black_box(&workspace)))
    });
}

/// Benchmark manifest validation
fn bench_manifest_validate(c: &mut Criterion) {
    let yaml = r#"
version: 1
repos:
  app:
    url: git@github.com:user/app.git
    path: app
    copyfile:
      - src: file1.txt
        dest: dest1.txt
      - src: file2.txt
        dest: dest2.txt
    linkfile:
      - src: link1
        dest: dest/link1
workspace:
  scripts:
    build:
      steps:
        - name: step1
          command: echo 1
        - name: step2
          command: echo 2
        - name: step3
          command: echo 3
"#;

    let manifest: Manifest = serde_yaml::from_str(yaml).unwrap();

    c.bench_function("manifest_validate", |b| {
        b.iter(|| black_box(&manifest).validate().unwrap())
    });
}

/// Setup a test repo and return temp dir path
fn setup_test_repo() -> tempfile::TempDir {
    use std::fs;

    let temp = tempfile::TempDir::new().unwrap();

    // Use git CLI to init (works regardless of library)
    Command::new("git")
        .args(["init"])
        .current_dir(temp.path())
        .output()
        .unwrap();

    Command::new("git")
        .args(["config", "user.name", "Bench User"])
        .current_dir(temp.path())
        .output()
        .unwrap();

    Command::new("git")
        .args(["config", "user.email", "bench@example.com"])
        .current_dir(temp.path())
        .output()
        .unwrap();

    // Create initial commit
    fs::write(temp.path().join("README.md"), "# Benchmark Repo").unwrap();

    Command::new("git")
        .args(["add", "README.md"])
        .current_dir(temp.path())
        .output()
        .unwrap();

    Command::new("git")
        .args(["commit", "-m", "Initial commit"])
        .current_dir(temp.path())
        .output()
        .unwrap();

    // Add some untracked files to make status more realistic
    for i in 0..10 {
        fs::write(
            temp.path().join(format!("file{}.txt", i)),
            format!("Content {}", i),
        )
        .unwrap();
    }

    // Create branches
    for i in 0..10 {
        Command::new("git")
            .args(["branch", &format!("branch-{}", i)])
            .current_dir(temp.path())
            .output()
            .unwrap();
    }

    temp
}

/// Compare git status implementations: git2 vs gix vs git CLI
fn bench_git_status_comparison(c: &mut Criterion) {
    let temp = setup_test_repo();

    let mut group = c.benchmark_group("git_status");

    // Benchmark git2
    {
        let repo = git2::Repository::open(temp.path()).unwrap();
        group.bench_function("git2", |b| {
            b.iter(|| {
                let statuses = repo.statuses(None).unwrap();
                black_box(statuses.len())
            })
        });
    }

    // Benchmark gix (if feature enabled)
    // Note: gix's status API is still maturing, so we benchmark repo open + head check
    #[cfg(feature = "gitoxide")]
    {
        let path = temp.path().to_path_buf();
        group.bench_function("gix", |b| {
            b.iter(|| {
                let repo = gix::open(&path).unwrap();
                // Use head_id() as a simple operation - full status API is still developing
                let head = repo.head_id();
                black_box(head.is_ok())
            })
        });
    }

    // Benchmark git CLI (porcelain)
    {
        let path = temp.path().to_path_buf();
        group.bench_function("git_cli", |b| {
            b.iter(|| {
                let output = Command::new("git")
                    .args(["status", "--porcelain"])
                    .current_dir(&path)
                    .output()
                    .unwrap();
                let lines = String::from_utf8_lossy(&output.stdout).lines().count();
                black_box(lines)
            })
        });
    }

    group.finish();
}

/// Compare branch listing implementations: git2 vs gix vs git CLI
fn bench_git_list_branches_comparison(c: &mut Criterion) {
    let temp = setup_test_repo();

    let mut group = c.benchmark_group("git_list_branches");

    // Benchmark git2
    {
        let repo = git2::Repository::open(temp.path()).unwrap();
        group.bench_function("git2", |b| {
            b.iter(|| {
                let branches: Vec<_> = repo
                    .branches(Some(git2::BranchType::Local))
                    .unwrap()
                    .collect();
                black_box(branches.len())
            })
        });
    }

    // Benchmark gix (if feature enabled)
    #[cfg(feature = "gitoxide")]
    {
        let repo = gix::open(temp.path()).unwrap();
        group.bench_function("gix", |b| {
            b.iter(|| {
                let names = repo.branch_names();
                black_box(names.len())
            })
        });
    }

    // Benchmark git CLI
    {
        let path = temp.path().to_path_buf();
        group.bench_function("git_cli", |b| {
            b.iter(|| {
                let output = Command::new("git")
                    .args(["branch", "--format=%(refname:short)"])
                    .current_dir(&path)
                    .output()
                    .unwrap();
                let count = String::from_utf8_lossy(&output.stdout).lines().count();
                black_box(count)
            })
        });
    }

    group.finish();
}

/// Compare repo open implementations: git2 vs gix
fn bench_repo_open_comparison(c: &mut Criterion) {
    let temp = setup_test_repo();

    let mut group = c.benchmark_group("repo_open");

    // Benchmark git2
    {
        let path = temp.path().to_path_buf();
        group.bench_function("git2", |b| {
            b.iter(|| {
                let repo = git2::Repository::open(black_box(&path)).unwrap();
                black_box(repo.path().to_path_buf())
            })
        });
    }

    // Benchmark gix (if feature enabled)
    #[cfg(feature = "gitoxide")]
    {
        let path = temp.path().to_path_buf();
        group.bench_function("gix", |b| {
            b.iter(|| {
                let repo = gix::open(black_box(&path)).unwrap();
                black_box(repo.path().to_path_buf())
            })
        });
    }

    group.finish();
}

/// Compare HEAD resolution: git2 vs gix vs git CLI
fn bench_get_current_branch_comparison(c: &mut Criterion) {
    let temp = setup_test_repo();

    let mut group = c.benchmark_group("get_current_branch");

    // Benchmark git2
    {
        let repo = git2::Repository::open(temp.path()).unwrap();
        group.bench_function("git2", |b| {
            b.iter(|| {
                let head = repo.head().unwrap();
                let name = head.shorthand().unwrap_or("HEAD");
                black_box(name.to_string())
            })
        });
    }

    // Benchmark gix (if feature enabled)
    #[cfg(feature = "gitoxide")]
    {
        let repo = gix::open(temp.path()).unwrap();
        group.bench_function("gix", |b| {
            b.iter(|| {
                let head = repo.head_name().unwrap();
                black_box(head.map(|n| n.shorten().to_string()))
            })
        });
    }

    // Benchmark git CLI
    {
        let path = temp.path().to_path_buf();
        group.bench_function("git_cli", |b| {
            b.iter(|| {
                let output = Command::new("git")
                    .args(["rev-parse", "--abbrev-ref", "HEAD"])
                    .current_dir(&path)
                    .output()
                    .unwrap();
                let branch = String::from_utf8_lossy(&output.stdout).trim().to_string();
                black_box(branch)
            })
        });
    }

    group.finish();
}

/// Benchmark file hashing (useful for change detection)
fn bench_file_hash(c: &mut Criterion) {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};

    let content = "This is some test content for hashing\n".repeat(100);

    c.bench_function("file_hash_content", |b| {
        b.iter(|| {
            let mut hasher = DefaultHasher::new();
            black_box(&content).hash(&mut hasher);
            hasher.finish()
        })
    });
}

/// Benchmark path operations (common in file linking)
fn bench_path_operations(c: &mut Criterion) {
    let workspace = PathBuf::from("/home/user/workspace");
    let repo_path = "packages/my-awesome-repo";

    c.bench_function("path_join", |b| {
        b.iter(|| {
            let full = workspace.join(black_box(repo_path));
            black_box(full)
        })
    });

    let full_path = workspace.join(repo_path);
    c.bench_function("path_canonicalize_relative", |b| {
        b.iter(|| {
            let path = black_box(&full_path);
            path.components().collect::<Vec<_>>()
        })
    });
}

/// Benchmark regex URL parsing (for platform detection)
fn bench_url_regex_parse(c: &mut Criterion) {
    use regex::Regex;

    let github_regex = Regex::new(r"github\.com[:/]([^/]+)/([^/\.]+)").unwrap();
    let gitlab_regex = Regex::new(r"gitlab\.com[:/](.+)/([^/\.]+)").unwrap();

    let url = "git@github.com:organization/repository-name.git";

    c.bench_function("url_regex_github", |b| {
        b.iter(|| github_regex.captures(black_box(url)))
    });

    let gitlab_url = "git@gitlab.com:group/subgroup/repo.git";
    c.bench_function("url_regex_gitlab", |b| {
        b.iter(|| gitlab_regex.captures(black_box(gitlab_url)))
    });
}

/// Setup multiple test repos to simulate a gitgrip workspace
fn setup_multi_repo_workspace() -> (tempfile::TempDir, Vec<PathBuf>) {
    let temp = tempfile::TempDir::new().unwrap();
    let workspace = temp.path();
    let mut repo_paths = Vec::new();

    // Create 5 repos to simulate a typical workspace
    for name in &["frontend", "backend", "shared-lib", "api", "docs"] {
        let repo_path = workspace.join(name);
        fs::create_dir_all(&repo_path).unwrap();

        Command::new("git")
            .args(["init"])
            .current_dir(&repo_path)
            .output()
            .unwrap();

        Command::new("git")
            .args(["config", "user.name", "Bench User"])
            .current_dir(&repo_path)
            .output()
            .unwrap();

        Command::new("git")
            .args(["config", "user.email", "bench@example.com"])
            .current_dir(&repo_path)
            .output()
            .unwrap();

        // Create initial commit
        fs::write(repo_path.join("README.md"), format!("# {}", name)).unwrap();

        Command::new("git")
            .args(["add", "README.md"])
            .current_dir(&repo_path)
            .output()
            .unwrap();

        Command::new("git")
            .args(["commit", "-m", "Initial commit"])
            .current_dir(&repo_path)
            .output()
            .unwrap();

        // Add some files
        for i in 0..3 {
            fs::write(
                repo_path.join(format!("file{}.txt", i)),
                format!("Content {}", i),
            )
            .unwrap();
        }

        repo_paths.push(repo_path);
    }

    (temp, repo_paths)
}

/// Benchmark forall-like command: running a command across multiple repos
fn bench_forall_command(c: &mut Criterion) {
    let (temp, repo_paths) = setup_multi_repo_workspace();

    let mut group = c.benchmark_group("forall");

    // Benchmark sequential execution (like forall without -p)
    {
        let paths = repo_paths.clone();
        group.bench_function("sequential_echo", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let output = Command::new("sh")
                        .arg("-c")
                        .arg("echo $REPO_NAME")
                        .current_dir(path)
                        .env("REPO_NAME", path.file_name().unwrap().to_str().unwrap())
                        .output()
                        .unwrap();
                    results.push(output.status.success());
                }
                black_box(results)
            })
        });
    }

    // Benchmark parallel execution (like forall -p)
    {
        use std::sync::{Arc, Mutex};
        use std::thread;

        let paths = repo_paths.clone();
        group.bench_function("parallel_echo", |b| {
            b.iter(|| {
                let results = Arc::new(Mutex::new(Vec::new()));
                let mut handles = vec![];

                for path in paths.clone() {
                    let results = Arc::clone(&results);
                    let handle = thread::spawn(move || {
                        let output = Command::new("sh")
                            .arg("-c")
                            .arg("echo $REPO_NAME")
                            .current_dir(&path)
                            .env("REPO_NAME", path.file_name().unwrap().to_str().unwrap())
                            .output()
                            .unwrap();
                        results.lock().unwrap().push(output.status.success());
                    });
                    handles.push(handle);
                }

                for handle in handles {
                    handle.join().unwrap();
                }

                black_box(Arc::try_unwrap(results).unwrap().into_inner().unwrap())
            })
        });
    }

    // Benchmark sequential git status across repos (git2) - simulates forall interception
    {
        let paths = repo_paths.clone();
        group.bench_function("sequential_git_status_git2", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = git2::Repository::open(path).unwrap();
                    let statuses = repo.statuses(None).unwrap();
                    results.push(statuses.len());
                }
                black_box(results)
            })
        });
    }

    // Benchmark forall interception: git status --porcelain (full output formatting)
    {
        let paths = repo_paths.clone();
        group.bench_function("intercepted_git_status_porcelain", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = git2::Repository::open(path).unwrap();
                    let statuses = repo.statuses(None).unwrap();

                    // Format as porcelain (what forall interception does)
                    let mut output = String::new();
                    for entry in statuses.iter() {
                        let status = entry.status();
                        let filepath = entry.path().unwrap_or("?");

                        let idx = if status.is_index_new() {
                            'A'
                        } else if status.is_index_modified() {
                            'M'
                        } else if status.is_index_deleted() {
                            'D'
                        } else {
                            ' '
                        };

                        let wt = if status.is_wt_new() {
                            '?'
                        } else if status.is_wt_modified() {
                            'M'
                        } else if status.is_wt_deleted() {
                            'D'
                        } else {
                            ' '
                        };

                        output.push_str(&format!("{}{} {}\n", idx, wt, filepath));
                    }
                    results.push(output);
                }
                black_box(results)
            })
        });
    }

    // Benchmark sequential git status across repos (gix)
    #[cfg(feature = "gitoxide")]
    {
        let paths = repo_paths.clone();
        group.bench_function("sequential_git_status_gix", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = gix::open(path).unwrap();
                    // gix status API is still maturing, so we check head_id as proxy
                    let head_ok = repo.head_id().is_ok();
                    results.push(head_ok);
                }
                black_box(results)
            })
        });
    }

    // Benchmark sequential git status via CLI (what TypeScript does)
    {
        let paths = repo_paths.clone();
        group.bench_function("sequential_git_status_cli", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let output = Command::new("git")
                        .args(["status", "--porcelain"])
                        .current_dir(path)
                        .output()
                        .unwrap();
                    results.push(String::from_utf8_lossy(&output.stdout).lines().count());
                }
                black_box(results)
            })
        });
    }

    drop(temp); // Clean up
    group.finish();
}

/// Benchmark multi-repo status gathering (gr status)
fn bench_multi_repo_status(c: &mut Criterion) {
    let (temp, repo_paths) = setup_multi_repo_workspace();

    let mut group = c.benchmark_group("multi_repo_status");

    // Full status check using git2 (branch + status + ahead/behind)
    {
        let paths = repo_paths.clone();
        group.bench_function("git2_full_status", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = git2::Repository::open(path).unwrap();

                    // Get current branch
                    let head = repo.head().unwrap();
                    let branch = head.shorthand().unwrap_or("HEAD").to_string();

                    // Get status
                    let statuses = repo.statuses(None).unwrap();
                    let has_changes = !statuses.is_empty();

                    results.push((branch, has_changes));
                }
                black_box(results)
            })
        });
    }

    // Full status check using git CLI (like TypeScript)
    {
        let paths = repo_paths.clone();
        group.bench_function("git_cli_full_status", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    // Get current branch
                    let branch_output = Command::new("git")
                        .args(["rev-parse", "--abbrev-ref", "HEAD"])
                        .current_dir(path)
                        .output()
                        .unwrap();
                    let branch = String::from_utf8_lossy(&branch_output.stdout)
                        .trim()
                        .to_string();

                    // Get status
                    let status_output = Command::new("git")
                        .args(["status", "--porcelain"])
                        .current_dir(path)
                        .output()
                        .unwrap();
                    let has_changes = !status_output.stdout.is_empty();

                    results.push((branch, has_changes));
                }
                black_box(results)
            })
        });
    }

    #[cfg(feature = "gitoxide")]
    {
        let paths = repo_paths.clone();
        group.bench_function("gix_branch_only", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = gix::open(path).unwrap();
                    let head = repo.head_name().unwrap();
                    let branch = head
                        .map(|n| n.shorten().to_string())
                        .unwrap_or_else(|| "HEAD".to_string());
                    results.push(branch);
                }
                black_box(results)
            })
        });
    }

    // Full status check using gix (branch + head_id as status proxy)
    #[cfg(feature = "gitoxide")]
    {
        let paths = repo_paths.clone();
        group.bench_function("gix_full_status", |b| {
            b.iter(|| {
                let mut results = Vec::new();
                for path in &paths {
                    let repo = gix::open(path).unwrap();

                    // Get current branch
                    let head = repo.head_name().unwrap();
                    let branch = head
                        .map(|n| n.shorten().to_string())
                        .unwrap_or_else(|| "HEAD".to_string());

                    // gix status API is still maturing - use head_id check as proxy
                    // In real usage, would use repo.status() when stable
                    let has_head = repo.head_id().is_ok();

                    results.push((branch, has_head));
                }
                black_box(results)
            })
        });
    }

    drop(temp);
    group.finish();
}

/// Benchmark manifest loading and repo resolution (gr sync prep phase)
fn bench_manifest_and_repos(c: &mut Criterion) {
    // Realistic manifest with multiple repos
    let manifest_yaml = r#"
version: 1
manifest:
  url: git@github.com:org/manifest.git
  default_branch: main
repos:
  frontend:
    url: git@github.com:org/frontend.git
    path: frontend
    default_branch: main
    copyfile:
      - src: .env.example
        dest: .env
  backend:
    url: git@github.com:org/backend.git
    path: backend
    default_branch: main
    linkfile:
      - src: shared/types.ts
        dest: frontend/src/types.ts
  shared-lib:
    url: git@github.com:org/shared-lib.git
    path: shared-lib
    default_branch: main
  api:
    url: git@github.com:org/api.git
    path: api
    default_branch: develop
  docs:
    url: git@github.com:org/docs.git
    path: docs
    default_branch: main
settings:
  pr_prefix: "[workspace]"
  merge_strategy: all-or-nothing
workspace:
  env:
    NODE_ENV: development
    API_URL: http://localhost:3000
  scripts:
    build:
      description: Build all packages
      command: npm run build
    test:
      description: Run all tests
      steps:
        - name: lint
          command: npm run lint
        - name: unit
          command: npm test
        - name: e2e
          command: npm run e2e
"#;

    c.bench_function("manifest_parse_and_validate", |b| {
        b.iter(|| {
            let manifest = Manifest::parse(black_box(manifest_yaml)).unwrap();
            manifest.validate().unwrap();
            black_box(manifest)
        })
    });

    c.bench_function("manifest_repo_resolution", |b| {
        let manifest = Manifest::parse(manifest_yaml).unwrap();
        let workspace = PathBuf::from("/home/user/workspace");

        b.iter(|| {
            let repos: Vec<_> = manifest
                .repos
                .iter()
                .filter_map(|(name, config)| {
                    RepoInfo::from_config(name, config, black_box(&workspace))
                })
                .collect();
            black_box(repos)
        })
    });
}

/// Benchmark telemetry overhead
///
/// To compare telemetry vs no-telemetry, run:
/// ```bash
/// # With telemetry (default)
/// cargo bench --bench benchmarks -- telemetry
///
/// # Without telemetry
/// cargo bench --bench benchmarks --no-default-features -- telemetry
/// ```
#[cfg(feature = "telemetry")]
fn bench_telemetry_overhead(c: &mut Criterion) {
    use gitgrip::telemetry::metrics::GLOBAL_METRICS;
    use std::time::Duration;

    let mut group = c.benchmark_group("telemetry_overhead");

    // Benchmark metrics recording (the hot path when telemetry is enabled)
    group.bench_function("record_git_metric", |b| {
        b.iter(|| {
            GLOBAL_METRICS.record_git(
                black_box("fetch"),
                black_box(Duration::from_millis(100)),
                black_box(true),
            );
        })
    });

    group.bench_function("record_platform_metric", |b| {
        b.iter(|| {
            GLOBAL_METRICS.record_platform(
                black_box("github"),
                black_box("create_pr"),
                black_box(Duration::from_millis(500)),
                black_box(true),
            );
        })
    });

    group.bench_function("record_cache_metric", |b| {
        b.iter(|| {
            GLOBAL_METRICS.record_cache(black_box(true));
        })
    });

    group.bench_function("metrics_snapshot", |b| {
        // Add some metrics first
        for i in 0..10 {
            GLOBAL_METRICS.record_git(
                &format!("op{}", i),
                Duration::from_millis(i as u64 * 10),
                true,
            );
        }
        b.iter(|| black_box(GLOBAL_METRICS.snapshot()))
    });

    group.finish();
}

#[cfg(not(feature = "telemetry"))]
fn bench_telemetry_overhead(c: &mut Criterion) {
    // When telemetry is disabled, we measure the baseline
    let mut group = c.benchmark_group("telemetry_overhead");

    group.bench_function("baseline_noop", |b| {
        b.iter(|| {
            // This measures the baseline when telemetry is compiled out
            black_box(42)
        })
    });

    group.finish();
}

criterion_group!(
    benches,
    bench_manifest_parse,
    bench_state_parse,
    bench_url_parse,
    bench_url_parse_azure,
    bench_manifest_validate,
    bench_git_status_comparison,
    bench_git_list_branches_comparison,
    bench_repo_open_comparison,
    bench_get_current_branch_comparison,
    bench_file_hash,
    bench_path_operations,
    bench_url_regex_parse,
    // High-level gitgrip command benchmarks
    bench_forall_command,
    bench_multi_repo_status,
    bench_manifest_and_repos,
    // Telemetry overhead benchmarks
    bench_telemetry_overhead,
);

criterion_main!(benches);

fn main() {
    // Note: Using CARGO_CFG_TARGET_OS because #[cfg()] attributes in build.rs
    // check the HOST platform, not the target platform
    let target_os = std::env::var("CARGO_CFG_TARGET_OS").unwrap_or_default();
    if target_os == "windows" {
        // Link Windows system libraries required by libgit2-sys
        // These provide security (GetNamedSecurityInfoW) and registry
        // (RegOpenKeyExW, RegQueryValueExW, RegCloseKey) functions
        println!("cargo:rustc-link-lib=advapi32");

        // Increase default stack size from 1 MB to 8 MB on Windows.
        // The large clap Commands enum (~25 variants with nested subcommands)
        // causes a stack overflow during parsing in debug builds.
        // Linux/macOS default to 8 MB; this makes Windows match.
        let target_env = std::env::var("CARGO_CFG_TARGET_ENV").unwrap_or_default();
        if target_env == "msvc" {
            println!("cargo:rustc-link-arg=/STACK:8388608");
        } else {
            // MinGW / GNU toolchain
            println!("cargo:rustc-link-arg=-Wl,--stack-reserve=8388608");
        }
    }
}

//! Add command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::manifest_paths;
use crate::core::repo::RepoInfo;
use crate::git::cache::invalidate_status_cache;
use crate::git::{get_workdir, open_repo, path_exists};
use crate::util::log_cmd;
use git2::Repository;
use std::path::PathBuf;
use std::process::Command;

/// Run the add command
pub fn run_add(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    files: &[String],
) -> anyhow::Result<()> {
    Output::header("Checking repositories for changes to stage...");
    println!();

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    let mut total_staged = 0;
    let mut repos_with_changes = 0;

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                let staged = stage_files(&git_repo, &repo.absolute_path, files)?;
                if staged > 0 {
                    Output::success(&format!("{}: staged {} file(s)", repo.name, staged));
                    total_staged += staged;
                    repos_with_changes += 1;
                    invalidate_status_cache(&repo.absolute_path);
                }
            }
            Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
        }
    }

    // Also handle manifest worktree if it exists (in griptree scenario)
    if let Some(manifests_dir) = manifest_paths::resolve_manifest_repo_dir(workspace_root) {
        let manifests_git_dir = manifests_dir.join(".git");
        if manifests_git_dir.exists() && path_exists(&manifests_dir) {
            match open_repo(&manifests_dir) {
                Ok(git_repo) => {
                    let staged = stage_files(&git_repo, &manifests_dir, files)?;
                    if staged > 0 {
                        Output::success(&format!("manifest: staged {} file(s)", staged));
                        total_staged += staged;
                        repos_with_changes += 1;
                        invalidate_status_cache(&manifests_dir);
                    }
                }
                Err(e) => Output::warning(&format!("manifest: {}", e)),
            }
        }
    }

    println!();
    if total_staged > 0 {
        println!(
            "Staged {} file(s) in {} repository(s).",
            total_staged, repos_with_changes
        );
    } else {
        println!("No changes to stage.");
    }

    Ok(())
}

/// Stage files in a repository using git CLI
fn stage_files(repo: &Repository, _repo_path: &PathBuf, files: &[String]) -> anyhow::Result<usize> {
    let repo_dir = get_workdir(repo);

    // Get count of changes before staging
    let mut cmd = Command::new("git");
    cmd.args(["status", "--porcelain"]).current_dir(repo_dir);
    log_cmd(&cmd);
    let before_output = cmd.output()?;
    let before_count = String::from_utf8_lossy(&before_output.stdout)
        .lines()
        .filter(|l| !l.starts_with("??") || files.contains(&".".to_string()))
        .count();

    if before_count == 0 {
        return Ok(0);
    }

    // Build git add command
    let mut args = vec!["add"];

    if files.len() == 1 && files[0] == "." {
        args.push("-A"); // Add all changes including deletions
    } else {
        for file in files {
            args.push(file);
        }
    }

    let mut cmd = Command::new("git");
    cmd.args(&args).current_dir(repo_dir);
    log_cmd(&cmd);
    let output = cmd.output()?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        anyhow::bail!("git add failed: {}", stderr);
    }

    // Count what was actually staged
    let mut cmd = Command::new("git");
    cmd.args(["diff", "--cached", "--name-only"])
        .current_dir(repo_dir);
    log_cmd(&cmd);
    let after_output = cmd.output()?;

    let staged_count = String::from_utf8_lossy(&after_output.stdout)
        .lines()
        .count();

    Ok(staged_count)
}

//! Agent build command — run agent.build for repo(s).

use std::path::PathBuf;
use std::process::Command;

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::filter_repos;

/// Run the agent build command.
///
/// Executes the `agent.build` command from the manifest for each repo
/// (or a specific repo if `repo_filter` is set).
pub fn run_agent_build(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    repo_filter: Option<&str>,
) -> anyhow::Result<()> {
    let repos = filter_repos(manifest, workspace_root, None, None, false);

    let mut ran_any = false;

    for repo in &repos {
        if let Some(filter) = repo_filter {
            if repo.name != filter {
                continue;
            }
        }

        let build_cmd = repo.agent.as_ref().and_then(|a| a.build.as_deref());

        let Some(cmd) = build_cmd else {
            if repo_filter.is_some() {
                anyhow::bail!(
                    "Repository '{}' has no agent.build command defined in the manifest",
                    repo.name
                );
            }
            continue;
        };

        Output::header(&format!("Building {}", repo.name));
        Output::info(&format!("$ {}", cmd));

        let status = Command::new("sh")
            .arg("-c")
            .arg(cmd)
            .current_dir(&repo.absolute_path)
            .status()?;

        if !status.success() {
            anyhow::bail!(
                "Build failed for '{}' (exit code: {:?})",
                repo.name,
                status.code()
            );
        }

        Output::success(&format!("{} built successfully", repo.name));
        ran_any = true;
    }

    if !ran_any {
        if repo_filter.is_some() {
            anyhow::bail!("Repository not found in manifest");
        }
        Output::info("No repos have agent.build configured");
    }

    Ok(())
}

//! Agent context command — dump workspace context for AI agent system prompts.

use std::path::PathBuf;

use crate::core::griptree::GriptreeConfig;
use crate::core::manifest::Manifest;
use crate::core::repo::filter_repos;
use crate::git::status::get_repo_status;

use super::{
    AgentContextJson, GriptreeContextJson, RepoAgentContextJson, RepoContextJson,
    WorkspaceContextJson,
};

/// Run the agent context command.
///
/// Outputs workspace context as plain markdown (for system prompt injection)
/// or structured JSON (for programmatic consumption).
pub fn run_agent_context(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    repo_filter: Option<&str>,
    json: bool,
) -> anyhow::Result<()> {
    // Get all repos (include reference repos)
    let all_repos = filter_repos(manifest, workspace_root, None, None, true);

    // Validate repo filter
    if let Some(filter) = repo_filter {
        if !all_repos.iter().any(|r| r.name == filter) {
            anyhow::bail!("Repository '{}' not found in manifest", filter);
        }
    }

    // Get status for each repo
    let statuses: Vec<_> = all_repos.iter().map(|r| (r, get_repo_status(r))).collect();

    // Load griptree config (if in a griptree workspace)
    let griptree = GriptreeConfig::load_from_workspace(workspace_root)
        .ok()
        .flatten();

    if json {
        output_json(workspace_root, manifest, &statuses, &griptree, repo_filter)
    } else {
        output_markdown(workspace_root, manifest, &statuses, &griptree, repo_filter);
        Ok(())
    }
}

fn output_json(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    statuses: &[(&crate::core::repo::RepoInfo, crate::git::status::RepoStatus)],
    griptree: &Option<GriptreeConfig>,
    repo_filter: Option<&str>,
) -> anyhow::Result<()> {
    let ws_agent = manifest.workspace.as_ref().and_then(|w| w.agent.as_ref());

    let scripts: Option<Vec<String>> = manifest
        .workspace
        .as_ref()
        .and_then(|w| w.scripts.as_ref())
        .map(|s| s.keys().cloned().collect());

    let env = manifest.workspace.as_ref().and_then(|w| w.env.clone());

    let workspace = WorkspaceContextJson {
        root: workspace_root.display().to_string(),
        description: ws_agent.and_then(|a| a.description.clone()),
        conventions: ws_agent.map(|a| a.conventions.clone()).unwrap_or_default(),
        workflows: ws_agent.and_then(|a| a.workflows.clone()),
        scripts,
        env,
    };

    let repos: Vec<RepoContextJson> = statuses
        .iter()
        .filter(|(repo, _)| repo_filter.map_or(true, |f| repo.name == f))
        .map(|(repo, status)| RepoContextJson {
            name: repo.name.clone(),
            path: repo.path.clone(),
            url: repo.url.clone(),
            default_branch: repo.default_branch.clone(),
            current_branch: status.branch.clone(),
            clean: status.clean,
            exists: status.exists,
            reference: repo.reference,
            groups: repo.groups.clone(),
            agent: repo.agent.as_ref().map(|a| RepoAgentContextJson {
                description: a.description.clone(),
                language: a.language.clone(),
                build: a.build.clone(),
                test: a.test.clone(),
                lint: a.lint.clone(),
                format: a.format.clone(),
            }),
        })
        .collect();

    let griptree_json = griptree.as_ref().map(|g| GriptreeContextJson {
        branch: g.branch.clone(),
        path: g.path.clone(),
        upstreams: g.repo_upstreams.clone(),
    });

    let context = AgentContextJson {
        workspace,
        repos,
        griptree: griptree_json,
    };

    println!("{}", serde_json::to_string_pretty(&context)?);
    Ok(())
}

fn output_markdown(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    statuses: &[(&crate::core::repo::RepoInfo, crate::git::status::RepoStatus)],
    griptree: &Option<GriptreeConfig>,
    repo_filter: Option<&str>,
) {
    let ws_agent = manifest.workspace.as_ref().and_then(|w| w.agent.as_ref());

    // Workspace header
    println!("# Workspace: {}", workspace_root.display());
    if let Some(desc) = ws_agent.and_then(|a| a.description.as_deref()) {
        println!("{}", desc);
    }
    println!();

    // Conventions
    if let Some(agent) = ws_agent {
        if !agent.conventions.is_empty() {
            println!("## Conventions");
            for convention in &agent.conventions {
                println!("- {}", convention);
            }
            println!();
        }

        // Workflows
        if let Some(workflows) = &agent.workflows {
            if !workflows.is_empty() {
                println!("## Workflows");
                for (name, cmd) in workflows {
                    println!("- {}: `{}`", name, cmd);
                }
                println!();
            }
        }
    }

    // Scripts
    if let Some(workspace) = &manifest.workspace {
        if let Some(scripts) = &workspace.scripts {
            if !scripts.is_empty() {
                println!("## Scripts");
                for name in scripts.keys() {
                    println!("- {}", name);
                }
                println!();
            }
        }
    }

    // Griptree section
    if let Some(g) = griptree {
        println!("## Griptree: {}", g.branch);
        if !g.repo_upstreams.is_empty() {
            let upstreams: Vec<String> = g
                .repo_upstreams
                .iter()
                .map(|(repo, upstream)| format!("{}:{}", repo, upstream))
                .collect();
            println!("Upstreams: {}", upstreams.join(", "));
        }
        println!();
    }

    // Repos
    println!("## Repos");
    println!();

    for (repo, status) in statuses {
        if let Some(filter) = repo_filter {
            if repo.name != filter {
                continue;
            }
        }

        // Repo header line
        let ref_tag = if repo.reference { " [reference]" } else { "" };
        let agent = repo.agent.as_ref();

        let lang = agent
            .and_then(|a| a.language.as_deref())
            .map(|l| format!(" ({})", l))
            .unwrap_or_default();

        let desc = agent
            .and_then(|a| a.description.as_deref())
            .map(|d| format!(" -- {}", d))
            .unwrap_or_default();

        // Build command annotations
        let mut cmds = Vec::new();
        if let Some(a) = agent {
            if let Some(b) = &a.build {
                cmds.push(format!("build: {}", b));
            }
            if let Some(t) = &a.test {
                cmds.push(format!("test: {}", t));
            }
            if let Some(l) = &a.lint {
                cmds.push(format!("lint: {}", l));
            }
        }
        let cmds_str = if cmds.is_empty() {
            String::new()
        } else {
            format!(" [{}]", cmds.join("] ["))
        };

        println!("### {}{}{}{}", repo.name, lang, ref_tag, desc);

        if !status.exists {
            println!("- Status: not cloned");
        } else {
            // Status line
            let status_str = if status.clean {
                "clean".to_string()
            } else {
                let mut parts = Vec::new();
                if status.staged > 0 {
                    parts.push(format!("{} staged", status.staged));
                }
                if status.modified > 0 {
                    parts.push(format!("{} modified", status.modified));
                }
                if status.untracked > 0 {
                    parts.push(format!("{} untracked", status.untracked));
                }
                parts.join(", ")
            };

            println!(
                "- Branch: {} (default: {})",
                status.branch, repo.default_branch
            );
            println!("- Status: {}", status_str);
        }

        if !cmds_str.is_empty() {
            println!("- Commands:{}", cmds_str);
        }

        if !repo.groups.is_empty() {
            println!("- Groups: {}", repo.groups.join(", "));
        }

        println!();
    }
}

//! Agent context generation — generate context files for multiple AI tools from a single source.

use std::path::Path;

use crate::cli::output::Output;
use crate::core::manifest::{AgentContextTarget, Manifest};
use crate::core::manifest_paths;
use crate::core::repo::filter_repos;
use crate::files::resolve_file_source;

/// Run the agent generate-context command.
///
/// Reads `workspace.agent.context_source`, applies format adapters,
/// and writes to each configured target destination.
pub fn run_agent_generate_context(
    workspace_root: &Path,
    manifest: &Manifest,
    dry_run: bool,
    quiet: bool,
) -> anyhow::Result<()> {
    let agent_config = manifest.workspace.as_ref().and_then(|w| w.agent.as_ref());

    let targets = match agent_config.and_then(|a| a.targets.as_ref()) {
        Some(targets) if !targets.is_empty() => targets,
        _ => {
            if !quiet {
                Output::info("No agent context targets configured");
            }
            return Ok(());
        }
    };

    // Read context source content (if configured)
    let source_content = if let Some(source) = agent_config.and_then(|a| a.context_source.as_ref())
    {
        let manifests_dir = manifest_paths::resolve_manifest_content_dir(workspace_root);
        let spaces_dir = manifest_paths::spaces_dir(workspace_root);
        let source_path = resolve_file_source(source, &manifests_dir, &spaces_dir)
            .map_err(|e| anyhow::anyhow!("Failed to resolve context_source '{}': {}", source, e))?;

        Some(std::fs::read_to_string(&source_path).map_err(|e| {
            anyhow::anyhow!(
                "Failed to read context_source '{}': {}",
                source_path.display(),
                e
            )
        })?)
    } else {
        None
    };

    let mut generated = 0;

    for target in targets {
        if target.dest.contains("{repo}") {
            generated +=
                generate_per_repo(workspace_root, manifest, target, &source_content, dry_run)?;
        } else {
            generated += generate_workspace_level(
                workspace_root,
                manifest,
                target,
                &source_content,
                dry_run,
            )?;
        }
    }

    if !quiet {
        if dry_run {
            Output::info(&format!(
                "Dry run: {} file(s) would be generated",
                generated
            ));
        } else {
            Output::success(&format!("Generated {} context file(s)", generated));
        }
    }

    Ok(())
}

/// Generate a single workspace-level context file (no {repo} placeholder).
fn generate_workspace_level(
    workspace_root: &Path,
    manifest: &Manifest,
    target: &AgentContextTarget,
    source_content: &Option<String>,
    dry_run: bool,
) -> anyhow::Result<usize> {
    let content = match source_content {
        Some(src) => src.clone(),
        None => {
            // No context_source — skip workspace-level targets that need content
            return Ok(0);
        }
    };

    // Apply compose_with: append additional files
    let content = apply_compose_with(workspace_root, manifest, &content, target)?;

    // Apply format adapter
    let formatted = apply_format(&target.format, &content, None);

    let dest_path = workspace_root.join(&target.dest);

    if dry_run {
        Output::info(&format!(
            "  {} -> {} ({} bytes)",
            target.format,
            target.dest,
            formatted.len()
        ));
    } else {
        if let Some(parent) = dest_path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(&dest_path, &formatted)?;
    }

    Ok(1)
}

/// Generate per-repo context files ({repo} placeholder in dest).
fn generate_per_repo(
    workspace_root: &Path,
    manifest: &Manifest,
    target: &AgentContextTarget,
    source_content: &Option<String>,
    dry_run: bool,
) -> anyhow::Result<usize> {
    let workspace_root_buf = workspace_root.to_path_buf();
    let repos = filter_repos(manifest, &workspace_root_buf, None, None, false);
    let mut count = 0;

    for repo in &repos {
        let agent = match &repo.agent {
            Some(a) => a,
            None => continue,
        };

        let dest = target.dest.replace("{repo}", &repo.name);
        let dest_path = workspace_root.join(&dest);

        // Build per-repo content from agent metadata
        let repo_content = build_repo_skill_content(&repo.name, agent, source_content);

        // Apply format adapter
        let formatted = apply_format(&target.format, &repo_content, Some(&repo.name));

        if dry_run {
            Output::info(&format!(
                "  {} -> {} ({} bytes)",
                target.format,
                dest,
                formatted.len()
            ));
        } else {
            if let Some(parent) = dest_path.parent() {
                std::fs::create_dir_all(parent)?;
            }
            std::fs::write(&dest_path, &formatted)?;
        }

        count += 1;
    }

    Ok(count)
}

/// Build skill content for a single repository from its agent config.
fn build_repo_skill_content(
    repo_name: &str,
    agent: &crate::core::manifest::RepoAgentConfig,
    _source_content: &Option<String>,
) -> String {
    let mut content = String::new();

    content.push_str(&format!("# {}\n\n", repo_name));

    if let Some(desc) = &agent.description {
        content.push_str(&format!("{}\n\n", desc));
    }

    let mut fields = Vec::new();
    if let Some(lang) = &agent.language {
        fields.push(format!("Language: {}", lang));
    }
    if let Some(build) = &agent.build {
        fields.push(format!("Build: `{}`", build));
    }
    if let Some(test) = &agent.test {
        fields.push(format!("Test: `{}`", test));
    }
    if let Some(lint) = &agent.lint {
        fields.push(format!("Lint: `{}`", lint));
    }
    if let Some(fmt) = &agent.format {
        fields.push(format!("Format: `{}`", fmt));
    }

    if !fields.is_empty() {
        for field in &fields {
            content.push_str(&format!("{}\n", field));
        }
    }

    content
}

/// Apply compose_with files — read additional files and append to content.
fn apply_compose_with(
    workspace_root: &Path,
    manifest: &Manifest,
    base_content: &str,
    target: &AgentContextTarget,
) -> anyhow::Result<String> {
    let compose_files = match &target.compose_with {
        Some(files) if !files.is_empty() => files,
        _ => return Ok(base_content.to_string()),
    };

    let manifests_dir = manifest_paths::resolve_manifest_content_dir(workspace_root);
    let spaces_dir = manifest_paths::spaces_dir(workspace_root);

    let mut result = base_content.to_string();

    for src in compose_files {
        // Try workspace-relative first (most common for compose_with),
        // then gripspace resolution, then manifest-relative
        let workspace_relative = workspace_root.join(src);
        let file_path = if workspace_relative.exists() {
            workspace_relative
        } else {
            match resolve_file_source(src, &manifests_dir, &spaces_dir) {
                Ok(p) => p,
                Err(_) => workspace_relative,
            }
        };

        match std::fs::read_to_string(&file_path) {
            Ok(content) => {
                result.push_str("\n\n");
                result.push_str(&content);
            }
            Err(e) => {
                Output::warning(&format!("compose_with '{}' not found: {}", src, e));
            }
        }
    }

    // Ensure unused variable warning doesn't fire
    let _ = manifest;

    Ok(result)
}

/// Apply format adapter to transform content for the target AI tool.
fn apply_format(format: &str, content: &str, repo_name: Option<&str>) -> String {
    match format {
        "raw" => content.to_string(),
        "claude" => format_claude(content, repo_name),
        "opencode" | "codex" => format_opencode(content, repo_name),
        "cursor" => format_cursor(content),
        _ => content.to_string(),
    }
}

/// Claude format: add YAML frontmatter for per-repo, pass through for workspace.
fn format_claude(content: &str, repo_name: Option<&str>) -> String {
    match repo_name {
        Some(name) => {
            let mut out = String::new();
            out.push_str("---\n");
            out.push_str(&format!("name: {}\n", name));
            out.push_str("---\n\n");
            out.push_str(content);
            out
        }
        None => content.to_string(),
    }
}

/// OpenCode/Codex format: add simple frontmatter for per-repo.
fn format_opencode(content: &str, repo_name: Option<&str>) -> String {
    match repo_name {
        Some(name) => {
            let mut out = String::new();
            out.push_str("---\n");
            out.push_str(&format!("name: {}\n", name));
            out.push_str("---\n\n");
            out.push_str(content);
            out
        }
        None => content.to_string(),
    }
}

/// Cursor format: strip markdown heading markers for .cursorrules format.
fn format_cursor(content: &str) -> String {
    let mut out = String::new();
    for line in content.lines() {
        if line.starts_with('#') {
            // Strip heading markers, keep the text
            let stripped = line.trim_start_matches('#').trim();
            out.push_str(stripped);
        } else {
            out.push_str(line);
        }
        out.push('\n');
    }
    out
}

