//! Branch command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, get_manifest_repo_info, RepoInfo};
use crate::git::{
    branch::{branch_exists, create_and_checkout_branch, delete_local_branch, list_local_branches},
    get_current_branch, open_repo,
};
use std::path::PathBuf;

/// Options for the branch command
pub struct BranchOptions<'a> {
    pub workspace_root: &'a PathBuf,
    pub manifest: &'a Manifest,
    pub name: Option<&'a str>,
    pub delete: bool,
    pub move_commits: bool,
    pub repos_filter: Option<&'a [String]>,
    pub group_filter: Option<&'a [String]>,
    pub json: bool,
}

/// Run the branch command
pub fn run_branch(opts: BranchOptions<'_>) -> anyhow::Result<()> {
    let mut repos: Vec<RepoInfo> = filter_repos(
        opts.manifest,
        opts.workspace_root,
        opts.repos_filter,
        opts.group_filter,
        false,
    );

    // Include manifest repo in branch operations
    if let Some(manifest_repo) = get_manifest_repo_info(opts.manifest, opts.workspace_root) {
        repos.push(manifest_repo);
    }

    match opts.name {
        Some(branch_name) if opts.delete => {
            // Delete branch
            #[derive(serde::Serialize)]
            struct JsonDeleteResult {
                repo: String,
                branch: String,
                action: String,
                #[serde(skip_serializing_if = "Option::is_none")]
                error: Option<String>,
            }

            let mut json_results: Vec<JsonDeleteResult> = Vec::new();

            if !opts.json {
                Output::header(&format!("Deleting branch '{}'", branch_name));
                println!();
            }

            for repo in &repos {
                if !repo.exists() {
                    if opts.json {
                        json_results.push(JsonDeleteResult {
                            repo: repo.name.clone(),
                            branch: branch_name.to_string(),
                            action: "skipped".to_string(),
                            error: Some("not cloned".to_string()),
                        });
                    } else {
                        Output::warning(&format!("{}: not cloned", repo.name));
                    }
                    continue;
                }

                match open_repo(&repo.absolute_path) {
                    Ok(git_repo) => {
                        if !branch_exists(&git_repo, branch_name) {
                            if opts.json {
                                json_results.push(JsonDeleteResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "not_found".to_string(),
                                    error: None,
                                });
                            } else {
                                Output::info(&format!("{}: branch doesn't exist", repo.name));
                            }
                            continue;
                        }

                        match delete_local_branch(&git_repo, branch_name, false) {
                            Ok(()) => {
                                if opts.json {
                                    json_results.push(JsonDeleteResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "deleted".to_string(),
                                        error: None,
                                    });
                                } else {
                                    Output::success(&format!("{}: deleted", repo.name));
                                }
                            }
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonDeleteResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        error: Some(e.to_string()),
                                    });
                                } else {
                                    Output::error(&format!("{}: {}", repo.name, e));
                                }
                            }
                        }
                    }
                    Err(e) => {
                        if opts.json {
                            json_results.push(JsonDeleteResult {
                                repo: repo.name.clone(),
                                branch: branch_name.to_string(),
                                action: "error".to_string(),
                                error: Some(e.to_string()),
                            });
                        } else {
                            Output::error(&format!("{}: {}", repo.name, e));
                        }
                    }
                }
            }

            if opts.json {
                println!("{}", serde_json::to_string_pretty(&json_results)?);
            }
        }
        Some(branch_name) if opts.move_commits => {
            // Move commits to new branch (create branch, reset current to remote, checkout new)
            #[derive(serde::Serialize)]
            struct JsonMoveResult {
                repo: String,
                branch: String,
                action: String,
                #[serde(skip_serializing_if = "Option::is_none")]
                from_branch: Option<String>,
                #[serde(skip_serializing_if = "Option::is_none")]
                error: Option<String>,
            }

            let mut json_results: Vec<JsonMoveResult> = Vec::new();

            if !opts.json {
                Output::header(&format!(
                    "Moving commits to branch '{}' in {} repos...",
                    branch_name,
                    repos.len()
                ));
                println!();
            }

            for repo in &repos {
                if !repo.exists() {
                    if opts.json {
                        json_results.push(JsonMoveResult {
                            repo: repo.name.clone(),
                            branch: branch_name.to_string(),
                            action: "skipped".to_string(),
                            from_branch: None,
                            error: Some("not cloned".to_string()),
                        });
                    } else {
                        Output::warning(&format!("{}: not cloned", repo.name));
                    }
                    continue;
                }

                match open_repo(&repo.absolute_path) {
                    Ok(git_repo) => {
                        let current = match get_current_branch(&git_repo) {
                            Ok(b) => b,
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonMoveResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        from_branch: None,
                                        error: Some(format!(
                                            "failed to get current branch - {}",
                                            e
                                        )),
                                    });
                                } else {
                                    Output::error(&format!(
                                        "{}: failed to get current branch - {}",
                                        repo.name, e
                                    ));
                                }
                                continue;
                            }
                        };

                        if branch_exists(&git_repo, branch_name) {
                            if opts.json {
                                json_results.push(JsonMoveResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "error".to_string(),
                                    from_branch: Some(current),
                                    error: Some(format!("branch '{}' already exists", branch_name)),
                                });
                            } else {
                                Output::error(&format!(
                                    "{}: branch '{}' already exists",
                                    repo.name, branch_name
                                ));
                            }
                            continue;
                        }

                        // Create branch at current HEAD
                        let head = match git_repo.head() {
                            Ok(h) => h,
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonMoveResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        from_branch: Some(current),
                                        error: Some(format!("failed to get HEAD - {}", e)),
                                    });
                                } else {
                                    Output::error(&format!(
                                        "{}: failed to get HEAD - {}",
                                        repo.name, e
                                    ));
                                }
                                continue;
                            }
                        };
                        let head_commit = match head.peel_to_commit() {
                            Ok(c) => c,
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonMoveResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        from_branch: Some(current),
                                        error: Some(format!("failed to get HEAD commit - {}", e)),
                                    });
                                } else {
                                    Output::error(&format!(
                                        "{}: failed to get HEAD commit - {}",
                                        repo.name, e
                                    ));
                                }
                                continue;
                            }
                        };

                        if let Err(e) = git_repo.branch(branch_name, &head_commit, false) {
                            if opts.json {
                                json_results.push(JsonMoveResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "error".to_string(),
                                    from_branch: Some(current),
                                    error: Some(format!("failed to create branch - {}", e)),
                                });
                            } else {
                                Output::error(&format!(
                                    "{}: failed to create branch - {}",
                                    repo.name, e
                                ));
                            }
                            continue;
                        }

                        // Reset current branch to origin/<current>
                        let remote_ref = format!("refs/remotes/origin/{}", current);
                        let remote_commit = match git_repo.revparse_single(&remote_ref) {
                            Ok(obj) => match obj.peel_to_commit() {
                                Ok(c) => c,
                                Err(e) => {
                                    if opts.json {
                                        json_results.push(JsonMoveResult {
                                            repo: repo.name.clone(),
                                            branch: branch_name.to_string(),
                                            action: "error".to_string(),
                                            from_branch: Some(current),
                                            error: Some(format!(
                                                "failed to find remote commit - {}",
                                                e
                                            )),
                                        });
                                    } else {
                                        Output::error(&format!(
                                            "{}: failed to find remote commit - {}",
                                            repo.name, e
                                        ));
                                    }
                                    continue;
                                }
                            },
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonMoveResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        from_branch: Some(current.clone()),
                                        error: Some(format!(
                                            "no remote tracking branch origin/{} - {}",
                                            current, e
                                        )),
                                    });
                                } else {
                                    Output::error(&format!(
                                        "{}: no remote tracking branch origin/{} - {}",
                                        repo.name, current, e
                                    ));
                                }
                                continue;
                            }
                        };

                        if let Err(e) =
                            git_repo.reset(remote_commit.as_object(), git2::ResetType::Hard, None)
                        {
                            if opts.json {
                                json_results.push(JsonMoveResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "error".to_string(),
                                    from_branch: Some(current.clone()),
                                    error: Some(format!(
                                        "failed to reset to origin/{} - {}",
                                        current, e
                                    )),
                                });
                            } else {
                                Output::error(&format!(
                                    "{}: failed to reset to origin/{} - {}",
                                    repo.name, current, e
                                ));
                            }
                            continue;
                        }

                        // Checkout the new branch
                        if let Err(e) = git_repo.set_head(&format!("refs/heads/{}", branch_name)) {
                            if opts.json {
                                json_results.push(JsonMoveResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "error".to_string(),
                                    from_branch: Some(current),
                                    error: Some(format!("failed to checkout new branch - {}", e)),
                                });
                            } else {
                                Output::error(&format!(
                                    "{}: failed to checkout new branch - {}",
                                    repo.name, e
                                ));
                            }
                            continue;
                        }

                        if let Err(e) = git_repo
                            .checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
                        {
                            if opts.json {
                                json_results.push(JsonMoveResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "error".to_string(),
                                    from_branch: Some(current),
                                    error: Some(format!("failed to update working tree - {}", e)),
                                });
                            } else {
                                Output::error(&format!(
                                    "{}: failed to update working tree - {}",
                                    repo.name, e
                                ));
                            }
                            continue;
                        }

                        if opts.json {
                            json_results.push(JsonMoveResult {
                                repo: repo.name.clone(),
                                branch: branch_name.to_string(),
                                action: "moved".to_string(),
                                from_branch: Some(current.clone()),
                                error: None,
                            });
                        } else {
                            Output::success(&format!(
                                "{}: moved commits from {} to {}",
                                repo.name, current, branch_name
                            ));
                        }
                    }
                    Err(e) => {
                        if opts.json {
                            json_results.push(JsonMoveResult {
                                repo: repo.name.clone(),
                                branch: branch_name.to_string(),
                                action: "error".to_string(),
                                from_branch: None,
                                error: Some(e.to_string()),
                            });
                        } else {
                            Output::error(&format!("{}: {}", repo.name, e));
                        }
                    }
                }
            }

            if opts.json {
                println!("{}", serde_json::to_string_pretty(&json_results)?);
            } else {
                println!();
                println!(
                    "Commits moved to branch: {}",
                    Output::branch_name(branch_name)
                );
            }
        }
        Some(branch_name) => {
            // Create branch
            #[derive(serde::Serialize)]
            struct JsonCreateResult {
                repo: String,
                branch: String,
                action: String,
                #[serde(skip_serializing_if = "Option::is_none")]
                error: Option<String>,
            }

            let mut json_results: Vec<JsonCreateResult> = Vec::new();

            if !opts.json {
                Output::header(&format!(
                    "Creating branch '{}' in {} repos...",
                    branch_name,
                    repos.len()
                ));
                println!();
            }

            for repo in &repos {
                if !repo.exists() {
                    if opts.json {
                        json_results.push(JsonCreateResult {
                            repo: repo.name.clone(),
                            branch: branch_name.to_string(),
                            action: "skipped".to_string(),
                            error: Some("not cloned".to_string()),
                        });
                    } else {
                        Output::warning(&format!("{}: not cloned", repo.name));
                    }
                    continue;
                }

                match open_repo(&repo.absolute_path) {
                    Ok(git_repo) => {
                        if branch_exists(&git_repo, branch_name) {
                            if opts.json {
                                json_results.push(JsonCreateResult {
                                    repo: repo.name.clone(),
                                    branch: branch_name.to_string(),
                                    action: "already_exists".to_string(),
                                    error: None,
                                });
                            } else {
                                Output::info(&format!("{}: already exists", repo.name));
                            }
                            continue;
                        }

                        match create_and_checkout_branch(&git_repo, branch_name) {
                            Ok(()) => {
                                if opts.json {
                                    json_results.push(JsonCreateResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "created".to_string(),
                                        error: None,
                                    });
                                } else {
                                    Output::success(&format!("{}: created", repo.name));
                                }
                            }
                            Err(e) => {
                                if opts.json {
                                    json_results.push(JsonCreateResult {
                                        repo: repo.name.clone(),
                                        branch: branch_name.to_string(),
                                        action: "error".to_string(),
                                        error: Some(e.to_string()),
                                    });
                                } else {
                                    Output::error(&format!("{}: {}", repo.name, e));
                                }
                            }
                        }
                    }
                    Err(e) => {
                        if opts.json {
                            json_results.push(JsonCreateResult {
                                repo: repo.name.clone(),
                                branch: branch_name.to_string(),
                                action: "error".to_string(),
                                error: Some(e.to_string()),
                            });
                        } else {
                            Output::error(&format!("{}: {}", repo.name, e));
                        }
                    }
                }
            }

            if opts.json {
                println!("{}", serde_json::to_string_pretty(&json_results)?);
            } else {
                println!();
                println!(
                    "All repos now on branch: {}",
                    Output::branch_name(branch_name)
                );
            }
        }
        None => {
            if opts.json {
                // JSON output for list mode
                #[derive(serde::Serialize)]
                struct JsonBranch {
                    repo: String,
                    branch: String,
                    default_branch: String,
                }

                let mut results: Vec<JsonBranch> = Vec::new();
                for repo in &repos {
                    if !repo.exists() {
                        continue;
                    }
                    if let Ok(git_repo) = open_repo(&repo.absolute_path) {
                        let current = get_current_branch(&git_repo).unwrap_or_default();
                        results.push(JsonBranch {
                            repo: repo.name.clone(),
                            branch: current,
                            default_branch: repo.default_branch.clone(),
                        });
                    }
                }
                println!("{}", serde_json::to_string_pretty(&results)?);
            } else {
                // List branches
                Output::header("Branches");
                println!();

                for repo in &repos {
                    if !repo.exists() {
                        continue;
                    }

                    match open_repo(&repo.absolute_path) {
                        Ok(git_repo) => {
                            let current = get_current_branch(&git_repo).unwrap_or_default();
                            let branches = list_local_branches(&git_repo).unwrap_or_default();

                            println!("  {}:", Output::repo_name(&repo.name));
                            for branch in branches {
                                let marker = if branch == current { "* " } else { "  " };
                                let formatted = if branch == current {
                                    Output::branch_name(&branch)
                                } else {
                                    branch
                                };
                                println!("    {}{}", marker, formatted);
                            }
                        }
                        Err(_) => continue,
                    }
                }
            }
        }
    }

    Ok(())
}

//! Checkout command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{get_manifest_repo_info, RepoInfo};
use crate::git::{
    branch::{branch_exists, checkout_branch, create_and_checkout_branch},
    open_repo,
};
use std::path::PathBuf;

/// Run the checkout command
pub fn run_checkout(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    branch_name: &str,
    create: bool,
) -> anyhow::Result<()> {
    let action = if create {
        "Creating and checking out"
    } else {
        "Checking out"
    };
    Output::header(&format!(
        "{} '{}' in {} repos...",
        action,
        branch_name,
        manifest.repos.len()
    ));
    println!();

    let mut repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .filter(|r| !r.reference) // Skip reference repos
        .collect();

    // Include manifest repo in checkout operations
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.push(manifest_repo);
    }

    let mut success_count = 0;
    let mut _skip_count = 0;

    for repo in &repos {
        if !repo.exists() {
            Output::warning(&format!("{}: not cloned", repo.name));
            _skip_count += 1;
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                let exists = branch_exists(&git_repo, branch_name);

                if create {
                    // -b flag: create if doesn't exist, checkout if it does
                    if exists {
                        match checkout_branch(&git_repo, branch_name) {
                            Ok(()) => {
                                Output::success(&format!(
                                    "{}: checked out (already exists)",
                                    repo.name
                                ));
                                success_count += 1;
                            }
                            Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
                        }
                    } else {
                        match create_and_checkout_branch(&git_repo, branch_name) {
                            Ok(()) => {
                                Output::success(&format!("{}: created and checked out", repo.name));
                                success_count += 1;
                            }
                            Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
                        }
                    }
                } else {
                    // Normal checkout: skip if branch doesn't exist
                    if !exists {
                        Output::info(&format!("{}: branch doesn't exist, skipping", repo.name));
                        _skip_count += 1;
                        continue;
                    }

                    match checkout_branch(&git_repo, branch_name) {
                        Ok(()) => {
                            Output::success(&repo.name);
                            success_count += 1;
                        }
                        Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
                    }
                }
            }
            Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
        }
    }

    println!();
    println!(
        "Switched {}/{} repos to {}",
        success_count,
        repos.len(),
        Output::branch_name(branch_name)
    );

    Ok(())
}

//! Cherry-pick command implementation
//!
//! Cherry-picks a commit across repos that contain it.

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::filter_repos;
use crate::git::cherry_pick::{
    cherry_pick, cherry_pick_abort, cherry_pick_continue, cherry_pick_in_progress, CherryPickResult,
};
use crate::git::path_exists;
use std::path::PathBuf;

/// Run the cherry-pick command
pub fn run_cherry_pick(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    commit: Option<&str>,
    abort: bool,
    continue_pick: bool,
    repos_filter: Option<&[String]>,
    group_filter: Option<&[String]>,
) -> anyhow::Result<()> {
    let repos = filter_repos(manifest, workspace_root, repos_filter, group_filter, false);

    if abort {
        Output::header("Aborting cherry-pick...");
        println!();

        let mut aborted = 0;
        for repo in &repos {
            if !path_exists(&repo.absolute_path) {
                continue;
            }

            if cherry_pick_in_progress(&repo.absolute_path) {
                match cherry_pick_abort(&repo.absolute_path) {
                    Ok(()) => {
                        Output::success(&format!("{}: cherry-pick aborted", repo.name));
                        aborted += 1;
                    }
                    Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
                }
            }
        }

        if aborted == 0 {
            Output::info("No cherry-pick in progress in any repo.");
        }
        return Ok(());
    }

    if continue_pick {
        Output::header("Continuing cherry-pick...");
        println!();

        let mut continued = 0;
        for repo in &repos {
            if !path_exists(&repo.absolute_path) {
                continue;
            }

            if cherry_pick_in_progress(&repo.absolute_path) {
                match cherry_pick_continue(&repo.absolute_path) {
                    Ok(()) => {
                        Output::success(&format!("{}: cherry-pick continued", repo.name));
                        continued += 1;
                    }
                    Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
                }
            }
        }

        if continued == 0 {
            Output::info("No cherry-pick in progress in any repo.");
        }
        return Ok(());
    }

    let commit_sha = match commit {
        Some(sha) => sha,
        None => {
            anyhow::bail!("Commit SHA required. Usage: gr cherry-pick <sha>");
        }
    };

    Output::header(&format!("Cherry-picking {}...", commit_sha));
    println!();

    let mut applied = 0;
    let mut skipped = 0;
    let mut conflicts = 0;

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            Output::warning(&format!("{}: not cloned, skipping", repo.name));
            continue;
        }

        match cherry_pick(&repo.absolute_path, commit_sha) {
            CherryPickResult::Applied => {
                Output::success(&format!("{}: applied", repo.name));
                applied += 1;
            }
            CherryPickResult::CommitNotFound => {
                skipped += 1;
                // Silently skip — commit only exists in one repo typically
            }
            CherryPickResult::Conflict(msg) => {
                Output::warning(&format!("{}: conflict", repo.name));
                if !msg.is_empty() {
                    // Print first few lines of conflict info
                    for line in msg.lines().take(5) {
                        println!("    {}", line);
                    }
                }
                conflicts += 1;
            }
            CherryPickResult::Error(msg) => {
                Output::error(&format!("{}: {}", repo.name, msg.trim()));
            }
        }
    }

    println!();
    if applied > 0 {
        Output::success(&format!(
            "Cherry-picked into {} repo(s), {} skipped.",
            applied, skipped
        ));
    } else if conflicts > 0 {
        Output::warning("Resolve conflicts and run 'gr cherry-pick --continue'");
    } else if repos.is_empty() {
        Output::info("No repos matched the given filters.");
    } else {
        Output::info(&format!("Commit {} not found in any repo.", commit_sha));
    }

    Ok(())
}

//! CI pipeline command implementation
//!
//! Provides `gr ci run`, `gr ci list`, and `gr ci status` for workspace CI/CD.

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use chrono::Utc;
use serde::{Deserialize, Serialize};
use std::path::PathBuf;
use std::process::Command;
use std::time::Instant;

/// Result of a single CI step
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StepResult {
    pub name: String,
    pub command: String,
    pub success: bool,
    pub exit_code: Option<i32>,
    pub duration_ms: u64,
    pub output: String,
}

/// Result of a pipeline run
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PipelineResult {
    pub pipeline: String,
    pub success: bool,
    pub steps: Vec<StepResult>,
    pub total_duration_ms: u64,
    pub timestamp: String,
}

/// Run a CI pipeline
pub fn run_ci_run(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    pipeline_name: &str,
    json: bool,
) -> anyhow::Result<()> {
    let ci_config = manifest
        .workspace
        .as_ref()
        .and_then(|w| w.ci.as_ref())
        .and_then(|ci| ci.pipelines.as_ref());

    let pipelines = match ci_config {
        Some(p) => p,
        None => {
            anyhow::bail!(
                "No CI pipelines defined in manifest. Add a 'workspace.ci.pipelines' section."
            );
        }
    };

    let pipeline = match pipelines.get(pipeline_name) {
        Some(p) => p,
        None => {
            let available: Vec<&String> = pipelines.keys().collect();
            anyhow::bail!(
                "Pipeline '{}' not found. Available: {:?}",
                pipeline_name,
                available
            );
        }
    };

    if !json {
        Output::header(&format!("Running pipeline: {}", pipeline_name));
        if let Some(ref desc) = pipeline.description {
            Output::info(desc);
        }
        println!();
    }

    let pipeline_start = Instant::now();
    let mut step_results: Vec<StepResult> = Vec::new();
    let mut pipeline_success = true;

    for step in &pipeline.steps {
        if !json {
            let spinner = Output::spinner(&format!("Running: {}...", step.name));

            let result = run_step(workspace_root, step, manifest);
            let step_result = result;

            if step_result.success {
                spinner.finish_with_message(format!(
                    "{}: passed ({}ms)",
                    step.name, step_result.duration_ms
                ));
            } else {
                spinner.finish_with_message(format!(
                    "{}: FAILED (exit {})",
                    step.name,
                    step_result.exit_code.unwrap_or(-1)
                ));

                if !step_result.output.is_empty() {
                    eprintln!("{}", step_result.output);
                }

                if !step.continue_on_error {
                    pipeline_success = false;
                    step_results.push(step_result);
                    break;
                }
                pipeline_success = false;
            }

            step_results.push(step_result);
        } else {
            let step_result = run_step(workspace_root, step, manifest);
            let failed = !step_result.success;
            step_results.push(step_result);

            if failed && !step.continue_on_error {
                pipeline_success = false;
                break;
            }
            if failed {
                pipeline_success = false;
            }
        }
    }

    let total_duration_ms = pipeline_start.elapsed().as_millis() as u64;

    let result = PipelineResult {
        pipeline: pipeline_name.to_string(),
        success: pipeline_success,
        steps: step_results,
        total_duration_ms,
        timestamp: Utc::now().to_rfc3339(),
    };

    // Save result to disk
    save_ci_result(workspace_root, &result)?;

    if json {
        println!("{}", serde_json::to_string_pretty(&result)?);
    } else {
        println!();
        if pipeline_success {
            Output::success(&format!(
                "Pipeline '{}' passed ({}ms)",
                pipeline_name, total_duration_ms
            ));
        } else {
            Output::error(&format!(
                "Pipeline '{}' failed ({}ms)",
                pipeline_name, total_duration_ms
            ));
        }
    }

    if !pipeline_success {
        anyhow::bail!("Pipeline '{}' failed", result.pipeline);
    }

    Ok(())
}

/// List available CI pipelines
pub fn run_ci_list(manifest: &Manifest, json: bool) -> anyhow::Result<()> {
    let ci_config = manifest
        .workspace
        .as_ref()
        .and_then(|w| w.ci.as_ref())
        .and_then(|ci| ci.pipelines.as_ref());

    let pipelines = match ci_config {
        Some(p) => p,
        None => {
            if json {
                println!("[]");
            } else {
                println!("No CI pipelines defined.");
            }
            return Ok(());
        }
    };

    if json {
        #[derive(Serialize)]
        struct PipelineInfo {
            name: String,
            description: Option<String>,
            steps: usize,
        }

        let infos: Vec<PipelineInfo> = pipelines
            .iter()
            .map(|(name, pipeline)| PipelineInfo {
                name: name.clone(),
                description: pipeline.description.clone(),
                steps: pipeline.steps.len(),
            })
            .collect();

        println!("{}", serde_json::to_string_pretty(&infos)?);
    } else {
        Output::header("CI Pipelines");
        println!();

        for (name, pipeline) in pipelines {
            let desc = pipeline
                .description
                .as_deref()
                .unwrap_or("(no description)");
            println!("  {} - {} ({} steps)", name, desc, pipeline.steps.len());
        }
    }

    Ok(())
}

/// Show status of last CI runs
pub fn run_ci_status(workspace_root: &PathBuf, json: bool) -> anyhow::Result<()> {
    let results_dir = workspace_root.join(".gitgrip").join("ci-results");

    if !results_dir.exists() {
        if json {
            println!("[]");
        } else {
            println!("No CI results found. Run 'gr ci run <pipeline>' first.");
        }
        return Ok(());
    }

    let mut results: Vec<PipelineResult> = Vec::new();

    for entry in std::fs::read_dir(&results_dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.extension().and_then(|e| e.to_str()) == Some("json") {
            let content = std::fs::read_to_string(&path)?;
            if let Ok(result) = serde_json::from_str::<PipelineResult>(&content) {
                results.push(result);
            }
        }
    }

    // Sort by timestamp (most recent first)
    results.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));

    if json {
        println!("{}", serde_json::to_string_pretty(&results)?);
    } else {
        Output::header("CI Status");
        println!();

        if results.is_empty() {
            println!("  No results found.");
        } else {
            for result in &results {
                let status = if result.success { "PASS" } else { "FAIL" };
                let passed = result.steps.iter().filter(|s| s.success).count();
                let total = result.steps.len();
                println!(
                    "  {} {} - {} ({}/{} steps, {}ms) [{}]",
                    if result.success { "✓" } else { "✗" },
                    result.pipeline,
                    status,
                    passed,
                    total,
                    result.total_duration_ms,
                    result.timestamp
                );
            }
        }
    }

    Ok(())
}

/// Run a single CI step
fn run_step(
    workspace_root: &PathBuf,
    step: &crate::core::manifest::CiStep,
    manifest: &Manifest,
) -> StepResult {
    let start = Instant::now();

    // Resolve working directory
    let cwd = match &step.cwd {
        Some(dir) => workspace_root.join(dir),
        None => workspace_root.clone(),
    };

    let mut cmd = Command::new("sh");
    cmd.arg("-c").arg(&step.command).current_dir(&cwd);

    // Set workspace env vars
    if let Some(ref workspace) = manifest.workspace {
        if let Some(ref env) = workspace.env {
            for (key, value) in env {
                cmd.env(key, value);
            }
        }
    }

    // Set step-specific env vars
    if let Some(ref env) = step.env {
        for (key, value) in env {
            cmd.env(key, value);
        }
    }

    match cmd.output() {
        Ok(output) => {
            let duration_ms = start.elapsed().as_millis() as u64;
            let stdout = String::from_utf8_lossy(&output.stdout);
            let stderr = String::from_utf8_lossy(&output.stderr);
            let combined = if stderr.is_empty() {
                stdout.to_string()
            } else {
                format!("{}\n{}", stdout, stderr)
            };

            StepResult {
                name: step.name.clone(),
                command: step.command.clone(),
                success: output.status.success(),
                exit_code: output.status.code(),
                duration_ms,
                output: combined,
            }
        }
        Err(e) => StepResult {
            name: step.name.clone(),
            command: step.command.clone(),
            success: false,
            exit_code: None,
            duration_ms: start.elapsed().as_millis() as u64,
            output: format!("Failed to execute: {}", e),
        },
    }
}

/// Save CI result to disk
fn save_ci_result(workspace_root: &PathBuf, result: &PipelineResult) -> anyhow::Result<()> {
    let results_dir = workspace_root.join(".gitgrip").join("ci-results");
    std::fs::create_dir_all(&results_dir)?;

    let filename = format!("{}.json", result.pipeline);
    let path = results_dir.join(filename);
    let json = serde_json::to_string_pretty(result)?;
    std::fs::write(path, json)?;

    Ok(())
}

//! Commit command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::manifest_paths;
use crate::core::repo::RepoInfo;
use crate::git::cache::invalidate_status_cache;
use crate::git::{get_workdir, open_repo, path_exists};
use crate::util::log_cmd;
use git2::Repository;
use std::path::PathBuf;
use std::process::Command;

/// Run the commit command
pub fn run_commit(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    message: &str,
    amend: bool,
    json: bool,
) -> anyhow::Result<()> {
    if !json {
        Output::header("Committing changes...");
        println!();
    }

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    let mut success_count = 0;
    let mut skip_count = 0;

    #[derive(serde::Serialize)]
    struct JsonCommit {
        repo: String,
        sha: String,
    }
    let mut json_committed: Vec<JsonCommit> = Vec::new();
    let mut json_skipped: Vec<String> = Vec::new();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                // Check if there are staged changes
                if !has_staged_changes(&git_repo)? {
                    skip_count += 1;
                    json_skipped.push(repo.name.clone());
                    continue;
                }

                match create_commit(&git_repo, message, amend) {
                    Ok(commit_id) => {
                        let short_id = &commit_id[..7.min(commit_id.len())];
                        if !json {
                            if amend {
                                Output::success(&format!("{}: amended ({})", repo.name, short_id));
                            } else {
                                Output::success(&format!(
                                    "{}: committed ({})",
                                    repo.name, short_id
                                ));
                            }
                        }
                        success_count += 1;
                        json_committed.push(JsonCommit {
                            repo: repo.name.clone(),
                            sha: commit_id.clone(),
                        });
                        invalidate_status_cache(&repo.absolute_path);
                    }
                    Err(e) => {
                        if !json {
                            Output::error(&format!("{}: {}", repo.name, e));
                        }
                    }
                }
            }
            Err(e) => {
                if !json {
                    Output::error(&format!("{}: {}", repo.name, e));
                }
            }
        }
    }

    // Also handle manifest worktree if it exists (in griptree scenario)
    if let Some(manifests_dir) = manifest_paths::resolve_manifest_repo_dir(workspace_root) {
        let manifests_git_dir = manifests_dir.join(".git");
        if manifests_git_dir.exists() && path_exists(&manifests_dir) {
            match open_repo(&manifests_dir) {
                Ok(git_repo) => {
                    if has_staged_changes(&git_repo)? {
                        match create_commit(&git_repo, message, amend) {
                            Ok(commit_id) => {
                                let short_id = &commit_id[..7.min(commit_id.len())];
                                if !json {
                                    if amend {
                                        Output::success(&format!(
                                            "manifest: amended ({})",
                                            short_id
                                        ));
                                    } else {
                                        Output::success(&format!(
                                            "manifest: committed ({})",
                                            short_id
                                        ));
                                    }
                                }
                                success_count += 1;
                                json_committed.push(JsonCommit {
                                    repo: "manifest".to_string(),
                                    sha: commit_id.clone(),
                                });
                                invalidate_status_cache(&manifests_dir);
                            }
                            Err(e) => {
                                if !json {
                                    Output::error(&format!("manifest: {}", e));
                                }
                            }
                        }
                    }
                }
                Err(e) => {
                    if !json {
                        Output::warning(&format!("manifest: {}", e));
                    }
                }
            }
        }
    }

    if json {
        #[derive(serde::Serialize)]
        struct JsonCommitResult {
            success: bool,
            committed: Vec<JsonCommit>,
            skipped: Vec<String>,
        }

        let result = JsonCommitResult {
            success: !json_committed.is_empty(),
            committed: json_committed,
            skipped: json_skipped,
        };
        println!("{}", serde_json::to_string_pretty(&result)?);
    } else {
        println!();
        if success_count > 0 {
            println!(
                "Created {} commit(s){}.",
                success_count,
                if skip_count > 0 {
                    format!(", {} repo(s) had no staged changes", skip_count)
                } else {
                    String::new()
                }
            );
        } else {
            println!("No changes to commit.");
        }
    }

    Ok(())
}

/// Check if a repository has staged changes using git CLI
fn has_staged_changes(repo: &Repository) -> anyhow::Result<bool> {
    let repo_path = get_workdir(repo);

    let mut cmd = Command::new("git");
    cmd.args(["diff", "--cached", "--quiet"])
        .current_dir(repo_path);
    log_cmd(&cmd);
    let output = cmd.output()?;

    // Exit code 0 means no diff (no staged changes)
    // Exit code 1 means there are changes
    Ok(!output.status.success())
}

/// Create a commit in the repository using git CLI
fn create_commit(repo: &Repository, message: &str, amend: bool) -> anyhow::Result<String> {
    let repo_path = get_workdir(repo);

    let mut args = vec!["commit", "-m", message];
    if amend {
        args.push("--amend");
    }

    let mut cmd = Command::new("git");
    cmd.args(&args).current_dir(repo_path);
    log_cmd(&cmd);
    let output = cmd.output()?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        anyhow::bail!("git commit failed: {}", stderr);
    }

    // Get the commit hash
    let mut cmd = Command::new("git");
    cmd.args(["rev-parse", "HEAD"]).current_dir(repo_path);
    log_cmd(&cmd);
    let hash_output = cmd.output()?;

    let commit_id = String::from_utf8_lossy(&hash_output.stdout)
        .trim()
        .to_string();
    Ok(commit_id)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::git::open_repo;
    use std::fs;
    use std::process::Command as StdCommand;
    use tempfile::TempDir;

    fn setup_test_repo() -> (TempDir, Repository) {
        let temp_dir = TempDir::new().unwrap();

        StdCommand::new("git")
            .args(["init"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        StdCommand::new("git")
            .args(["config", "user.name", "Test User"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        StdCommand::new("git")
            .args(["config", "user.email", "test@example.com"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        let repo = open_repo(temp_dir.path()).unwrap();
        (temp_dir, repo)
    }

    #[test]
    fn test_has_staged_changes_empty() {
        let (_temp_dir, repo) = setup_test_repo();
        assert!(!has_staged_changes(&repo).unwrap());
    }

    #[test]
    fn test_has_staged_changes_with_staged() {
        let (temp_dir, repo) = setup_test_repo();

        // Create and stage a file
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "content").unwrap();

        StdCommand::new("git")
            .args(["add", "test.txt"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        assert!(has_staged_changes(&repo).unwrap());
    }

    #[test]
    fn test_create_commit() {
        let (temp_dir, repo) = setup_test_repo();

        // Create and stage a file
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "content").unwrap();

        StdCommand::new("git")
            .args(["add", "test.txt"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        let commit_id = create_commit(&repo, "Test commit", false).unwrap();
        assert!(!commit_id.is_empty());

        // Verify commit was created
        let output = StdCommand::new("git")
            .args(["log", "-1", "--format=%s"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();
        let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
        assert_eq!(message, "Test commit");
    }

    #[test]
    fn test_amend_commit() {
        let (temp_dir, repo) = setup_test_repo();

        // Create initial commit
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "initial").unwrap();

        StdCommand::new("git")
            .args(["add", "test.txt"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        create_commit(&repo, "Initial commit", false).unwrap();

        // Modify and stage
        fs::write(&file_path, "amended").unwrap();

        StdCommand::new("git")
            .args(["add", "test.txt"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();

        // Amend
        create_commit(&repo, "Amended commit", true).unwrap();

        // Verify only one commit exists
        let output = StdCommand::new("git")
            .args(["rev-list", "--count", "HEAD"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();
        let count: usize = String::from_utf8_lossy(&output.stdout)
            .trim()
            .parse()
            .unwrap();
        assert_eq!(count, 1);

        // Verify message was updated
        let output = StdCommand::new("git")
            .args(["log", "-1", "--format=%s"])
            .current_dir(temp_dir.path())
            .output()
            .unwrap();
        let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
        assert_eq!(message, "Amended commit");
    }
}

//! Diff command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{get_manifest_repo_info, RepoInfo};
use crate::git::{open_repo, path_exists};
use git2::{DiffOptions, Repository};
use std::path::PathBuf;

/// Run the diff command
pub fn run_diff(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    staged: bool,
    json: bool,
) -> anyhow::Result<()> {
    let mut repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    // Include manifest repo in diff operations
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.push(manifest_repo);
    }

    if json {
        return run_diff_json(workspace_root, &repos, staged);
    }

    let mut has_changes = false;

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                let diff_output = get_diff(&git_repo, staged)?;
                if !diff_output.is_empty() {
                    if has_changes {
                        println!();
                    }
                    Output::header(&format!("diff: {}", repo.name));
                    println!("{}", diff_output);
                    has_changes = true;
                }
            }
            Err(e) => Output::error(&format!("{}: {}", repo.name, e)),
        }
    }

    if !has_changes {
        println!("No changes.");
    }

    Ok(())
}

/// Run diff in JSON mode
fn run_diff_json(
    _workspace_root: &PathBuf,
    repos: &[RepoInfo],
    staged: bool,
) -> anyhow::Result<()> {
    #[derive(serde::Serialize)]
    struct JsonDiff {
        repo: String,
        diff: String,
        files_changed: usize,
    }

    let mut results: Vec<JsonDiff> = Vec::new();

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                let diff_output = get_diff(&git_repo, staged)?;
                if !diff_output.is_empty() {
                    // Count files changed by counting "diff --git" headers
                    let files_changed = diff_output
                        .lines()
                        .filter(|l| l.starts_with("diff --git"))
                        .count();
                    let files_changed = if files_changed == 0 { 1 } else { files_changed };
                    results.push(JsonDiff {
                        repo: repo.name.clone(),
                        diff: diff_output,
                        files_changed,
                    });
                }
            }
            Err(_) => continue,
        }
    }

    println!("{}", serde_json::to_string_pretty(&results)?);
    Ok(())
}

/// Get diff output for a repository
fn get_diff(repo: &Repository, staged: bool) -> anyhow::Result<String> {
    let mut output = String::new();
    let mut opts = DiffOptions::new();

    let diff = if staged {
        // Diff between HEAD and index (staged changes)
        let head = repo.head()?.peel_to_tree()?;
        repo.diff_tree_to_index(Some(&head), None, Some(&mut opts))?
    } else {
        // Diff between index and workdir (unstaged changes)
        repo.diff_index_to_workdir(None, Some(&mut opts))?
    };

    diff.print(git2::DiffFormat::Patch, |_delta, _hunk, line| {
        let prefix = match line.origin() {
            '+' => "+",
            '-' => "-",
            ' ' => " ",
            '>' => ">",
            '<' => "<",
            'F' => "", // File header
            'H' => "", // Hunk header
            'B' => "", // Binary
            _ => "",
        };

        // Color the output
        let content = std::str::from_utf8(line.content()).unwrap_or("");
        let colored_line = match line.origin() {
            '+' => format!("\x1b[32m{}{}\x1b[0m", prefix, content.trim_end()),
            '-' => format!("\x1b[31m{}{}\x1b[0m", prefix, content.trim_end()),
            '@' => format!("\x1b[36m{}\x1b[0m", content.trim_end()),
            _ => format!("{}{}", prefix, content.trim_end()),
        };

        output.push_str(&colored_line);
        output.push('\n');
        true
    })?;

    Ok(output)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use tempfile::TempDir;

    fn setup_test_repo() -> (TempDir, Repository) {
        let temp_dir = TempDir::new().unwrap();
        let repo = Repository::init(temp_dir.path()).unwrap();

        // Configure user for commits
        let mut config = repo.config().unwrap();
        config.set_str("user.name", "Test User").unwrap();
        config.set_str("user.email", "test@example.com").unwrap();

        // Create initial file and commit
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "initial content\n").unwrap();

        {
            let mut index = repo.index().unwrap();
            index.add_path(std::path::Path::new("test.txt")).unwrap();
            index.write().unwrap();

            let tree_id = index.write_tree().unwrap();
            let tree = repo.find_tree(tree_id).unwrap();
            let sig = repo.signature().unwrap();

            repo.commit(Some("HEAD"), &sig, &sig, "Initial commit", &tree, &[])
                .unwrap();
        }

        (temp_dir, repo)
    }

    #[test]
    fn test_diff_unstaged_changes() {
        let (temp_dir, repo) = setup_test_repo();

        // Modify the file (unstaged)
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "modified content\n").unwrap();

        let diff_output = get_diff(&repo, false).unwrap();
        assert!(diff_output.contains("-initial content"));
        assert!(diff_output.contains("+modified content"));
    }

    #[test]
    fn test_diff_staged_changes() {
        let (temp_dir, repo) = setup_test_repo();

        // Modify and stage the file
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "staged content\n").unwrap();

        {
            let mut index = repo.index().unwrap();
            index.add_path(std::path::Path::new("test.txt")).unwrap();
            index.write().unwrap();
        }

        let diff_output = get_diff(&repo, true).unwrap();
        assert!(diff_output.contains("-initial content"));
        assert!(diff_output.contains("+staged content"));
    }

    #[test]
    fn test_diff_no_changes() {
        let (_temp_dir, repo) = setup_test_repo();
        let diff_output = get_diff(&repo, false).unwrap();
        assert!(diff_output.is_empty());
    }
}

//! Env command implementation
//!
//! Displays workspace environment variables.

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::manifest_paths;
use std::path::PathBuf;

/// Run the env command
pub fn run_env(workspace_root: &PathBuf, manifest: &Manifest) -> anyhow::Result<()> {
    Output::header("Workspace Environment");
    println!();

    // Built-in environment variables
    println!("  GITGRIP_WORKSPACE={}", workspace_root.display());
    let manifest_path = manifest_paths::resolve_gripspace_manifest_path(workspace_root)
        .or_else(|| manifest_paths::resolve_repo_manifest_path(workspace_root))
        .unwrap_or_else(|| manifest_paths::default_gripspace_manifest_path(workspace_root));
    println!("  GITGRIP_MANIFEST={}", manifest_path.display());

    // Workspace-defined environment variables
    if let Some(ref workspace) = manifest.workspace {
        if let Some(ref env_vars) = workspace.env {
            println!();
            println!("Workspace variables:");
            for (key, value) in env_vars {
                println!("  {}={}", key, value);
            }
        }
    }

    Ok(())
}

//! Forall command implementation
//!
//! Runs a command in each repository.
//!
//! Includes optimization: common git commands are intercepted and run using
//! the git2/gix library instead of spawning git CLI processes, providing
//! up to 100x speedup.
//!
//! Supports:
//! - Direct git commands (git status, git branch, etc.)
//! - Piped commands (git status | grep modified)
//! - Redirected commands (git log > file.txt)

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, RepoInfo};
use crate::git::path_exists;
use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::{Command, Stdio};

/// Diff output format
#[derive(Debug, Clone)]
enum DiffFormat {
    Stat,
    NameOnly,
    NameStatus,
    Patch,
}

/// Interceptable git commands for optimization
#[derive(Debug, Clone)]
enum GitCommand {
    /// git status [--porcelain|-s]
    Status { porcelain: bool },
    /// git branch [-a|-r]
    ListBranches { all: bool, remotes: bool },
    /// git rev-parse HEAD
    GetHead,
    /// git rev-parse --abbrev-ref HEAD
    GetBranch,
    /// git rev-parse --short HEAD
    GetHeadShort,
    /// git log --oneline [-n N]
    LogOneline { count: usize },
    /// git diff [--staged] [format]
    Diff { staged: bool, format: DiffFormat },
    /// git ls-files [-m]
    LsFiles { modified: bool },
    /// git tag [-l]
    TagList,
    /// git remote [-v]
    Remote { verbose: bool },
    /// git stash list
    StashList,
    /// git blame FILE
    Blame { file: String },
    /// git config --get KEY
    ConfigGet { key: String },
}

/// Parsed command with optional pipe or redirect
#[derive(Debug)]
enum ParsedCommand {
    /// Simple git command
    Git(GitCommand),
    /// Git command piped to another command
    Piped {
        git_cmd: GitCommand,
        pipe_to: String,
    },
    /// Git command redirected to file
    Redirect {
        git_cmd: GitCommand,
        file: String,
        append: bool,
    },
    /// Not interceptable, run as shell command
    Shell(String),
}

/// Parse a command string, handling pipes and redirects
fn parse_command(command: &str) -> ParsedCommand {
    let trimmed = command.trim();

    // Check for pipe
    if let Some(pipe_pos) = trimmed.find('|') {
        let git_part = trimmed[..pipe_pos].trim();
        let pipe_part = trimmed[pipe_pos + 1..].trim();

        if let Some(git_cmd) = try_parse_git_command(git_part) {
            return ParsedCommand::Piped {
                git_cmd,
                pipe_to: pipe_part.to_string(),
            };
        }
    }

    // Check for redirect (>> before >)
    if let Some(pos) = trimmed.find(">>") {
        let git_part = trimmed[..pos].trim();
        let file = trimmed[pos + 2..].trim();

        if let Some(git_cmd) = try_parse_git_command(git_part) {
            return ParsedCommand::Redirect {
                git_cmd,
                file: file.to_string(),
                append: true,
            };
        }
    } else if let Some(pos) = trimmed.find('>') {
        let git_part = trimmed[..pos].trim();
        let file = trimmed[pos + 1..].trim();

        if let Some(git_cmd) = try_parse_git_command(git_part) {
            return ParsedCommand::Redirect {
                git_cmd,
                file: file.to_string(),
                append: false,
            };
        }
    }

    // Try simple git command
    if let Some(git_cmd) = try_parse_git_command(trimmed) {
        return ParsedCommand::Git(git_cmd);
    }

    // Fall back to shell
    ParsedCommand::Shell(command.to_string())
}

/// Try to parse a command string into an interceptable GitCommand
fn try_parse_git_command(command: &str) -> Option<GitCommand> {
    let trimmed = command.trim();
    let parts: Vec<&str> = trimmed.split_whitespace().collect();

    match parts.as_slice() {
        // === STATUS ===
        ["git", "status"] => Some(GitCommand::Status { porcelain: false }),
        ["git", "status", "--porcelain"] => Some(GitCommand::Status { porcelain: true }),
        ["git", "status", "-s"] => Some(GitCommand::Status { porcelain: true }),
        ["git", "status", "--short"] => Some(GitCommand::Status { porcelain: true }),

        // === BRANCH ===
        ["git", "branch"] => Some(GitCommand::ListBranches {
            all: false,
            remotes: false,
        }),
        ["git", "branch", "-a"] => Some(GitCommand::ListBranches {
            all: true,
            remotes: false,
        }),
        ["git", "branch", "--all"] => Some(GitCommand::ListBranches {
            all: true,
            remotes: false,
        }),
        ["git", "branch", "-r"] => Some(GitCommand::ListBranches {
            all: false,
            remotes: true,
        }),
        ["git", "branch", "--remotes"] => Some(GitCommand::ListBranches {
            all: false,
            remotes: true,
        }),

        // === REV-PARSE ===
        ["git", "rev-parse", "HEAD"] => Some(GitCommand::GetHead),
        ["git", "rev-parse", "--abbrev-ref", "HEAD"] => Some(GitCommand::GetBranch),
        ["git", "rev-parse", "--short", "HEAD"] => Some(GitCommand::GetHeadShort),

        // === LOG ===
        ["git", "log", "--oneline"] => Some(GitCommand::LogOneline { count: 10 }),
        ["git", "log", "--oneline", "-n", n] => {
            n.parse().ok().map(|count| GitCommand::LogOneline { count })
        }
        ["git", "log", "--oneline", n] if n.starts_with('-') => n[1..]
            .parse()
            .ok()
            .map(|count| GitCommand::LogOneline { count }),
        ["git", "log", "-1", "--oneline"] => Some(GitCommand::LogOneline { count: 1 }),
        ["git", "log", n, "--oneline"] if n.starts_with('-') => n[1..]
            .parse()
            .ok()
            .map(|count| GitCommand::LogOneline { count }),

        // === DIFF ===
        ["git", "diff"] => Some(GitCommand::Diff {
            staged: false,
            format: DiffFormat::Patch,
        }),
        ["git", "diff", "--stat"] => Some(GitCommand::Diff {
            staged: false,
            format: DiffFormat::Stat,
        }),
        ["git", "diff", "--name-only"] => Some(GitCommand::Diff {
            staged: false,
            format: DiffFormat::NameOnly,
        }),
        ["git", "diff", "--name-status"] => Some(GitCommand::Diff {
            staged: false,
            format: DiffFormat::NameStatus,
        }),
        ["git", "diff", "--staged"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::Patch,
        }),
        ["git", "diff", "--cached"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::Patch,
        }),
        ["git", "diff", "--staged", "--stat"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::Stat,
        }),
        ["git", "diff", "--cached", "--stat"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::Stat,
        }),
        ["git", "diff", "--staged", "--name-only"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::NameOnly,
        }),
        ["git", "diff", "--cached", "--name-only"] => Some(GitCommand::Diff {
            staged: true,
            format: DiffFormat::NameOnly,
        }),

        // === LS-FILES ===
        ["git", "ls-files"] => Some(GitCommand::LsFiles { modified: false }),
        ["git", "ls-files", "-m"] => Some(GitCommand::LsFiles { modified: true }),
        ["git", "ls-files", "--modified"] => Some(GitCommand::LsFiles { modified: true }),

        // === TAG ===
        ["git", "tag"] => Some(GitCommand::TagList),
        ["git", "tag", "-l"] => Some(GitCommand::TagList),
        ["git", "tag", "--list"] => Some(GitCommand::TagList),

        // === REMOTE ===
        ["git", "remote"] => Some(GitCommand::Remote { verbose: false }),
        ["git", "remote", "-v"] => Some(GitCommand::Remote { verbose: true }),
        ["git", "remote", "--verbose"] => Some(GitCommand::Remote { verbose: true }),

        // === STASH ===
        ["git", "stash", "list"] => Some(GitCommand::StashList),

        // === BLAME ===
        ["git", "blame", file] => Some(GitCommand::Blame {
            file: file.to_string(),
        }),

        // === CONFIG ===
        ["git", "config", "--get", key] => Some(GitCommand::ConfigGet {
            key: key.to_string(),
        }),

        _ => None,
    }
}

/// Execute an intercepted git command using git2 (fast path)
fn execute_git_command(repo_path: &PathBuf, cmd: &GitCommand) -> Result<String, String> {
    let repo =
        crate::git::open_repo(repo_path).map_err(|e| format!("Failed to open repo: {}", e))?;

    match cmd {
        GitCommand::Status { porcelain } => execute_status(&repo, *porcelain),
        GitCommand::ListBranches { all, remotes } => execute_branches(&repo, *all, *remotes),
        GitCommand::GetHead => execute_get_head(&repo),
        GitCommand::GetBranch => execute_get_branch(&repo),
        GitCommand::GetHeadShort => execute_get_head_short(&repo),
        GitCommand::LogOneline { count } => execute_log_oneline(&repo, *count),
        GitCommand::Diff { staged, format } => execute_diff(&repo, *staged, format),
        GitCommand::LsFiles { modified } => execute_ls_files(&repo, *modified),
        GitCommand::TagList => execute_tag_list(&repo),
        GitCommand::Remote { verbose } => execute_remote(&repo, *verbose),
        GitCommand::StashList => execute_stash_list(&repo),
        GitCommand::Blame { file } => execute_blame(&repo, repo_path, file),
        GitCommand::ConfigGet { key } => execute_config_get(&repo, key),
    }
}

fn execute_status(repo: &git2::Repository, porcelain: bool) -> Result<String, String> {
    let statuses = repo
        .statuses(None)
        .map_err(|e| format!("Failed to get status: {}", e))?;

    if porcelain {
        let mut output = String::new();
        for entry in statuses.iter() {
            let status = entry.status();
            let path = entry.path().unwrap_or("?");

            let index_status = if status.is_index_new() {
                'A'
            } else if status.is_index_modified() {
                'M'
            } else if status.is_index_deleted() {
                'D'
            } else if status.is_index_renamed() {
                'R'
            } else if status.is_index_typechange() {
                'T'
            } else {
                ' '
            };

            let wt_status = if status.is_wt_new() {
                '?'
            } else if status.is_wt_modified() {
                'M'
            } else if status.is_wt_deleted() {
                'D'
            } else if status.is_wt_renamed() {
                'R'
            } else if status.is_wt_typechange() {
                'T'
            } else {
                ' '
            };

            output.push_str(&format!("{}{} {}\n", index_status, wt_status, path));
        }
        Ok(output)
    } else {
        if statuses.is_empty() {
            return Ok("nothing to commit, working tree clean\n".to_string());
        }

        let mut output = String::new();
        let mut staged = Vec::new();
        let mut unstaged = Vec::new();
        let mut untracked = Vec::new();

        for entry in statuses.iter() {
            let path = entry.path().unwrap_or("?").to_string();
            let status = entry.status();

            if status.is_index_new() || status.is_index_modified() || status.is_index_deleted() {
                staged.push(path.clone());
            }
            if status.is_wt_modified() || status.is_wt_deleted() {
                unstaged.push(path.clone());
            }
            if status.is_wt_new() {
                untracked.push(path);
            }
        }

        if !staged.is_empty() {
            output.push_str("Changes to be committed:\n");
            for f in &staged {
                output.push_str(&format!("  {}\n", f));
            }
        }
        if !unstaged.is_empty() {
            output.push_str("Changes not staged for commit:\n");
            for f in &unstaged {
                output.push_str(&format!("  {}\n", f));
            }
        }
        if !untracked.is_empty() {
            output.push_str("Untracked files:\n");
            for f in &untracked {
                output.push_str(&format!("  {}\n", f));
            }
        }
        Ok(output)
    }
}

fn execute_branches(repo: &git2::Repository, all: bool, remotes: bool) -> Result<String, String> {
    let mut output = String::new();
    let head = repo.head().ok();
    let current_branch = head.as_ref().and_then(|h| h.shorthand()).unwrap_or("");

    // Local branches (unless remotes-only)
    if !remotes {
        let branches = repo
            .branches(Some(git2::BranchType::Local))
            .map_err(|e| format!("Failed to list branches: {}", e))?;

        for branch in branches {
            let (branch, _) = branch.map_err(|e| format!("Failed to read branch: {}", e))?;
            let name = branch
                .name()
                .map_err(|e| format!("Failed to get branch name: {}", e))?
                .unwrap_or("?");

            if name == current_branch {
                output.push_str(&format!("* {}\n", name));
            } else {
                output.push_str(&format!("  {}\n", name));
            }
        }
    }

    // Remote branches if -a or -r flag
    if all || remotes {
        let remote_branches = repo
            .branches(Some(git2::BranchType::Remote))
            .map_err(|e| format!("Failed to list remote branches: {}", e))?;

        for branch in remote_branches {
            let (branch, _) = branch.map_err(|e| format!("Failed to read branch: {}", e))?;
            let name = branch
                .name()
                .map_err(|e| format!("Failed to get branch name: {}", e))?
                .unwrap_or("?");
            output.push_str(&format!("  remotes/{}\n", name));
        }
    }

    Ok(output)
}

fn execute_get_head(repo: &git2::Repository) -> Result<String, String> {
    let head = repo
        .head()
        .map_err(|e| format!("Failed to get HEAD: {}", e))?;
    let oid = head
        .target()
        .ok_or_else(|| "HEAD has no target".to_string())?;
    Ok(format!("{}\n", oid))
}

fn execute_get_branch(repo: &git2::Repository) -> Result<String, String> {
    let head = repo
        .head()
        .map_err(|e| format!("Failed to get HEAD: {}", e))?;
    let name = head.shorthand().unwrap_or("HEAD");
    Ok(format!("{}\n", name))
}

fn execute_get_head_short(repo: &git2::Repository) -> Result<String, String> {
    let head = repo
        .head()
        .map_err(|e| format!("Failed to get HEAD: {}", e))?;
    let oid = head
        .target()
        .ok_or_else(|| "HEAD has no target".to_string())?;
    Ok(format!("{}\n", &oid.to_string()[..7]))
}

fn execute_log_oneline(repo: &git2::Repository, count: usize) -> Result<String, String> {
    let mut revwalk = repo
        .revwalk()
        .map_err(|e| format!("Failed to create revwalk: {}", e))?;
    revwalk
        .push_head()
        .map_err(|e| format!("Failed to push HEAD: {}", e))?;

    let mut output = String::new();
    for oid in revwalk.take(count) {
        let oid = oid.map_err(|e| format!("Failed to get oid: {}", e))?;
        let commit = repo
            .find_commit(oid)
            .map_err(|e| format!("Failed to find commit: {}", e))?;
        let short = &oid.to_string()[..7];
        let msg = commit.summary().unwrap_or("");
        output.push_str(&format!("{} {}\n", short, msg));
    }
    Ok(output)
}

fn execute_diff(
    repo: &git2::Repository,
    staged: bool,
    format: &DiffFormat,
) -> Result<String, String> {
    let diff = if staged {
        let head = repo
            .head()
            .map_err(|e| format!("Failed to get HEAD: {}", e))?;
        let tree = head
            .peel_to_tree()
            .map_err(|e| format!("Failed to get tree: {}", e))?;
        repo.diff_tree_to_index(Some(&tree), None, None)
    } else {
        repo.diff_index_to_workdir(None, None)
    }
    .map_err(|e| format!("Failed to get diff: {}", e))?;

    match format {
        DiffFormat::Stat => {
            let stats = diff
                .stats()
                .map_err(|e| format!("Failed to get stats: {}", e))?;
            let mut output = String::new();

            for delta in diff.deltas() {
                let path = delta
                    .new_file()
                    .path()
                    .map(|p| p.display().to_string())
                    .unwrap_or_else(|| "?".to_string());
                output.push_str(&format!(" {} |\n", path));
            }

            output.push_str(&format!(
                " {} files changed, {} insertions(+), {} deletions(-)\n",
                stats.files_changed(),
                stats.insertions(),
                stats.deletions()
            ));
            Ok(output)
        }
        DiffFormat::NameOnly => {
            let output: Vec<String> = diff
                .deltas()
                .filter_map(|d| d.new_file().path().map(|p| p.display().to_string()))
                .collect();
            Ok(output.join("\n") + if output.is_empty() { "" } else { "\n" })
        }
        DiffFormat::NameStatus => {
            let mut output = String::new();
            for delta in diff.deltas() {
                let status = match delta.status() {
                    git2::Delta::Added => 'A',
                    git2::Delta::Deleted => 'D',
                    git2::Delta::Modified => 'M',
                    git2::Delta::Renamed => 'R',
                    git2::Delta::Copied => 'C',
                    _ => '?',
                };
                let path = delta
                    .new_file()
                    .path()
                    .map(|p| p.display().to_string())
                    .unwrap_or_else(|| "?".to_string());
                output.push_str(&format!("{}\t{}\n", status, path));
            }
            Ok(output)
        }
        DiffFormat::Patch => {
            let mut output = String::new();
            diff.print(git2::DiffFormat::Patch, |_delta, _hunk, line| {
                let prefix = match line.origin() {
                    '+' => "+",
                    '-' => "-",
                    ' ' => " ",
                    'H' => "", // hunk header
                    'F' => "", // file header
                    _ => "",
                };
                if let Ok(content) = std::str::from_utf8(line.content()) {
                    if !prefix.is_empty() || line.origin() == 'H' || line.origin() == 'F' {
                        output.push_str(prefix);
                        output.push_str(content);
                    }
                }
                true
            })
            .map_err(|e| format!("Failed to print diff: {}", e))?;
            Ok(output)
        }
    }
}

fn execute_ls_files(repo: &git2::Repository, modified: bool) -> Result<String, String> {
    if modified {
        let statuses = repo
            .statuses(None)
            .map_err(|e| format!("Failed to get status: {}", e))?;
        let files: Vec<String> = statuses
            .iter()
            .filter(|e| e.status().is_wt_modified() || e.status().is_index_modified())
            .filter_map(|e| e.path().map(String::from))
            .collect();
        Ok(files.join("\n") + if files.is_empty() { "" } else { "\n" })
    } else {
        let index = repo
            .index()
            .map_err(|e| format!("Failed to get index: {}", e))?;
        let files: Vec<String> = index
            .iter()
            .filter_map(|e| String::from_utf8(e.path.clone()).ok())
            .collect();
        Ok(files.join("\n") + if files.is_empty() { "" } else { "\n" })
    }
}

fn execute_tag_list(repo: &git2::Repository) -> Result<String, String> {
    let mut tags = Vec::new();
    repo.tag_foreach(|_, name| {
        if let Ok(name) = std::str::from_utf8(name) {
            let name = name.strip_prefix("refs/tags/").unwrap_or(name);
            tags.push(name.to_string());
        }
        true
    })
    .map_err(|e| format!("Failed to list tags: {}", e))?;
    tags.sort();
    Ok(tags.join("\n") + if tags.is_empty() { "" } else { "\n" })
}

fn execute_remote(repo: &git2::Repository, verbose: bool) -> Result<String, String> {
    let remotes = repo
        .remotes()
        .map_err(|e| format!("Failed to get remotes: {}", e))?;
    let mut output = String::new();

    for name in remotes.iter().flatten() {
        if verbose {
            if let Ok(remote) = repo.find_remote(name) {
                let url = remote.url().unwrap_or("");
                output.push_str(&format!("{}\t{} (fetch)\n", name, url));
                output.push_str(&format!(
                    "{}\t{} (push)\n",
                    name,
                    remote.pushurl().unwrap_or(url)
                ));
            }
        } else {
            output.push_str(&format!("{}\n", name));
        }
    }
    Ok(output)
}

fn execute_stash_list(repo: &git2::Repository) -> Result<String, String> {
    // git2's stash_foreach requires &mut self, so we iterate refs instead
    let mut stashes = Vec::new();

    // Stashes are stored as refs/stash with reflog entries
    if let Ok(reference) = repo.find_reference("refs/stash") {
        if let Ok(reflog) = repo.reflog("refs/stash") {
            for (idx, entry) in reflog.iter().enumerate() {
                let msg = entry.message().unwrap_or("");
                stashes.push(format!("stash@{{{}}}: {}", idx, msg));
            }
        } else if let Some(oid) = reference.target() {
            // If no reflog, at least show the current stash
            if let Ok(commit) = repo.find_commit(oid) {
                let msg = commit.summary().unwrap_or("WIP");
                stashes.push(format!(
                    "stash@{{0}}: On {}: {}",
                    commit
                        .parent(0)
                        .ok()
                        .and_then(|_| repo.head().ok())
                        .and_then(|h| h.shorthand().map(String::from))
                        .unwrap_or_else(|| "branch".to_string()),
                    msg
                ));
            }
        }
    }

    Ok(stashes.join("\n") + if stashes.is_empty() { "" } else { "\n" })
}

fn execute_blame(repo: &git2::Repository, repo_path: &Path, file: &str) -> Result<String, String> {
    let blame = repo
        .blame_file(Path::new(file), None)
        .map_err(|e| format!("Failed to blame file: {}", e))?;

    let workdir = repo.workdir().unwrap_or(repo_path);
    let file_path = workdir.join(file);
    let content =
        std::fs::read_to_string(&file_path).map_err(|e| format!("Failed to read file: {}", e))?;
    let lines: Vec<&str> = content.lines().collect();

    let mut output = String::new();
    let mut line_num = 1;

    for hunk in blame.iter() {
        let oid = hunk.final_commit_id();
        let sig = hunk.final_signature();
        let short = &oid.to_string()[..8];
        let author = sig.name().unwrap_or("?");

        for _ in 0..hunk.lines_in_hunk() {
            let line_content = lines.get(line_num - 1).unwrap_or(&"");
            output.push_str(&format!(
                "{} ({:>12} {:>4}) {}\n",
                short, author, line_num, line_content
            ));
            line_num += 1;
        }
    }
    Ok(output)
}

fn execute_config_get(repo: &git2::Repository, key: &str) -> Result<String, String> {
    let config = repo
        .config()
        .map_err(|e| format!("Failed to get config: {}", e))?;
    let value = config.get_string(key).unwrap_or_default();
    Ok(format!("{}\n", value))
}

/// Execute a piped command: run git fast, pipe to shell command
fn execute_piped_command(
    repo_path: &PathBuf,
    git_cmd: &GitCommand,
    pipe_to: &str,
) -> Result<String, String> {
    let git_output = execute_git_command(repo_path, git_cmd)?;

    let mut child = Command::new("sh")
        .arg("-c")
        .arg(pipe_to)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|e| format!("Failed to spawn pipe command: {}", e))?;

    if let Some(mut stdin) = child.stdin.take() {
        stdin
            .write_all(git_output.as_bytes())
            .map_err(|e| format!("Failed to write to pipe: {}", e))?;
    }

    let output = child
        .wait_with_output()
        .map_err(|e| format!("Failed to wait for pipe command: {}", e))?;

    if output.status.success() {
        Ok(String::from_utf8_lossy(&output.stdout).to_string())
    } else {
        Err(format!(
            "Pipe command failed: {}",
            String::from_utf8_lossy(&output.stderr)
        ))
    }
}

/// Execute a redirected command: run git fast, write to file
fn execute_redirected_command(
    repo_path: &PathBuf,
    git_cmd: &GitCommand,
    file: &str,
    append: bool,
) -> Result<String, String> {
    let git_output = execute_git_command(repo_path, git_cmd)?;

    let mut file_handle = if append {
        std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open(file)
    } else {
        std::fs::File::create(file)
    }
    .map_err(|e| format!("Failed to open file '{}': {}", file, e))?;

    file_handle
        .write_all(git_output.as_bytes())
        .map_err(|e| format!("Failed to write to file: {}", e))?;

    Ok(format!("Output written to {}\n", file))
}

/// Run the forall command
pub fn run_forall(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    command: &str,
    parallel: bool,
    changed_only: bool,
    no_intercept: bool,
    group_filter: Option<&[String]>,
) -> anyhow::Result<()> {
    let repos: Vec<RepoInfo> = filter_repos(manifest, workspace_root, None, group_filter, true);

    // Parse the command (handles pipes, redirects, git interception)
    let parsed = if no_intercept {
        ParsedCommand::Shell(command.to_string())
    } else {
        parse_command(command)
    };

    if parallel {
        run_parallel(&repos, command, changed_only, &parsed)?;
    } else {
        run_sequential(&repos, command, changed_only, &parsed)?;
    }

    Ok(())
}

/// Execute a parsed command for a single repo
fn execute_parsed_command(
    repo_path: &PathBuf,
    command: &str,
    parsed: &ParsedCommand,
    repo: &RepoInfo,
) -> Result<String, String> {
    match parsed {
        ParsedCommand::Git(git_cmd) => execute_git_command(repo_path, git_cmd),
        ParsedCommand::Piped { git_cmd, pipe_to } => {
            execute_piped_command(repo_path, git_cmd, pipe_to)
        }
        ParsedCommand::Redirect {
            git_cmd,
            file,
            append,
        } => execute_redirected_command(repo_path, git_cmd, file, *append),
        ParsedCommand::Shell(_) => {
            // Run as shell command
            let output = Command::new("sh")
                .arg("-c")
                .arg(command)
                .current_dir(repo_path)
                .env("REPO_NAME", &repo.name)
                .env("REPO_PATH", repo_path)
                .env("REPO_URL", &repo.url)
                .env("REPO_BRANCH", &repo.default_branch)
                .output()
                .map_err(|e| e.to_string())?;

            if output.status.success() {
                let stdout = String::from_utf8_lossy(&output.stdout).to_string();
                let stderr = String::from_utf8_lossy(&output.stderr).to_string();
                Ok(format!("{}{}", stdout, stderr))
            } else {
                Err(format!(
                    "Exit code: {:?}\n{}{}",
                    output.status.code(),
                    String::from_utf8_lossy(&output.stdout),
                    String::from_utf8_lossy(&output.stderr)
                ))
            }
        }
    }
}

fn run_sequential(
    repos: &[RepoInfo],
    command: &str,
    changed_only: bool,
    parsed: &ParsedCommand,
) -> anyhow::Result<()> {
    let mut success_count = 0;
    let mut error_count = 0;
    let mut skip_count = 0;

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            Output::warning(&format!("{}: not cloned, skipping", repo.name));
            skip_count += 1;
            continue;
        }

        if changed_only && !has_changes(&repo.absolute_path)? {
            skip_count += 1;
            continue;
        }

        Output::header(&format!("{}:", repo.name));

        match execute_parsed_command(&repo.absolute_path, command, parsed, repo) {
            Ok(output) => {
                print!("{}", output);
                success_count += 1;
            }
            Err(e) => {
                Output::error(&e);
                error_count += 1;
            }
        }
        println!();
    }

    // Summary
    if error_count == 0 {
        Output::success(&format!(
            "Command completed in {} repo(s){}",
            success_count,
            if skip_count > 0 {
                format!(", {} skipped", skip_count)
            } else {
                String::new()
            }
        ));
    } else {
        Output::warning(&format!(
            "{} succeeded, {} failed, {} skipped",
            success_count, error_count, skip_count
        ));
    }

    Ok(())
}

/// Cloneable version of ParsedCommand for use in threads
#[derive(Debug, Clone)]
#[allow(dead_code)]
enum CloneableParsedCommand {
    Git(GitCommand),
    Piped {
        git_cmd: GitCommand,
        pipe_to: String,
    },
    Redirect {
        git_cmd: GitCommand,
        file: String,
        append: bool,
    },
    Shell(String), // String kept for structural consistency with ParsedCommand
}

impl From<&ParsedCommand> for CloneableParsedCommand {
    fn from(cmd: &ParsedCommand) -> Self {
        match cmd {
            ParsedCommand::Git(git_cmd) => CloneableParsedCommand::Git(git_cmd.clone()),
            ParsedCommand::Piped { git_cmd, pipe_to } => CloneableParsedCommand::Piped {
                git_cmd: git_cmd.clone(),
                pipe_to: pipe_to.clone(),
            },
            ParsedCommand::Redirect {
                git_cmd,
                file,
                append,
            } => CloneableParsedCommand::Redirect {
                git_cmd: git_cmd.clone(),
                file: file.clone(),
                append: *append,
            },
            ParsedCommand::Shell(s) => CloneableParsedCommand::Shell(s.clone()),
        }
    }
}

fn run_parallel(
    repos: &[RepoInfo],
    command: &str,
    changed_only: bool,
    parsed: &ParsedCommand,
) -> anyhow::Result<()> {
    use std::sync::{Arc, Mutex};
    use std::thread;

    let results = Arc::new(Mutex::new(Vec::new()));
    let mut handles = vec![];

    // Clone the parsed command for threads
    let cloneable_cmd = CloneableParsedCommand::from(parsed);

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        if changed_only && !has_changes(&repo.absolute_path).unwrap_or(false) {
            continue;
        }

        let repo_name = repo.name.clone();
        let repo_path = repo.absolute_path.clone();
        let repo_url = repo.url.clone();
        let repo_branch = repo.default_branch.clone();
        let cmd = command.to_string();
        let results = Arc::clone(&results);
        let parsed_cmd = cloneable_cmd.clone();

        let handle = thread::spawn(move || {
            let result = match &parsed_cmd {
                CloneableParsedCommand::Git(git_cmd) => execute_git_command(&repo_path, git_cmd),
                CloneableParsedCommand::Piped { git_cmd, pipe_to } => {
                    execute_piped_command(&repo_path, git_cmd, pipe_to)
                }
                CloneableParsedCommand::Redirect {
                    git_cmd,
                    file,
                    append,
                } => execute_redirected_command(&repo_path, git_cmd, file, *append),
                CloneableParsedCommand::Shell(_) => {
                    // Run as shell command
                    let output = Command::new("sh")
                        .arg("-c")
                        .arg(&cmd)
                        .current_dir(&repo_path)
                        .env("REPO_NAME", &repo_name)
                        .env("REPO_PATH", &repo_path)
                        .env("REPO_URL", &repo_url)
                        .env("REPO_BRANCH", &repo_branch)
                        .output();

                    match output {
                        Ok(out) => {
                            let stdout = String::from_utf8_lossy(&out.stdout).to_string();
                            let stderr = String::from_utf8_lossy(&out.stderr).to_string();
                            if out.status.success() {
                                Ok(format!("{}{}", stdout, stderr))
                            } else {
                                Err(format!(
                                    "Exit code: {:?}\n{}{}",
                                    out.status.code(),
                                    stdout,
                                    stderr
                                ))
                            }
                        }
                        Err(e) => Err(e.to_string()),
                    }
                }
            };

            let mut results = results.lock().expect("mutex poisoned");
            results.push((repo_name, result));
        });

        handles.push(handle);
    }

    // Wait for all threads
    for handle in handles {
        handle
            .join()
            .map_err(|_| anyhow::anyhow!("Worker thread panicked"))?;
    }

    // Print results
    let results = results.lock().expect("mutex poisoned");
    let mut success_count = 0;
    let mut error_count = 0;

    for (repo_name, output) in results.iter() {
        Output::header(&format!("{}:", repo_name));
        match output {
            Ok(output) => {
                print!("{}", output);
                success_count += 1;
            }
            Err(e) => {
                Output::error(&e.to_string());
                error_count += 1;
            }
        }
        println!();
    }

    if error_count == 0 {
        Output::success(&format!("Command completed in {} repo(s)", success_count));
    } else {
        Output::warning(&format!(
            "{} succeeded, {} failed",
            success_count, error_count
        ));
    }

    Ok(())
}

/// Check if a repository has uncommitted changes
fn has_changes(repo_path: &PathBuf) -> anyhow::Result<bool> {
    match crate::git::open_repo(repo_path) {
        Ok(repo) => {
            let statuses = repo.statuses(None)?;
            Ok(!statuses.is_empty())
        }
        Err(_) => Ok(false),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use git2::Repository;
    use tempfile::TempDir;

    fn setup_test_repo(temp: &TempDir) -> PathBuf {
        let repo_path = temp.path().join("repo");
        std::fs::create_dir_all(&repo_path).unwrap();
        let repo = Repository::init(&repo_path).unwrap();

        // Configure git
        {
            let mut config = repo.config().unwrap();
            config.set_str("user.name", "Test User").unwrap();
            config.set_str("user.email", "test@example.com").unwrap();
        }

        // Create initial commit
        {
            std::fs::write(repo_path.join("README.md"), "# Test").unwrap();
            let mut index = repo.index().unwrap();
            index.add_path(std::path::Path::new("README.md")).unwrap();
            index.write().unwrap();
            let sig = repo.signature().unwrap();
            let tree_id = index.write_tree().unwrap();
            let tree = repo.find_tree(tree_id).unwrap();
            repo.commit(Some("HEAD"), &sig, &sig, "Initial commit", &tree, &[])
                .unwrap();
        }

        repo_path
    }

    #[test]
    fn test_has_changes_clean_repo() {
        let temp = TempDir::new().unwrap();
        let repo_path = setup_test_repo(&temp);

        let result = has_changes(&repo_path);
        assert!(result.is_ok());
        assert!(!result.unwrap()); // Clean repo has no changes
    }

    #[test]
    fn test_has_changes_with_modifications() {
        let temp = TempDir::new().unwrap();
        let repo_path = setup_test_repo(&temp);

        // Modify a tracked file
        std::fs::write(repo_path.join("README.md"), "# Modified").unwrap();

        let result = has_changes(&repo_path);
        assert!(result.is_ok());
        assert!(result.unwrap()); // Has modifications
    }

    #[test]
    fn test_has_changes_with_untracked_file() {
        let temp = TempDir::new().unwrap();
        let repo_path = setup_test_repo(&temp);

        // Add untracked file
        std::fs::write(repo_path.join("new-file.txt"), "content").unwrap();

        let result = has_changes(&repo_path);
        assert!(result.is_ok());
        assert!(result.unwrap()); // Has untracked file
    }

    #[test]
    fn test_has_changes_nonexistent_repo() {
        let path = PathBuf::from("/nonexistent/path");
        let result = has_changes(&path);
        assert!(result.is_ok());
        assert!(!result.unwrap()); // Returns false for non-repo
    }

