    fn test_try_parse_git_command_branch() {
        assert!(matches!(
            try_parse_git_command("git branch"),
            Some(GitCommand::ListBranches {
                all: false,
                remotes: false
            })
        ));
        assert!(matches!(
            try_parse_git_command("git branch -a"),
            Some(GitCommand::ListBranches {
                all: true,
                remotes: false
            })
        ));
        assert!(matches!(
            try_parse_git_command("git branch -r"),
            Some(GitCommand::ListBranches {
