//! PR status command implementation

use crate::cli::output::{Output, Table};
use crate::core::manifest::Manifest;
use crate::core::repo::RepoInfo;
use crate::git::{get_current_branch, open_repo, path_exists};
use crate::platform::get_platform_adapter;
use std::path::PathBuf;

/// Run the PR status command
pub async fn run_pr_status(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    json_output: bool,
) -> anyhow::Result<()> {
    if !json_output {
        Output::header("Pull Request Status");
        println!();
    }

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .filter(|r| !r.reference) // Skip reference repos
        .collect();

    #[derive(serde::Serialize)]
    struct PRStatusInfo {
        repo: String,
        branch: String,
        pr_number: Option<u64>,
        state: String,
        approved: bool,
        checks_pass: bool,
        mergeable: bool,
        url: Option<String>,
    }

    let mut statuses: Vec<PRStatusInfo> = Vec::new();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        let git_repo = match open_repo(&repo.absolute_path) {
            Ok(r) => r,
            Err(_) => continue,
        };

        let branch = match get_current_branch(&git_repo) {
            Ok(b) => b,
            Err(_) => continue,
        };

        // Skip if on default branch
        if branch == repo.default_branch {
            continue;
        }

        let platform = get_platform_adapter(repo.platform_type, repo.platform_base_url.as_deref());

        match platform
            .find_pr_by_branch(&repo.owner, &repo.repo, &branch)
            .await
        {
            Ok(Some(pr)) => {
                // Get PR details including approval and mergeable status
                let (approved, mergeable) = match platform
                    .get_pull_request(&repo.owner, &repo.repo, pr.number)
                    .await
                {
                    Ok(full_pr) => {
                        let is_approved = platform
                            .is_pull_request_approved(&repo.owner, &repo.repo, pr.number)
                            .await
                            .unwrap_or(false);
                        (is_approved, full_pr.mergeable.unwrap_or(false))
                    }
                    Err(_) => (false, false),
                };

                // Get status checks
                let checks_pass = match platform
                    .get_status_checks(&repo.owner, &repo.repo, &branch)
                    .await
                {
                    Ok(status) => status.state == crate::platform::CheckState::Success,
                    Err(_) => false,
                };

                statuses.push(PRStatusInfo {
                    repo: repo.name.clone(),
                    branch: branch.clone(),
                    pr_number: Some(pr.number),
                    state: "open".to_string(),
                    approved,
                    checks_pass,
                    mergeable,
                    url: Some(pr.url.clone()),
                });
            }
            Ok(None) => {
                statuses.push(PRStatusInfo {
                    repo: repo.name.clone(),
                    branch: branch.clone(),
                    pr_number: None,
                    state: "none".to_string(),
                    approved: false,
                    checks_pass: false,
                    mergeable: false,
                    url: None,
                });
            }
            Err(e) => {
                if !json_output {
                    Output::error(&format!("{}: {}", repo.name, e));
                }
            }
        }
    }

    if json_output {
        println!("{}", serde_json::to_string_pretty(&statuses)?);
        return Ok(());
    }

    if statuses.is_empty() {
        println!("No repositories have changes on feature branches.");
        return Ok(());
    }

    // Display table
    let mut table = Table::new(vec![
        "Repo",
        "PR#",
        "State",
        "Approved",
        "Checks",
        "Mergeable",
    ]);

    for status in &statuses {
        let pr_num = status
            .pr_number
            .map(|n| format!("#{}", n))
            .unwrap_or_else(|| "-".to_string());
        let approved = if status.approved { "✓" } else { "✗" };
        let checks = if status.checks_pass { "✓" } else { "✗" };
        let mergeable = if status.mergeable { "✓" } else { "✗" };

        table.add_row(vec![
            &status.repo,
            &pr_num,
            &status.state,
            approved,
            checks,
            mergeable,
        ]);
    }

    table.print();

    // Summary
    println!();
    let with_prs = statuses.iter().filter(|s| s.pr_number.is_some()).count();
    let ready = statuses
        .iter()
        .filter(|s| s.pr_number.is_some() && s.approved && s.checks_pass && s.mergeable)
        .count();

    if ready == with_prs && with_prs > 0 {
        Output::success(&format!("All {} PRs ready to merge!", with_prs));
    } else if with_prs > 0 {
        println!("{}/{} PRs ready to merge", ready, with_prs);
    }

    Ok(())
}

//! Prune command implementation
//!
//! Deletes local branches that have been merged into the default branch.
//! Optionally prunes remote tracking refs.

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, RepoInfo};
use crate::git::branch::{delete_local_branch, is_branch_merged, list_local_branches};
use crate::git::{get_current_branch, open_repo, path_exists};
use crate::util::log_cmd;
use std::path::PathBuf;
use std::process::Command;

/// Run the prune command
pub fn run_prune(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    execute: bool,
    remote: bool,
    group_filter: Option<&[String]>,
) -> anyhow::Result<()> {
    if execute {
        Output::header("Pruning merged branches...");
    } else {
        Output::header("Pruning merged branches (dry run)...");
    }
    println!();

    let repos: Vec<RepoInfo> = filter_repos(manifest, workspace_root, None, group_filter, false);

    let mut total_pruned = 0;
    let mut total_repos = 0;

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        let git_repo = match open_repo(&repo.absolute_path) {
            Ok(r) => r,
            Err(e) => {
                Output::error(&format!("{}: {}", repo.name, e));
                continue;
            }
        };

        let current_branch = match get_current_branch(&git_repo) {
            Ok(b) => b,
            Err(e) => {
                Output::error(&format!("{}: {}", repo.name, e));
                continue;
            }
        };

        let branches = match list_local_branches(&git_repo) {
            Ok(b) => b,
            Err(e) => {
                Output::error(&format!("{}: {}", repo.name, e));
                continue;
            }
        };

        let mut merged_branches: Vec<String> = Vec::new();

        for branch in &branches {
            // Skip current branch and default branch
            if branch == &current_branch || branch == &repo.default_branch {
                continue;
            }

            match is_branch_merged(&git_repo, branch, &repo.default_branch) {
                Ok(true) => merged_branches.push(branch.clone()),
                Ok(false) => {}
                Err(e) => {
                    Output::warning(&format!(
                        "{}: could not check branch '{}': {}",
                        repo.name, branch, e
                    ));
                }
            }
        }

        if merged_branches.is_empty() {
            continue;
        }

        total_repos += 1;
        Output::subheader(&format!("{}:", repo.name));

        for branch in &merged_branches {
            if execute {
                match delete_local_branch(&git_repo, branch, false) {
                    Ok(()) => {
                        Output::success(&format!("  Deleted: {}", branch));
                        total_pruned += 1;
                    }
                    Err(e) => {
                        Output::error(&format!("  Failed to delete '{}': {}", branch, e));
                    }
                }
            } else {
                println!("  Would delete: {}", branch);
                total_pruned += 1;
            }
        }

        // Prune remote tracking refs if requested
        if remote {
            let mut cmd = Command::new("git");
            cmd.args(["fetch", "--prune"])
                .current_dir(&repo.absolute_path);
            log_cmd(&cmd);
            let output = cmd.output();

            match output {
                Ok(o) if o.status.success() => {
                    let stderr = String::from_utf8_lossy(&o.stderr);
                    if stderr.contains("pruning") || stderr.contains("[deleted]") {
                        Output::info("  Pruned remote tracking refs");
                    }
                }
                Ok(o) => {
                    let stderr = String::from_utf8_lossy(&o.stderr);
                    Output::warning(&format!("  Failed to prune remote refs: {}", stderr.trim()));
                }
                Err(e) => {
                    Output::warning(&format!("  Failed to prune remote refs: {}", e));
                }
            }
        }
    }

    println!();
    if total_pruned == 0 {
        Output::success("No merged branches to prune.");
    } else if execute {
        Output::success(&format!(
            "Pruned {} branch(es) across {} repo(s).",
            total_pruned, total_repos
        ));
    } else {
        Output::info(&format!(
            "Found {} merged branch(es) across {} repo(s).",
            total_pruned, total_repos
        ));
        Output::warning("Run with --execute to actually delete them.");
    }

    Ok(())
}

//! Pull command implementation
//!
//! Pulls latest changes across repositories (merge or rebase).

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, get_manifest_repo_info, RepoInfo};
use crate::git::remote::{safe_pull_latest_with_mode, PullMode};
use crate::git::{open_repo, path_exists};
use std::path::PathBuf;
use std::sync::{Arc, Mutex};
use tokio::task::JoinSet;

/// Result of pulling a single repo
#[derive(Debug, Clone)]
struct PullResult {
    name: String,
    success: bool,
    message: String,
}

/// Run the pull command
pub async fn run_pull(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    rebase: bool,
    group_filter: Option<&[String]>,
    sequential: bool,
    quiet: bool,
) -> anyhow::Result<()> {
    let mut repos: Vec<RepoInfo> = filter_repos(manifest, workspace_root, None, group_filter, true);

    // Include manifest repo at the beginning (pull it first)
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.insert(0, manifest_repo);
    }

    let mode = if rebase {
        PullMode::Rebase
    } else {
        PullMode::Merge
    };
    let mode_label = if rebase { "rebase" } else { "merge" };

    Output::header(&format!(
        "Pulling {} repositories ({})...",
        repos.len(),
        mode_label
    ));
    println!();

    let results = if sequential {
        pull_sequential(&repos, mode, quiet)?
    } else {
        pull_parallel(&repos, mode, quiet).await?
    };

    // Display results
    let mut success_count = 0;
    let mut error_count = 0;
    let mut failed_repos: Vec<(String, String)> = Vec::new();

    for result in results {
        if result.success {
            success_count += 1;
        } else {
            error_count += 1;
            failed_repos.push((result.name.clone(), result.message.clone()));
        }
    }

    println!();
    if error_count == 0 {
        Output::success(&format!(
            "All {} repositories pulled successfully.",
            success_count
        ));
    } else {
        Output::warning(&format!("{} pulled, {} failed", success_count, error_count));

        if !failed_repos.is_empty() {
            println!();
            for (repo_name, error_msg) in &failed_repos {
                println!("  ✗ {}: {}", repo_name, error_msg);
            }
        }
    }

    Ok(())
}

/// Pull repos sequentially
fn pull_sequential(
    repos: &[RepoInfo],
    mode: PullMode,
    quiet: bool,
) -> anyhow::Result<Vec<PullResult>> {
    let mut results = Vec::new();

    for repo in repos {
        let result = pull_single_repo(repo, mode, quiet, true)?;
        results.push(result);
    }

    Ok(results)
}

/// Pull repos in parallel using tokio
#[allow(clippy::unnecessary_to_owned)]
async fn pull_parallel(
    repos: &[RepoInfo],
    mode: PullMode,
    quiet: bool,
) -> anyhow::Result<Vec<PullResult>> {
    let results: Arc<Mutex<Vec<PullResult>>> = Arc::new(Mutex::new(Vec::new()));
    let mut join_set: JoinSet<anyhow::Result<()>> = JoinSet::new();

    let spinner = Output::spinner(&format!("Pulling {} repos in parallel...", repos.len()));

    for repo in repos.to_vec() {
        let results = Arc::clone(&results);

        join_set.spawn_blocking(move || {
            let result = pull_single_repo(&repo, mode, quiet, false)?;
            results.lock().expect("mutex poisoned").push(result);
            Ok(())
        });
    }

    while let Some(res) = join_set.join_next().await {
        res??;
    }

    spinner.finish_and_clear();

    let results = match Arc::try_unwrap(results) {
        Ok(mutex) => mutex.into_inner().expect("mutex poisoned"),
        Err(arc) => arc.lock().expect("mutex poisoned").clone(),
    };

    for result in &results {
        if result.success {
            if !quiet {
                Output::success(&format!("{}: {}", result.name, result.message));
            }
        } else {
            Output::error(&format!("{}: {}", result.name, result.message));
        }
    }

    Ok(results)
}

/// Pull a single repository
fn pull_single_repo(
    repo: &RepoInfo,
    mode: PullMode,
    quiet: bool,
    show_spinner: bool,
) -> anyhow::Result<PullResult> {
    let spinner = if show_spinner {
        Some(Output::spinner(&format!("Pulling {}...", repo.name)))
    } else {
        None
    };

    if !path_exists(&repo.absolute_path) {
        let message = "missing".to_string();
        if let Some(s) = spinner {
            s.finish_with_message(format!("{}: {}", repo.name, message));
        }
        return Ok(PullResult {
            name: repo.name.clone(),
            success: false,
            message,
        });
    }

    match open_repo(&repo.absolute_path) {
        Ok(git_repo) => {
            let result =
                safe_pull_latest_with_mode(&git_repo, &repo.default_branch, "origin", mode);

            match result {
                Ok(pull_result) => {
                    let (success, message) = if pull_result.pulled {
                        if pull_result.recovered {
                            (
                                true,
                                pull_result
                                    .message
                                    .unwrap_or_else(|| "pulled (recovered)".to_string()),
                            )
                        } else {
                            (
                                true,
                                pull_result.message.unwrap_or_else(|| "pulled".to_string()),
                            )
                        }
                    } else if let Some(msg) = pull_result.message {
                        (true, msg)
                    } else {
                        (true, "up to date".to_string())
                    };

                    if let Some(s) = spinner {
                        if !quiet || !success {
                            s.finish_with_message(format!("{}: {}", repo.name, message));
                        } else {
                            s.finish_and_clear();
                        }
                    }

                    Ok(PullResult {
                        name: repo.name.clone(),
                        success,
                        message,
                    })
                }
                Err(e) => {
                    let message = format!("error - {}", e);
                    if let Some(s) = spinner {
                        s.finish_with_message(format!("{}: {}", repo.name, message));
                    }
                    Ok(PullResult {
                        name: repo.name.clone(),
                        success: false,
                        message,
                    })
                }
            }
        }
        Err(e) => {
            let message = format!("error - {}", e);
            if let Some(s) = spinner {
                s.finish_with_message(format!("{}: {}", repo.name, message));
            }
            Ok(PullResult {
                name: repo.name.clone(),
                success: false,
                message,
            })
        }
    }
}

//! Push command implementation

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{get_manifest_repo_info, RepoInfo};
use crate::git::remote::{force_push_branch, push_branch};
use crate::git::{get_current_branch, open_repo, path_exists};
use git2::Repository;
use std::path::PathBuf;

/// JSON-serializable push error for --json output
#[derive(serde::Serialize)]
struct JsonPushError {
    repo: String,
    reason: String,
}

/// Run the push command
pub fn run_push(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    set_upstream: bool,
    force: bool,
    quiet: bool,
    json: bool,
) -> anyhow::Result<()> {
    if !json {
        if force {
            Output::header("Force pushing changes...");
        } else {
            Output::header("Pushing changes...");
        }
        println!();
    }

    let mut repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .filter(|r| !r.reference) // Skip reference repos
        .collect();

    // Include manifest repo in push operations
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.push(manifest_repo);
    }

    let mut success_count = 0;
    let mut skip_count = 0;
    let mut error_count = 0;
    let mut failed_repos: Vec<(String, String)> = Vec::new(); // (repo_name, error_message)
    let mut json_pushed: Vec<String> = Vec::new();
    let mut json_skipped: Vec<String> = Vec::new();
    let mut json_failed: Vec<JsonPushError> = Vec::new();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            skip_count += 1;
            continue;
        }

        match open_repo(&repo.absolute_path) {
            Ok(git_repo) => {
                let branch = match get_current_branch(&git_repo) {
                    Ok(b) => b,
                    Err(e) => {
                        if !json {
                            Output::error(&format!("{}: {}", repo.name, e));
                        }
                        error_count += 1;
                        json_failed.push(JsonPushError {
                            repo: repo.name.clone(),
                            reason: e.to_string(),
                        });
                        continue;
                    }
                };

                // Check if there's anything to push
                if !has_commits_to_push(&git_repo, &branch)? {
                    if !quiet && !json {
                        Output::info(&format!("{}: nothing to push", repo.name));
                    }
                    skip_count += 1;
                    json_skipped.push(repo.name.clone());
                    continue;
                }

                let action = if force { "Force pushing" } else { "Pushing" };
                let spinner = if !json {
                    Some(Output::spinner(&format!("{} {}...", action, repo.name)))
                } else {
                    None
                };

                let result = if force {
                    force_push_branch(&git_repo, &branch, "origin")
                } else {
                    push_branch(&git_repo, &branch, "origin", set_upstream)
                };

                match result {
                    Ok(()) => {
                        if let Some(s) = spinner {
                            let msg = if force {
                                format!("{}: force pushed", repo.name)
                            } else if set_upstream {
                                format!("{}: pushed and set upstream", repo.name)
                            } else {
                                format!("{}: pushed", repo.name)
                            };
                            s.finish_with_message(msg);
                        }
                        success_count += 1;
                        json_pushed.push(repo.name.clone());
                    }
                    Err(e) => {
                        // Check if this is a "nothing to push" situation
                        let error_msg = e.to_string().to_lowercase();
                        if error_msg.contains("everything up-to-date")
                            || error_msg.contains("nothing to commit")
                            || error_msg.contains("nothing to push")
                            || error_msg.contains("no changes")
                            || error_msg.contains("already up to date")
                        {
                            if let Some(s) = spinner {
                                if !quiet {
                                    s.finish_with_message(format!(
                                        "{}: skipped (nothing to push)",
                                        repo.name
                                    ));
                                } else {
                                    s.finish_and_clear();
                                }
                            }
                            skip_count += 1;
                            json_skipped.push(repo.name.clone());
                        } else {
                            if let Some(s) = spinner {
                                s.finish_with_message(format!("{}: failed - {}", repo.name, e));
                            }
                            error_count += 1;
                            failed_repos.push((repo.name.clone(), format!("Error: {}", e)));
                            json_failed.push(JsonPushError {
                                repo: repo.name.clone(),
                                reason: e.to_string(),
                            });
                        }
                    }
                }
            }
            Err(e) => {
                if !json {
                    Output::error(&format!("{}: {}", repo.name, e));
                }
                error_count += 1;
                failed_repos.push((repo.name.clone(), format!("Error: {}", e)));
                json_failed.push(JsonPushError {
                    repo: repo.name.clone(),
                    reason: e.to_string(),
                });
            }
        }
    }

    if json {
        #[derive(serde::Serialize)]
        struct JsonPushResult {
            success: bool,
            pushed: Vec<String>,
            skipped: Vec<String>,
            failed: Vec<JsonPushError>,
        }

        let result = JsonPushResult {
            success: error_count == 0,
            pushed: json_pushed,
            skipped: json_skipped,
            failed: json_failed,
        };
        println!("{}", serde_json::to_string_pretty(&result)?);
    } else {
        println!();
        let action = if force { "Force pushed" } else { "Pushed" };
        if error_count == 0 {
            if success_count > 0 {
                Output::success(&format!(
                    "{} {} repo(s){}.",
                    action,
                    success_count,
                    if skip_count > 0 {
                        format!(", {} had nothing to push", skip_count)
                    } else {
                        String::new()
                    }
                ));
            } else {
                println!("Nothing to push.");
            }
        } else {
            Output::warning(&format!(
                "{} {}, {} failed, {} skipped",
                success_count,
                action.to_lowercase(),
                error_count,
                skip_count
            ));

            // Show which repos failed and why
            if !failed_repos.is_empty() {
                println!();
                for (repo_name, error_msg) in &failed_repos {
                    println!("  ✗ {}: {}", repo_name, error_msg);
                }
            }
        }
    }

    Ok(())
}

/// Check if branch has commits that aren't on the remote
fn has_commits_to_push(repo: &Repository, branch: &str) -> anyhow::Result<bool> {
    // Try to find the remote tracking branch
    let remote_ref = format!("refs/remotes/origin/{}", branch);

    let local_ref = match repo.find_reference(&format!("refs/heads/{}", branch)) {
        Ok(r) => r,
        Err(_) => return Ok(false),
    };

    let remote_branch = match repo.find_reference(&remote_ref) {
        Ok(r) => r,
        Err(_) => {
            // No remote tracking branch - we have commits to push if local has any
            return Ok(local_ref.peel_to_commit().is_ok());
        }
    };

    let local_oid = local_ref.target().ok_or_else(|| {
        anyhow::anyhow!(
            "Could not resolve local branch '{}'. Ensure it exists and has at least one commit.",
            branch
        )
    })?;
    let remote_oid = remote_branch.target().ok_or_else(|| {
        anyhow::anyhow!(
            "Could not resolve remote tracking branch 'origin/{}'. Try running `gr sync` first.",
            branch
        )
    })?;

    // If they're the same, nothing to push
    if local_oid == remote_oid {
        return Ok(false);
    }

    // Check if local is ahead of remote
    let (ahead, _behind) = repo.graph_ahead_behind(local_oid, remote_oid)?;
    Ok(ahead > 0)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use tempfile::TempDir;

    fn setup_test_repo() -> (TempDir, Repository) {
        let temp_dir = TempDir::new().unwrap();
        let repo = Repository::init(temp_dir.path()).unwrap();

        // Configure user for commits
        let mut config = repo.config().unwrap();
        config.set_str("user.name", "Test User").unwrap();
        config.set_str("user.email", "test@example.com").unwrap();

        // Create initial commit
        let file_path = temp_dir.path().join("test.txt");
        fs::write(&file_path, "content").unwrap();

        {
            let mut index = repo.index().unwrap();
            index.add_path(std::path::Path::new("test.txt")).unwrap();
            index.write().unwrap();

            let tree_id = index.write_tree().unwrap();
            let tree = repo.find_tree(tree_id).unwrap();
            let sig = repo.signature().unwrap();

            repo.commit(Some("HEAD"), &sig, &sig, "Initial commit", &tree, &[])
                .unwrap();
        }

        (temp_dir, repo)
    }

    #[test]
    fn test_has_commits_to_push_no_remote() {
        let (_temp_dir, repo) = setup_test_repo();

        // Has commits but no remote - should return true
        let result = has_commits_to_push(&repo, "master").unwrap();
        assert!(result);
    }
}

//! Rebase command implementation
//!
//! Rebases branches across repositories.

use crate::cli::output::Output;
use crate::core::griptree::GriptreeConfig;
use crate::core::manifest::Manifest;
use crate::core::repo::RepoInfo;
use crate::git::{get_current_branch, open_repo, path_exists};
use crate::util::log_cmd;
use std::path::PathBuf;
use std::process::Command;

/// Run the rebase command
pub fn run_rebase(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    onto: Option<&str>,
    upstream: bool,
    abort: bool,
    _continue: bool,
) -> anyhow::Result<()> {
    if abort {
        return run_rebase_abort(workspace_root, manifest);
    }

    if _continue {
        return run_rebase_continue(workspace_root, manifest);
    }

    let use_upstream = upstream || onto.is_none();
    if upstream && onto.is_some() {
        Output::warning("Ignoring explicit target because --upstream was set");
    }
    if use_upstream {
        Output::header("Rebasing onto upstream branches");
    } else if let Some(target) = onto {
        Output::header(&format!("Rebasing onto {}", target));
    }
    println!();

    let griptree_config = GriptreeConfig::load_from_workspace(workspace_root)?;

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    let mut success_count = 0;
    let mut skip_count = 0;
    let mut error_count = 0;

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            skip_count += 1;
            continue;
        }

        let git_repo = match open_repo(&repo.absolute_path) {
            Ok(r) => r,
            Err(_) => {
                skip_count += 1;
                continue;
            }
        };

        let branch = match get_current_branch(&git_repo) {
            Ok(b) => b,
            Err(_) => {
                skip_count += 1;
                continue;
            }
        };

        // Skip if on default branch
        if branch == repo.default_branch {
            skip_count += 1;
            continue;
        }

        let spinner = Output::spinner(&format!("Rebasing {}...", repo.name));
        let target = if use_upstream {
            match griptree_config.as_ref() {
                Some(cfg) => match cfg.upstream_for_repo(&repo.name, &repo.default_branch) {
                    Ok(upstream) => upstream,
                    Err(e) => {
                        spinner.finish_with_message(format!("{}: error - {}", repo.name, e));
                        error_count += 1;
                        continue;
                    }
                },
                None => format!("origin/{}", repo.default_branch),
            }
        } else {
            onto.unwrap_or("origin/main").to_string()
        };

        // Use git command for rebase (git2 doesn't support interactive rebase well)
        let mut cmd = Command::new("git");
        cmd.args(["rebase", &target])
            .current_dir(&repo.absolute_path);
        log_cmd(&cmd);
        let output = cmd.output()?;

        if output.status.success() {
            spinner.finish_with_message(format!("{}: rebased", repo.name));
            success_count += 1;
        } else {
            let stderr = String::from_utf8_lossy(&output.stderr);
            if stderr.contains("CONFLICT") {
                spinner.finish_with_message(format!(
                    "{}: conflicts - resolve and run 'gr rebase --continue'",
                    repo.name
                ));
            } else {
                spinner.finish_with_message(format!("{}: failed", repo.name));
            }
            error_count += 1;
        }
    }

    println!();
    if error_count == 0 {
        Output::success(&format!(
            "Rebased {} repo(s){}",
            success_count,
            if skip_count > 0 {
                format!(", {} skipped", skip_count)
            } else {
                String::new()
            }
        ));
    } else {
        Output::warning(&format!(
            "{} rebased, {} failed, {} skipped",
            success_count, error_count, skip_count
        ));
        println!();
        println!("To continue after resolving conflicts: gr rebase --continue");
        println!("To abort the rebase: gr rebase --abort");
    }

    Ok(())
}

fn run_rebase_abort(workspace_root: &PathBuf, manifest: &Manifest) -> anyhow::Result<()> {
    Output::header("Aborting rebase");
    println!();

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        // Check if rebase is in progress
        let rebase_dir = repo.absolute_path.join(".git/rebase-merge");
        let rebase_apply_dir = repo.absolute_path.join(".git/rebase-apply");

        if rebase_dir.exists() || rebase_apply_dir.exists() {
            let mut cmd = Command::new("git");
            cmd.args(["rebase", "--abort"])
                .current_dir(&repo.absolute_path);
            log_cmd(&cmd);
            let output = cmd.output()?;

            if output.status.success() {
                Output::success(&format!("{}: rebase aborted", repo.name));
            } else {
                Output::error(&format!("{}: failed to abort", repo.name));
            }
        }
    }

    Ok(())
}

fn run_rebase_continue(workspace_root: &PathBuf, manifest: &Manifest) -> anyhow::Result<()> {
    Output::header("Continuing rebase");
    println!();

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        // Check if rebase is in progress
        let rebase_dir = repo.absolute_path.join(".git/rebase-merge");
        let rebase_apply_dir = repo.absolute_path.join(".git/rebase-apply");

        if rebase_dir.exists() || rebase_apply_dir.exists() {
            let mut cmd = Command::new("git");
            cmd.args(["rebase", "--continue"])
                .current_dir(&repo.absolute_path);
            log_cmd(&cmd);
            let output = cmd.output()?;

            if output.status.success() {
                Output::success(&format!("{}: rebase continued", repo.name));
            } else {
                let stderr = String::from_utf8_lossy(&output.stderr);
                if stderr.contains("CONFLICT") {
                    Output::warning(&format!("{}: still has conflicts", repo.name));
                } else {
                    Output::error(&format!("{}: failed to continue", repo.name));
                }
            }
        }
    }

    Ok(())
}

//! Release command implementation
//!
//! Automates the full release workflow: version bump, changelog, build,
//! branch, commit, push, PR, CI wait, merge, and GitHub release creation.

use std::path::PathBuf;
use std::process::Command;

use chrono::Local;
use serde::Serialize;

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, RepoInfo};
use crate::platform::{get_platform_adapter, ReleaseResult};

/// Options for the release command
pub struct ReleaseOptions<'a> {
    pub workspace_root: &'a PathBuf,
    pub manifest: &'a Manifest,
    pub version: &'a str,
    pub notes: Option<&'a str>,
    pub dry_run: bool,
    pub skip_pr: bool,
    pub target_repo: Option<&'a str>,
    pub json: bool,
    pub quiet: bool,
    pub timeout: u64,
}

/// JSON output for release steps
#[derive(Serialize)]
struct ReleaseOutputJson {
    version: String,
    steps: Vec<StepResultJson>,
}

#[derive(Serialize)]
struct StepResultJson {
    name: String,
    status: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    files: Option<Vec<String>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    url: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    number: Option<u64>,
}

impl StepResultJson {
    fn ok(name: &str) -> Self {
        Self {
            name: name.to_string(),
            status: "ok".to_string(),
            files: None,
            url: None,
            number: None,
        }
    }

    fn skipped(name: &str) -> Self {
        Self {
            name: name.to_string(),
            status: "skipped".to_string(),
            files: None,
            url: None,
            number: None,
        }
    }
}

/// Normalize version string — strip leading 'v' for internal use, ensure tag has 'v' prefix
pub fn normalize_version(version: &str) -> anyhow::Result<(String, String)> {
    let bare = version.strip_prefix('v').unwrap_or(version);

    // Basic semver validation: must have at least X.Y.Z
    let parts: Vec<&str> = bare.split('.').collect();
    if parts.len() < 2 {
        anyhow::bail!(
            "Invalid version '{}'. Expected format: X.Y.Z (e.g. 0.12.4)",
            version
        );
    }
    for part in &parts[..2] {
        if part.parse::<u64>().is_err() {
            anyhow::bail!(
                "Invalid version '{}'. Version components must be numeric.",
                version
            );
        }
    }

    let tag = format!("v{}", bare);
    Ok((bare.to_string(), tag))
}

/// Auto-detect version files in repo directories
pub fn detect_version_files(
    workspace_root: &PathBuf,
    repos: &[RepoInfo],
) -> Vec<(String, PathBuf)> {
    let mut files = Vec::new();

    for repo in repos {
        if repo.reference {
            continue;
        }

        let cargo_toml = repo.absolute_path.join("Cargo.toml");
        if cargo_toml.exists() {
            files.push((repo.name.clone(), cargo_toml));
        }

        let package_json = repo.absolute_path.join("package.json");
        if package_json.exists() {
            files.push((repo.name.clone(), package_json));
        }
    }

    // Also check workspace root
    let root_cargo = workspace_root.join("Cargo.toml");
    if root_cargo.exists() && !files.iter().any(|(_, p)| p == &root_cargo) {
        files.push(("workspace".to_string(), root_cargo));
    }

    let root_package = workspace_root.join("package.json");
    if root_package.exists() && !files.iter().any(|(_, p)| p == &root_package) {
        files.push(("workspace".to_string(), root_package));
    }

    files
}

/// Bump version in a Cargo.toml file
pub fn bump_cargo_toml(path: &PathBuf, new_version: &str, dry_run: bool) -> anyhow::Result<bool> {
    let content = std::fs::read_to_string(path)?;

    // Match the first `version = "..."` in the [package] section
    let re = regex::Regex::new(r#"(?m)^(version\s*=\s*")([^"]+)(")"#)?;
    if !re.is_match(&content) {
        return Ok(false);
    }

    let old_version = re
        .captures(&content)
        .and_then(|c| c.get(2))
        .map(|m| m.as_str().to_string())
        .unwrap_or_default();

    if old_version == new_version {
        return Ok(false); // Already at this version
    }

    let new_content = re
        .replace(&content, format!("${{1}}{}${{3}}", new_version))
        .to_string();

    if !dry_run {
        std::fs::write(path, &new_content)?;
    }

    Ok(true)
}

/// Bump version in a package.json file
pub fn bump_package_json(path: &PathBuf, new_version: &str, dry_run: bool) -> anyhow::Result<bool> {
    let content = std::fs::read_to_string(path)?;

    // Match "version": "..."
    let re = regex::Regex::new(r#"("version"\s*:\s*")([^"]+)(")"#)?;
    if !re.is_match(&content) {
        return Ok(false);
    }

    let old_version = re
        .captures(&content)
        .and_then(|c| c.get(2))
        .map(|m| m.as_str().to_string())
        .unwrap_or_default();

    if old_version == new_version {
        return Ok(false);
    }

    let new_content = re
        .replace(&content, format!("${{1}}{}${{3}}", new_version))
        .to_string();

    if !dry_run {
        std::fs::write(path, &new_content)?;
    }

    Ok(true)
}

/// Bump version in a file using a custom pattern from manifest config
pub fn bump_custom_file(
    path: &PathBuf,
    pattern: &str,
    new_version: &str,
    dry_run: bool,
) -> anyhow::Result<bool> {
    let content = std::fs::read_to_string(path)?;

    // The pattern uses {version} as a placeholder — escape regex-special chars
    // and replace {version} with a capture group
    let escaped = regex::escape(pattern);
    let regex_pattern = escaped.replace(r"\{version\}", r#"([^\s"']+)"#);
    let re = regex::Regex::new(&regex_pattern)?;

    if !re.is_match(&content) {
        return Ok(false);
    }

    let replacement = pattern.replace("{version}", new_version);
    let new_content = re.replace(&content, replacement.as_str()).to_string();

    if new_content == content {
        return Ok(false);
    }

    if !dry_run {
        std::fs::write(path, &new_content)?;
    }

    Ok(true)
}

/// Update CHANGELOG.md with a new version section
pub fn update_changelog(
    path: &PathBuf,
    version_tag: &str,
    notes: Option<&str>,
    dry_run: bool,
) -> anyhow::Result<bool> {
    if !path.exists() {
        return Ok(false);
    }

    let content = std::fs::read_to_string(path)?;
    let date = Local::now().format("%Y-%m-%d").to_string();

    let new_section = if let Some(notes) = notes {
        format!("## [{}] - {}\n\n{}\n\n", version_tag, date, notes)
    } else {
        format!("## [{}] - {}\n\n", version_tag, date)
    };

    // Insert after the first heading line (# Changelog or similar)
    let new_content = if let Some(pos) = content.find('\n') {
        // Check if there's a blank line after the heading
        let insert_pos = if content[pos + 1..].starts_with('\n') {
            pos + 2
        } else {
            pos + 1
        };
        format!(
            "{}\n{}{}",
            &content[..pos],
            new_section,
            &content[insert_pos..]
        )
    } else {
        format!("{}\n\n{}", content, new_section)
    };

    if !dry_run {
        std::fs::write(path, &new_content)?;
    }

    Ok(true)
}

/// Find the target repo for GitHub release creation
fn find_release_target<'a>(
    repos: &'a [RepoInfo],
    target_name: Option<&str>,
) -> anyhow::Result<&'a RepoInfo> {
    if let Some(name) = target_name {
        repos
            .iter()
            .find(|r| r.name == name)
            .ok_or_else(|| anyhow::anyhow!("Repository '{}' not found in manifest", name))
    } else {
        // Auto-detect: first non-reference repo
        repos
            .iter()
            .find(|r| !r.reference)
            .ok_or_else(|| anyhow::anyhow!("No non-reference repos found for release target"))
    }
}

/// Run the release command
pub async fn run_release(opts: ReleaseOptions<'_>) -> anyhow::Result<()> {
    let (bare_version, version_tag) = normalize_version(opts.version)?;
    let repos = filter_repos(opts.manifest, opts.workspace_root, None, None, false);

    let mut steps: Vec<StepResultJson> = Vec::new();

    if !opts.json {
        if opts.dry_run {
            Output::header(&format!("Release {} (dry run)", version_tag));
        } else {
            Output::header(&format!("Releasing {}", version_tag));
        }
        println!();
    }

    // ── Step 1: Bump version files ──────────────────────────────
    if !opts.json && !opts.quiet {
        Output::info(&format!("Step 1: Bumping version to {}", bare_version));
    }

    let release_config = opts
        .manifest
        .workspace
        .as_ref()
        .and_then(|w| w.release.as_ref());

    let mut bumped_files: Vec<String> = Vec::new();

    if let Some(config) = release_config.and_then(|r| r.version_files.as_ref()) {
        // Use manifest-configured version files
        for vf in config {
            let path = opts.workspace_root.join(&vf.path);
            if !path.exists() {
                if !opts.quiet {
                    Output::warning(&format!("Version file not found: {}", vf.path));
                }
                continue;
            }

            let changed = bump_custom_file(&path, &vf.pattern, &bare_version, opts.dry_run)?;
            if changed {
                bumped_files.push(vf.path.clone());
                if !opts.json && !opts.quiet {
                    Output::success(&format!("  Updated {}", vf.path));
                }
            }
        }
    } else {
        // Auto-detect version files
        let detected = detect_version_files(opts.workspace_root, &repos);
        for (repo_name, path) in &detected {
            let file_name = path.file_name().unwrap_or_default().to_string_lossy();
            let relative = path
                .strip_prefix(opts.workspace_root)
                .unwrap_or(path)
                .to_string_lossy()
                .to_string();

            let changed = if file_name == "Cargo.toml" {
                bump_cargo_toml(path, &bare_version, opts.dry_run)?
            } else if file_name == "package.json" {
                bump_package_json(path, &bare_version, opts.dry_run)?
            } else {
                false
            };

            if changed {
                bumped_files.push(relative.clone());
                if !opts.json && !opts.quiet {
                    Output::success(&format!("  Updated {} ({})", relative, repo_name));
                }
            }
        }
    }

    if bumped_files.is_empty() && !opts.quiet {
        Output::warning("  No version files were updated");
    }

    let mut step = StepResultJson::ok("bump-version");
    step.files = Some(bumped_files.clone());
    steps.push(step);

    // Update Cargo.lock if any Cargo.toml was bumped
    if !opts.dry_run {
        for file in &bumped_files {
            if file.ends_with("Cargo.toml") {
                let cargo_dir = opts.workspace_root.join(file);
                let cargo_dir = cargo_dir.parent().unwrap_or(opts.workspace_root);
                if cargo_dir.join("Cargo.lock").exists() {
                    let status = Command::new("cargo")
                        .arg("generate-lockfile")
                        .current_dir(cargo_dir)
                        .status();
                    if let Ok(s) = status {
                        if s.success() && !opts.json && !opts.quiet {
                            Output::success(&format!(
                                "  Updated Cargo.lock in {}",
                                cargo_dir.display()
                            ));
                        }
                    }
                }
            }
        }
    }

    // ── Step 2: Update CHANGELOG ────────────────────────────────
    if !opts.json && !opts.quiet {
        Output::info("Step 2: Updating CHANGELOG");
    }

    let changelog_path = release_config
        .and_then(|r| r.changelog.as_ref())
        .map(|p| opts.workspace_root.join(p))
        .unwrap_or_else(|| opts.workspace_root.join("CHANGELOG.md"));

    let changelog_updated =
        update_changelog(&changelog_path, &version_tag, opts.notes, opts.dry_run)?;

    if changelog_updated {
        let relative = changelog_path
            .strip_prefix(opts.workspace_root)
            .unwrap_or(&changelog_path)
            .to_string_lossy()
            .to_string();
        if !opts.json && !opts.quiet {
            Output::success(&format!("  Updated {}", relative));
        }
        steps.push(StepResultJson::ok("changelog"));
    } else {
        if !opts.json && !opts.quiet {
            Output::info("  No CHANGELOG.md found, skipping");
        }
        steps.push(StepResultJson::skipped("changelog"));
    }

    // ── Step 3: Build ───────────────────────────────────────────
    if !opts.json && !opts.quiet {
        Output::info("Step 3: Building");
    }

    let mut built_any = false;
    for repo in &repos {
        let build_cmd = repo.agent.as_ref().and_then(|a| a.build.as_deref());
        let Some(cmd) = build_cmd else {
            continue;
        };

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info(&format!("  Would run in {}: {}", repo.name, cmd));
            }
            built_any = true;
            continue;
        }

        if !opts.json && !opts.quiet {
            Output::info(&format!("  Building {} ({})", repo.name, cmd));
        }

        let status = Command::new("sh")
            .arg("-c")
            .arg(cmd)
            .current_dir(&repo.absolute_path)
            .status()?;

        if !status.success() {
            anyhow::bail!(
                "Build failed for '{}' (exit code: {:?})",
                repo.name,
                status.code()
            );
        }

        built_any = true;
        if !opts.json && !opts.quiet {
            Output::success(&format!("  {} built successfully", repo.name));
        }
    }

    if built_any {
        steps.push(StepResultJson::ok("build"));
    } else {
        if !opts.json && !opts.quiet {
            Output::info("  No agent.build configured, skipping");
        }
        steps.push(StepResultJson::skipped("build"));
    }

    // ── Steps 4-9: PR workflow (skip if --skip-pr) ──────────────
    if opts.skip_pr {
        if !opts.json && !opts.quiet {
            Output::info("Skipping PR workflow (--skip-pr)");
        }
        steps.push(StepResultJson::skipped("branch"));
        steps.push(StepResultJson::skipped("pr"));
        steps.push(StepResultJson::skipped("ci"));
        steps.push(StepResultJson::skipped("merge"));
    } else {
        // Step 4: Create branch
        if !opts.json && !opts.quiet {
            Output::info(&format!("Step 4: Creating branch release/{}", version_tag));
        }

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info(&format!(
                    "  Would create branch release/{} across repos",
                    version_tag
                ));
            }
            steps.push(StepResultJson::ok("branch"));
        } else {
            crate::cli::commands::branch::run_branch(
                crate::cli::commands::branch::BranchOptions {
                    workspace_root: opts.workspace_root,
                    manifest: opts.manifest,
                    name: Some(&format!("release/{}", version_tag)),
                    delete: false,
                    move_commits: false,
                    repos_filter: None,
                    group_filter: None,
                    json: opts.json,
                },
            )?;
            steps.push(StepResultJson::ok("branch"));
        }

        // Step 5: Stage all changes
        if !opts.json && !opts.quiet {
            Output::info("Step 5: Staging and committing changes");
        }

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info(&format!(
                    "  Would commit: \"chore: release {}\"",
                    version_tag
                ));
            }
        } else {
            // Stage all changes
            crate::cli::commands::add::run_add(
                opts.workspace_root,
                opts.manifest,
                &[".".to_string()],
            )?;

            // Commit
            crate::cli::commands::commit::run_commit(
                opts.workspace_root,
                opts.manifest,
                &format!("chore: release {}", version_tag),
                false,
                opts.json,
            )?;
        }

        // Step 6: Push
        if !opts.json && !opts.quiet {
            Output::info("Step 6: Pushing to remote");
        }

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info("  Would push with upstream tracking");
            }
        } else {
            crate::cli::commands::push::run_push(
                opts.workspace_root,
                opts.manifest,
                true,  // set_upstream
                false, // force
                opts.quiet,
                opts.json,
            )?;
        }

        // Step 7: Create PR
        if !opts.json && !opts.quiet {
            Output::info("Step 7: Creating pull request");
        }

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info(&format!(
                    "  Would create PR: \"chore: release {}\"",
                    version_tag
                ));
            }
            steps.push(StepResultJson::ok("pr"));
        } else {
            crate::cli::commands::pr::run_pr_create(
                opts.workspace_root,
                opts.manifest,
                Some(&format!("chore: release {}", version_tag)),
                opts.notes,
                false, // draft
                false, // push (already pushed)
                false, // dry_run
                opts.json,
            )
            .await?;
            steps.push(StepResultJson::ok("pr"));
        }

        // Step 8: Wait for CI + Merge
        if !opts.json && !opts.quiet {
            Output::info("Step 8: Waiting for CI and merging");
        }

        if opts.dry_run {
            if !opts.json && !opts.quiet {
                Output::info(&format!(
                    "  Would wait {}s for CI, then merge",
                    opts.timeout
                ));
            }
            steps.push(StepResultJson::ok("ci"));
            steps.push(StepResultJson::ok("merge"));
        } else {
            crate::cli::commands::pr::run_pr_merge(
                opts.workspace_root,
                opts.manifest,
                None,  // method (default)
                false, // force
                false, // update
                false, // auto
                opts.json,
                true, // wait
                opts.timeout,
            )
            .await?;
            steps.push(StepResultJson::ok("ci"));
            steps.push(StepResultJson::ok("merge"));
        }

        // Step 9: Sync after merge
        if !opts.json && !opts.quiet {
            Output::info("Step 9: Syncing after merge");
        }

        if !opts.dry_run {
            // Checkout default branch
            let default_branch = repos
                .first()
                .map(|r| r.default_branch.as_str())
                .unwrap_or("main");
            crate::cli::commands::checkout::run_checkout(
                opts.workspace_root,
                opts.manifest,
                default_branch,
                false,
            )?;

            // Sync
            crate::cli::commands::sync::run_sync(
                opts.workspace_root,
                opts.manifest,
                false, // force
                opts.quiet,
                None,  // group
                false, // sequential
                false, // reset_refs
                opts.json,
                false, // no_hooks
            )
            .await?;
        }
    }

    // ── Step 10: Create GitHub release ──────────────────────────
    if !opts.json && !opts.quiet {
        Output::info("Step 10: Creating GitHub release");
    }

    let target_repo = find_release_target(&repos, opts.target_repo)?;

    if opts.dry_run {
        if !opts.json && !opts.quiet {
            Output::info(&format!(
                "  Would create release {} on {}/{} ({})",
                version_tag, target_repo.owner, target_repo.repo, target_repo.name
            ));
        }
        let mut step = StepResultJson::ok("release");
        step.url = Some(format!(
            "https://github.com/{}/{}/releases/tag/{}",
            target_repo.owner, target_repo.repo, version_tag
        ));
        steps.push(step);
    } else {
        let platform = get_platform_adapter(
            target_repo.platform_type,
            target_repo.platform_base_url.as_deref(),
        );

        let default_branch = &target_repo.default_branch;

        let result: ReleaseResult = platform
            .create_release(
                &target_repo.owner,
                &target_repo.repo,
                &version_tag,
                &version_tag,
                opts.notes,
                default_branch,
                false, // draft
                false, // prerelease
            )
            .await
            .map_err(|e| anyhow::anyhow!("Failed to create release: {}", e))?;

        if !opts.json && !opts.quiet {
            Output::success(&format!("  Created release: {}", result.url));
        }

        let mut step = StepResultJson::ok("release");
        step.url = Some(result.url);
        steps.push(step);
    }

    // ── Step 11: Post-release hooks ─────────────────────────────
    if let Some(hooks) = release_config.and_then(|r| r.post_release.as_ref()) {
        if !opts.json && !opts.quiet {
            Output::info("Step 11: Running post-release hooks");
        }

        for hook in hooks {
            let cmd = hook.command.replace("{version}", &bare_version);
            let display_name = hook.name.as_deref().unwrap_or(&cmd);

            if opts.dry_run {
                if !opts.json && !opts.quiet {
                    Output::info(&format!("  Would run: {}", display_name));
                }
                continue;
            }

            if !opts.json && !opts.quiet {
                Output::info(&format!("  Running: {}", display_name));
            }

            let working_dir = hook
                .cwd
                .as_ref()
                .map(|p| opts.workspace_root.join(p))
                .unwrap_or_else(|| opts.workspace_root.clone());

            let status = Command::new("sh")
                .arg("-c")
                .arg(&cmd)
                .current_dir(&working_dir)
                .status()?;

            if !status.success() {
                anyhow::bail!(
                    "Post-release hook '{}' failed (exit code: {:?})",
                    display_name,
                    status.code()
                );
            }

            if !opts.json && !opts.quiet {
                Output::success(&format!("  {} completed", display_name));
            }
        }
        steps.push(StepResultJson::ok("post-release"));
    }

    // ── Output ──────────────────────────────────────────────────
    if opts.json {
        let output = ReleaseOutputJson {
            version: bare_version,
            steps,
        };
        println!("{}", serde_json::to_string_pretty(&output)?);
    } else if !opts.quiet {
        println!();
        if opts.dry_run {
            Output::success(&format!("Dry run complete for {}", version_tag));
        } else {
            Output::success(&format!("Released {}", version_tag));
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_normalize_version_with_v_prefix() {
        let (bare, tag) = normalize_version("v1.2.3").unwrap();
        assert_eq!(bare, "1.2.3");
        assert_eq!(tag, "v1.2.3");
    }

    #[test]
    fn test_normalize_version_without_prefix() {
        let (bare, tag) = normalize_version("1.2.3").unwrap();
        assert_eq!(bare, "1.2.3");
        assert_eq!(tag, "v1.2.3");
    }

    #[test]
    fn test_normalize_version_two_parts() {
        let (bare, tag) = normalize_version("1.0").unwrap();
        assert_eq!(bare, "1.0");
        assert_eq!(tag, "v1.0");
    }

    #[test]
    fn test_normalize_version_prerelease() {
