//! Sync command implementation

use crate::cli::commands::link::apply_links;
use crate::cli::output::Output;
use crate::core::gripspace::{
    ensure_gripspace, gripspace_name, resolve_all_gripspaces, update_gripspace,
};
use crate::core::griptree::GriptreeConfig;
use crate::core::manifest::{HookCondition, Manifest};
use crate::core::manifest_paths;
use crate::core::repo::{filter_repos, get_manifest_repo_info, RepoInfo};
use crate::core::sync_state::SyncSnapshot;
use crate::files::process_composefiles;
use crate::git::branch::{checkout_branch_at_upstream, checkout_detached, has_commits_ahead};
use crate::git::remote::{
    fetch_remote, pull_latest_from_upstream, reset_hard, safe_pull_latest, set_branch_upstream_ref,
};
use crate::git::status::has_uncommitted_changes;
use crate::git::{clone_repo, get_current_branch, open_repo, path_exists};
use git2::Repository;
use indicatif::ProgressBar;
use std::collections::HashSet;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use tokio::task::JoinSet;

/// Result of syncing a single repo
#[derive(Debug)]
struct SyncResult {
    name: String,
    success: bool,
    message: String,
    was_cloned: bool,
    had_changes: bool,
}

/// JSON-serializable sync result for --json output
#[derive(serde::Serialize)]
struct JsonSyncRepo {
    name: String,
    action: String,
    error: Option<String>,
}

/// Result of running a single post-sync hook
#[derive(serde::Serialize, Clone)]
struct HookResult {
    name: String,
    success: bool,
    skipped: bool,
    duration_ms: u64,
    #[serde(skip_serializing_if = "Option::is_none")]
    error: Option<String>,
}

/// Run the sync command
#[allow(clippy::too_many_arguments)]
pub async fn run_sync(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    force: bool,
    quiet: bool,
    group_filter: Option<&[String]>,
    sequential: bool,
    reset_refs: bool,
    json: bool,
    no_hooks: bool,
) -> anyhow::Result<()> {
    // Re-load and resolve gripspaces before syncing repos
    let manifest = sync_gripspaces(workspace_root, manifest, quiet)?;
    let manifest = &manifest;

    let mut repos: Vec<RepoInfo> = filter_repos(manifest, workspace_root, None, group_filter, true);

    // Include manifest repo at the beginning (sync it first)
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.insert(0, manifest_repo);
    }
    let griptree_config = GriptreeConfig::load_from_workspace(workspace_root)?;
    let griptree_branch = griptree_config.as_ref().map(|cfg| cfg.branch.clone());

    // Capture pre-sync snapshot for rollback support
    if let Ok(snapshot) = SyncSnapshot::capture(workspace_root, &repos) {
        if let Err(e) = snapshot.save(workspace_root) {
            if !quiet && !json {
                Output::warning(&format!("Could not save sync snapshot: {}", e));
            }
        }
    }

    if !json {
        Output::header(&format!("Syncing {} repositories...", repos.len()));
        println!();
    }

    let results = if sequential {
        sync_sequential(
            &repos,
            force,
            quiet,
            griptree_config.as_ref(),
            griptree_branch.as_deref(),
            reset_refs,
        )?
    } else {
        sync_parallel(
            &repos,
            force,
            quiet,
            griptree_config.clone(),
            griptree_branch.clone(),
            reset_refs,
        )
        .await?
    };

    // Display results
    let mut success_count = 0;
    let mut error_count = 0;
    let mut failed_repos: Vec<(String, String)> = Vec::new();

    // Build JSON data alongside display
    let mut json_repos: Vec<JsonSyncRepo> = Vec::new();

    for result in &results {
        let action = if result.was_cloned {
            "cloned"
        } else if result.success {
            "pulled"
        } else {
            "failed"
        };

        json_repos.push(JsonSyncRepo {
            name: result.name.clone(),
            action: action.to_string(),
            error: if !result.success {
                Some(result.message.clone())
            } else {
                None
            },
        });

        if result.success {
            success_count += 1;
        } else {
            error_count += 1;
            failed_repos.push((result.name.clone(), result.message.clone()));
        }
    }

    if !json {
        println!();
        if error_count == 0 {
            Output::success(&format!(
                "All {} repositories synced successfully.",
                success_count
            ));
        } else {
            Output::warning(&format!("{} synced, {} failed", success_count, error_count));

            if !failed_repos.is_empty() {
                println!();
                for (repo_name, error_msg) in &failed_repos {
                    println!("  ✗ {}: {}", repo_name, error_msg);
                }
            }
        }
    }

    // Process composefiles after sync
    let mut composefiles_count = 0;
    if let Some(ref manifest_config) = manifest.manifest {
        if let Some(ref composefiles) = manifest_config.composefile {
            if !composefiles.is_empty() {
                composefiles_count = composefiles.len();
                let manifests_dir = manifest_paths::resolve_manifest_content_dir(workspace_root);
                let spaces_dir = manifest_paths::spaces_dir(workspace_root);

                match process_composefiles(
                    workspace_root,
                    &manifests_dir,
                    &spaces_dir,
                    composefiles,
                ) {
                    Ok(()) => {
                        if !quiet && !json {
                            Output::success(&format!(
                                "Processed {} composefile(s)",
                                composefiles.len()
                            ));
                        }
                    }
                    Err(e) => {
                        if !json {
                            Output::warning(&format!("Composefile processing failed: {}", e));
                        }
                    }
                }
            }
        }
    }

    // Generate agent context files (after composefiles, before linkfiles)
    if let Some(agent_config) = manifest.workspace.as_ref().and_then(|w| w.agent.as_ref()) {
        if agent_config.targets.is_some() {
            match crate::cli::commands::agent::run_agent_generate_context(
                workspace_root,
                manifest,
                false,
                quiet || json,
            ) {
                Ok(()) => {}
                Err(e) => {
                    if !json {
                        Output::warning(&format!("Agent context generation failed: {}", e));
                    }
                }
            }
        }
    }

    // Apply linkfiles and copyfiles after repos and composefiles
    match apply_links(workspace_root, manifest, quiet || json) {
        Ok(()) => {}
        Err(e) => {
            if !json {
                Output::warning(&format!("Link application failed: {}", e));
            }
        }
    }

    // Execute post-sync hooks
    let hook_results = if no_hooks {
        Vec::new()
    } else {
        execute_post_sync_hooks(workspace_root, manifest, &results, quiet, json)
    };

    if json {
        #[derive(serde::Serialize)]
        struct JsonSyncResult {
            success: bool,
            repos: Vec<JsonSyncRepo>,
            composefiles: usize,
            hooks: Vec<HookResult>,
        }

        let result = JsonSyncResult {
            success: error_count == 0,
            repos: json_repos,
            composefiles: composefiles_count,
            hooks: hook_results,
        };
        println!("{}", serde_json::to_string_pretty(&result)?);
    }

    Ok(())
}

/// Sync gripspaces: update existing or clone new ones, then resolve merged manifest.
fn sync_gripspaces(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    quiet: bool,
) -> anyhow::Result<Manifest> {
    let gripspaces = match &manifest.gripspaces {
        Some(gs) if !gs.is_empty() => gs,
        _ => return Ok(manifest.clone()),
    };

    let spaces_dir = manifest_paths::spaces_dir(workspace_root);

    if !quiet {
        Output::header(&format!("Syncing {} gripspace(s)...", gripspaces.len()));
        println!();
    }

    for gs_config in gripspaces {
        let name = gripspace_name(&gs_config.url);
        // Use resolve_space_name to find the actual directory (handles reserved names)
        let dir_name = match crate::core::gripspace::resolve_space_name(&gs_config.url, &spaces_dir)
        {
            Ok(dir_name) => dir_name,
            Err(e) => {
                Output::warning(&format!(
                    "gripspace '{}': name resolution failed: {}",
                    gs_config.url, e
                ));
                continue;
            }
        };
        let gs_path = spaces_dir.join(&dir_name);

        if gs_path.exists() {
            match update_gripspace(&gs_path, gs_config) {
                Ok(()) => {
                    if !quiet {
                        Output::success(&format!("gripspace '{}': updated", name));
                    }
                }
                Err(e) => {
                    Output::warning(&format!("gripspace '{}': update failed: {}", name, e));
                }
            }
        } else {
            match ensure_gripspace(&spaces_dir, gs_config) {
                Ok(_) => {
                    if !quiet {
                        Output::success(&format!("gripspace '{}': cloned", name));
                    }
                }
                Err(e) => {
                    Output::warning(&format!("gripspace '{}': clone failed: {}", name, e));
                }
            }
        }
    }

    if !quiet {
        println!();
    }

    // Re-resolve the merged manifest from whichever layout is present.
    let manifest_path = manifest_paths::resolve_gripspace_manifest_path(workspace_root);
    let mut resolved = if let Some(path) = manifest_path {
        Manifest::parse_raw(&std::fs::read_to_string(path)?)?
    } else {
        manifest.clone()
    };

    if let Err(e) = resolve_all_gripspaces(&mut resolved, &spaces_dir) {
        Output::warning(&format!("Gripspace resolution failed: {}", e));
        return Ok(manifest.clone());
    }

    if let Err(e) = resolved.validate() {
        Output::warning(&format!(
            "Resolved manifest validation failed after gripspace sync: {}. \
Using the pre-sync manifest; check gripspace manifests/includes.",
            e
        ));
        return Ok(manifest.clone());
    }

    Ok(resolved)
}

/// Sync repos sequentially (original behavior)
fn sync_sequential(
    repos: &[RepoInfo],
    force: bool,
    quiet: bool,
    griptree_config: Option<&GriptreeConfig>,
    griptree_branch: Option<&str>,
    reset_refs: bool,
) -> anyhow::Result<Vec<SyncResult>> {
    let mut results = Vec::new();

    for repo in repos {
        let result = sync_single_repo(
            repo,
            force,
            quiet,
            true,
            griptree_config,
            griptree_branch,
            reset_refs,
        )?;
        results.push(result);
    }

    Ok(results)
}

/// Sync repos in parallel using tokio
#[allow(clippy::unnecessary_to_owned)] // We need to clone for move into spawn_blocking
async fn sync_parallel(
    repos: &[RepoInfo],
    force: bool,
    quiet: bool,
    griptree_config: Option<GriptreeConfig>,
    griptree_branch: Option<String>,
    reset_refs: bool,
) -> anyhow::Result<Vec<SyncResult>> {
    let results: Arc<Mutex<Vec<SyncResult>>> = Arc::new(Mutex::new(Vec::new()));
    let mut join_set: JoinSet<anyhow::Result<()>> = JoinSet::new();

    // Show a single spinner for all repos
    let spinner = Output::spinner(&format!("Syncing {} repos in parallel...", repos.len()));

    for repo in repos.to_vec() {
        let results = Arc::clone(&results);
        let griptree_config = griptree_config.clone();
        let griptree_branch = griptree_branch.clone();

        join_set.spawn_blocking(move || {
            let result = sync_single_repo(
                &repo,
                force,
                quiet,
                false,
                griptree_config.as_ref(),
                griptree_branch.as_deref(),
                reset_refs,
            )?;
            results.lock().expect("mutex poisoned").push(result);
            Ok(())
        });
    }

    // Wait for all tasks to complete
    while let Some(res) = join_set.join_next().await {
        res??;
    }

    spinner.finish_and_clear();

    // Extract results from Arc<Mutex<>>
    let results = match Arc::try_unwrap(results) {
        Ok(mutex) => mutex.into_inner().expect("mutex poisoned"),
        Err(arc) => arc.lock().expect("mutex poisoned").clone(),
    };

    // Print results in order
    for result in &results {
        if result.success {
            if !quiet || result.was_cloned {
                Output::success(&format!("{}: {}", result.name, result.message));
            }
        } else {
            Output::error(&format!("{}: {}", result.name, result.message));
        }
    }

    Ok(results)
}

fn sync_griptree_upstream(
    repo: &RepoInfo,
    git_repo: &Repository,
    current_branch: Option<&str>,
    griptree_config: Option<&GriptreeConfig>,
    spinner: Option<&ProgressBar>,
    quiet: bool,
) -> SyncResult {
    let upstream = match griptree_config {
        Some(cfg) => match cfg.upstream_for_repo(&repo.name, &repo.default_branch) {
            Ok(upstream) => upstream,
            Err(e) => {
                let msg = format!("error - {}", e);
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return SyncResult {
                    name: repo.name.clone(),
                    success: false,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                };
            }
        },
        None => format!("origin/{}", repo.default_branch),
    };

    let remote = upstream.split('/').next().unwrap_or("origin");
    let mut upstream_set_warning: Option<String> = None;

    if let Err(e) = fetch_remote(git_repo, remote) {
        let msg = format!("error - {}", e);
        if let Some(s) = spinner {
            s.finish_with_message(format!("{}: {}", repo.name, msg));
        }
        return SyncResult {
            name: repo.name.clone(),
            success: false,
            message: msg,
            was_cloned: false,
            had_changes: false,
        };
    }

    if let Some(current) = current_branch {
        if let Err(e) = set_branch_upstream_ref(git_repo, current, &upstream) {
            upstream_set_warning = Some(format!("upstream tracking not updated: {}", e));
        }
    }

    if let Some(current) = current_branch {
        match has_commits_ahead(git_repo, &upstream) {
            Ok(true) => {
                let mut msg = format!(
                    "skipped - branch '{}' has local commits not in '{}'",
                    current, upstream
                );
                if let Some(warning) = upstream_set_warning.as_ref() {
                    msg.push_str(&format!(" ({})", warning));
                }
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return SyncResult {
                    name: repo.name.clone(),
                    success: true,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                };
            }
            Ok(false) => {}
            Err(e) => {
                let msg = format!("error - {}", e);
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return SyncResult {
                    name: repo.name.clone(),
                    success: false,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                };
            }
        }
    }

    match pull_latest_from_upstream(git_repo, &upstream) {
        Ok(()) => {
            let mut msg = format!("pulled ({})", upstream);
            if let Some(warning) = upstream_set_warning.as_ref() {
                msg.push_str(&format!(" ({})", warning));
            }
            if let Some(s) = spinner {
                if !quiet {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                } else {
                    s.finish_and_clear();
                }
            }

            SyncResult {
                name: repo.name.clone(),
                success: true,
                message: msg,
                was_cloned: false,
                had_changes: true,
            }
        }
        Err(e) => {
            let msg = format!("error - {}", e);
            if let Some(s) = spinner {
                s.finish_with_message(format!("{}: {}", repo.name, msg));
            }
            SyncResult {
                name: repo.name.clone(),
                success: false,
                message: msg,
                was_cloned: false,
                had_changes: false,
            }
        }
    }
}

fn sync_reference_reset(
    repo: &RepoInfo,
    git_repo: &Repository,
    griptree_config: Option<&GriptreeConfig>,
    spinner: Option<&ProgressBar>,
    quiet: bool,
) -> SyncResult {
    let upstream = match griptree_config {
        Some(cfg) => match cfg.upstream_for_repo(&repo.name, &repo.default_branch) {
            Ok(upstream) => upstream,
            Err(e) => {
                let msg = format!("error - {}", e);
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return SyncResult {
                    name: repo.name.clone(),
                    success: false,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                };
            }
        },
        None => format!("origin/{}", repo.default_branch),
    };

    let mut upstream_parts = upstream.splitn(2, '/');
    let remote = upstream_parts.next().unwrap_or("origin");
    let upstream_branch = upstream_parts.next().unwrap_or(&repo.default_branch);

    if let Ok(is_dirty) = has_uncommitted_changes(git_repo) {
        if is_dirty {
            Output::warning(&format!(
                "{}: --reset-refs will discard local changes",
                repo.name
            ));
        }
    }
    if let Ok(true) = has_commits_ahead(git_repo, &upstream) {
        Output::warning(&format!(
            "{}: --reset-refs will discard local commits not in {}",
            repo.name, upstream
        ));
    }
    if let Err(e) = fetch_remote(git_repo, remote) {
        let msg = format!("error - {}", e);
        if let Some(s) = spinner {
            s.finish_with_message(format!("{}: {}", repo.name, msg));
        }
        return SyncResult {
            name: repo.name.clone(),
            success: false,
            message: msg,
            was_cloned: false,
            had_changes: false,
        };
    }

    let mut used_detached_fallback = false;
    if let Err(e) = checkout_branch_at_upstream(git_repo, upstream_branch, &upstream) {
        let err_msg = e.to_string();
        if is_worktree_branch_lock_error(&err_msg) {
            if let Err(detach_err) = checkout_detached(git_repo, &upstream) {
                let msg = format!(
                    "error - {} (fallback detach failed: {})",
                    err_msg, detach_err
                );
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return SyncResult {
                    name: repo.name.clone(),
                    success: false,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                };
            }
            used_detached_fallback = true;
        } else {
            let msg = format!("error - {}", err_msg);
            if let Some(s) = spinner {
                s.finish_with_message(format!("{}: {}", repo.name, msg));
            }
            return SyncResult {
                name: repo.name.clone(),
                success: false,
                message: msg,
                was_cloned: false,
                had_changes: false,
            };
        }
    }

    match reset_hard(git_repo, &upstream) {
        Ok(()) => {
            let msg = if used_detached_fallback {
                format!("reset ({}, detached fallback)", upstream)
            } else {
                format!("reset ({})", upstream)
            };
            if let Some(s) = spinner {
                if !quiet {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                } else {
                    s.finish_and_clear();
                }
            }

            SyncResult {
                name: repo.name.clone(),
                success: true,
                message: msg,
                was_cloned: false,
                had_changes: true,
            }
        }
        Err(e) => {
            let msg = format!("error - {}", e);
            if let Some(s) = spinner {
                s.finish_with_message(format!("{}: {}", repo.name, msg));
            }
            SyncResult {
                name: repo.name.clone(),
                success: false,
                message: msg,
                was_cloned: false,
                had_changes: false,
            }
        }
    }
}

fn is_worktree_branch_lock_error(message: &str) -> bool {
    message.contains("checked out in another worktree")
        || message.contains("already checked out in another worktree")
        || message.contains("already used by worktree")
}

/// Sync a single repository
fn sync_single_repo(
    repo: &RepoInfo,
    force: bool,
    quiet: bool,
    show_spinner: bool,
    griptree_config: Option<&GriptreeConfig>,
    griptree_branch: Option<&str>,
    reset_refs: bool,
) -> anyhow::Result<SyncResult> {
    let spinner = if show_spinner {
        Some(Output::spinner(&format!("Pulling {}...", repo.name)))
    } else {
        None
    };

    if !path_exists(&repo.absolute_path) {
        // Clone the repo
        if let Some(ref s) = spinner {
            s.set_message(format!("Cloning {}...", repo.name));
        }

        match clone_repo(&repo.url, &repo.absolute_path, Some(&repo.default_branch)) {
            Ok(_) => {
                // Check actual branch after clone
                let clone_msg = if let Ok(git_repo) = open_repo(&repo.absolute_path) {
                    if let Ok(actual_branch) = get_current_branch(&git_repo) {
                        if actual_branch != repo.default_branch {
                            format!(
                                "cloned (on '{}', manifest specifies '{}')",
                                actual_branch, repo.default_branch
                            )
                        } else {
                            "cloned".to_string()
                        }
                    } else {
                        "cloned".to_string()
                    }
                } else {
                    "cloned".to_string()
                };

                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, clone_msg));
                }

                return Ok(SyncResult {
                    name: repo.name.clone(),
                    success: true,
                    message: clone_msg,
                    was_cloned: true,
                    had_changes: true,
                });
            }
            Err(e) => {
                let msg = format!("clone failed - {}", e);
                if let Some(s) = spinner {
                    s.finish_with_message(format!("{}: {}", repo.name, msg));
                }
                return Ok(SyncResult {
                    name: repo.name.clone(),
                    success: false,
                    message: msg,
                    was_cloned: false,
                    had_changes: false,
                });
            }
        }
    }

    // Pull existing repo
    match open_repo(&repo.absolute_path) {
        Ok(git_repo) => {
            if repo.reference && reset_refs {
                let result =
                    sync_reference_reset(repo, &git_repo, griptree_config, spinner.as_ref(), quiet);
                return Ok(result);
            }

            let current_branch = get_current_branch(&git_repo).ok();
            let use_griptree_upstream = match (griptree_branch, current_branch.as_deref()) {
                (Some(base), Some(current)) => current == base,
                _ => false,
            };

            if use_griptree_upstream {
                let result = sync_griptree_upstream(
                    repo,
                    &git_repo,
                    current_branch.as_deref(),
                    griptree_config,
                    spinner.as_ref(),
                    quiet,
                );
                Ok(result)
            } else {
                let result = safe_pull_latest(&git_repo, &repo.default_branch, "origin");

                match result {
                    Ok(pull_result) => {
                        let had_changes = pull_result.pulled;
                        let (success, message) = if pull_result.pulled {
                            if pull_result.recovered {
                                (
                                    true,
                                    pull_result
                                        .message
                                        .unwrap_or_else(|| "pulled (recovered)".to_string()),
                                )
                            } else {
                                (
                                    true,
                                    pull_result.message.unwrap_or_else(|| "pulled".to_string()),
                                )
                            }
                        } else if let Some(msg) = pull_result.message {
                            if force {
                                (true, format!("skipped - {}", msg))
                            } else {
                                (true, msg)
                            }
                        } else {
                            (true, "up to date".to_string())
                        };

                        if let Some(s) = spinner {
                            if !quiet || !success {
                                s.finish_with_message(format!("{}: {}", repo.name, message));
                            } else {
                                s.finish_and_clear();
                            }
                        }

                        Ok(SyncResult {
                            name: repo.name.clone(),
                            success,
                            message,
                            was_cloned: false,
                            had_changes,
                        })
                    }
                    Err(e) => {
                        let msg = format!("error - {}", e);
                        if let Some(s) = spinner {
                            s.finish_with_message(format!("{}: {}", repo.name, msg));
                        }
                        Ok(SyncResult {
                            name: repo.name.clone(),
                            success: false,
                            message: msg,
                            was_cloned: false,
                            had_changes: false,
                        })
                    }
                }
            }
        }
        Err(e) => {
            let msg = format!("error - {}", e);
            if let Some(s) = spinner {
                s.finish_with_message(format!("{}: {}", repo.name, msg));
            }
            Ok(SyncResult {
                name: repo.name.clone(),
                success: false,
                message: msg,
                was_cloned: false,
                had_changes: false,
            })
        }
    }
}

// Make SyncResult cloneable for parallel sync
impl Clone for SyncResult {
    fn clone(&self) -> Self {
        SyncResult {
            name: self.name.clone(),
            success: self.success,
            message: self.message.clone(),
            was_cloned: self.was_cloned,
            had_changes: self.had_changes,
        }
    }
}

/// Execute post-sync hooks defined in the manifest
fn execute_post_sync_hooks(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    sync_results: &[SyncResult],
    quiet: bool,
    json: bool,
) -> Vec<HookResult> {
    let hooks = match manifest
        .workspace
        .as_ref()
        .and_then(|w| w.hooks.as_ref())
        .and_then(|h| h.post_sync.as_ref())
    {
        Some(hooks) if !hooks.is_empty() => hooks,
        _ => return Vec::new(),
    };

    // Build set of repos that had changes
    let changed_repos: HashSet<&str> = sync_results
        .iter()
        .filter(|r| r.had_changes)
        .map(|r| r.name.as_str())
        .collect();

    let any_changed = !changed_repos.is_empty();

    if !quiet && !json {
        Output::header("Post-Sync Hooks");
        println!();
    }

    let mut results = Vec::new();

    for hook in hooks {
        let hook_name = hook.name.as_deref().unwrap_or(&hook.command).to_string();

        // Check condition
        let should_run = match hook.condition {
            HookCondition::Always => true,
            HookCondition::Changed => {
                if let Some(ref repos) = hook.repos {
                    // Run if any of the specified repos had changes
                    repos.iter().any(|r| changed_repos.contains(r.as_str()))
                } else {
                    // Run if any repo had changes
                    any_changed
                }
            }
        };

        if !should_run {
            if !quiet && !json {
                Output::info(&format!("{}: skipped (no changes)", hook_name));
            }
            results.push(HookResult {
                name: hook_name,
                success: true,
                skipped: true,
                duration_ms: 0,
                error: None,
            });
            continue;
        }

        let working_dir = hook
            .cwd
            .as_ref()
            .map(|p| workspace_root.join(p))
            .unwrap_or_else(|| workspace_root.clone());

        let start = std::time::Instant::now();
        let status = std::process::Command::new("sh")
            .arg("-c")
            .arg(&hook.command)
            .current_dir(&working_dir)
            .status();
        let duration_ms = start.elapsed().as_millis() as u64;

        match status {
            Ok(exit) if exit.success() => {
                if !quiet && !json {
                    Output::success(&format!(
                        "{}: completed ({:.1}s)",
                        hook_name,
                        duration_ms as f64 / 1000.0
                    ));
                }
                results.push(HookResult {
                    name: hook_name,
                    success: true,
                    skipped: false,
                    duration_ms,
                    error: None,
                });
            }
            Ok(exit) => {
                let err_msg = format!("exit code {}", exit.code().unwrap_or(-1));
                if !quiet && !json {
                    Output::warning(&format!("{}: failed ({})", hook_name, err_msg));
                }
                results.push(HookResult {
                    name: hook_name,
                    success: false,
                    skipped: false,
                    duration_ms,
                    error: Some(err_msg),
                });
            }
            Err(e) => {
                let err_msg = e.to_string();
                if !quiet && !json {
                    Output::warning(&format!("{}: failed ({})", hook_name, err_msg));
                }
                results.push(HookResult {
                    name: hook_name,
                    success: false,
                    skipped: false,
                    duration_ms,
                    error: Some(err_msg),
                });
            }
        }
    }

    if !quiet && !json && !results.is_empty() {
        println!();
    }

    results
}

/// Rollback all repos to their state before the last sync.
pub async fn run_sync_rollback(
    workspace_root: &Path,
    _manifest: &Manifest,
    quiet: bool,
    json: bool,
) -> anyhow::Result<()> {
    let snapshot = SyncSnapshot::load_latest(workspace_root)?
        .ok_or_else(|| anyhow::anyhow!("No sync snapshot found. Run `gr sync` first."))?;

    if !quiet && !json {
        Output::header(&format!(
            "Rolling back to snapshot from {}",
            snapshot.timestamp.format("%Y-%m-%d %H:%M:%S UTC")
        ));
        println!();
    }

    let mut success_count = 0;
    let mut error_count = 0;

    #[derive(serde::Serialize)]
    struct JsonRollbackRepo {
        name: String,
        action: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        error: Option<String>,
    }
    let mut json_repos: Vec<JsonRollbackRepo> = Vec::new();

    for repo_snap in &snapshot.repos {
        if !repo_snap.path.exists() {
            if !quiet && !json {
                Output::warning(&format!("{}: skipped (not on disk)", repo_snap.name));
            }
            json_repos.push(JsonRollbackRepo {
                name: repo_snap.name.clone(),
                action: "skipped".to_string(),
                error: Some("not on disk".to_string()),
            });
            continue;
        }

        match open_repo(&repo_snap.path) {
            Ok(git_repo) => {
                // Checkout the recorded branch first (if different)
                let current = get_current_branch(&git_repo).unwrap_or_default();
                if current != repo_snap.branch {
                    if let Err(e) =
                        crate::git::branch::checkout_branch(&git_repo, &repo_snap.branch)
                    {
                        let msg = format!("checkout failed: {}", e);
                        if !quiet && !json {
                            Output::error(&format!("{}: {}", repo_snap.name, msg));
                        }
                        error_count += 1;
                        json_repos.push(JsonRollbackRepo {
                            name: repo_snap.name.clone(),
                            action: "failed".to_string(),
                            error: Some(msg),
                        });
                        continue;
                    }
                }

                // Reset to the recorded commit
                match reset_hard(&git_repo, &repo_snap.head_commit) {
                    Ok(()) => {
                        if !quiet && !json {
                            Output::success(&format!(
                                "{}: restored to {} on {}",
                                repo_snap.name,
                                &repo_snap.head_commit[..7.min(repo_snap.head_commit.len())],
                                repo_snap.branch
                            ));
                        }
                        success_count += 1;
                        json_repos.push(JsonRollbackRepo {
                            name: repo_snap.name.clone(),
                            action: "restored".to_string(),
                            error: None,
                        });
                    }
                    Err(e) => {
                        let msg = format!("reset failed: {}", e);
                        if !quiet && !json {
                            Output::error(&format!("{}: {}", repo_snap.name, msg));
                        }
                        error_count += 1;
                        json_repos.push(JsonRollbackRepo {
                            name: repo_snap.name.clone(),
                            action: "failed".to_string(),
                            error: Some(msg),
                        });
                    }
                }
            }
            Err(e) => {
                let msg = format!("open failed: {}", e);
                if !quiet && !json {
                    Output::error(&format!("{}: {}", repo_snap.name, msg));
                }
                error_count += 1;
                json_repos.push(JsonRollbackRepo {
                    name: repo_snap.name.clone(),
                    action: "failed".to_string(),
                    error: Some(msg),
                });
            }
        }
    }

    if json {
        #[derive(serde::Serialize)]
        struct JsonRollbackResult {
            success: bool,
            timestamp: String,
            repos: Vec<JsonRollbackRepo>,
        }
        let result = JsonRollbackResult {
            success: error_count == 0,
            timestamp: snapshot.timestamp.to_rfc3339(),
            repos: json_repos,
        };
        println!("{}", serde_json::to_string_pretty(&result)?);
    } else if !quiet {
        println!();
        if error_count == 0 {
            Output::success(&format!("Rolled back {} repo(s).", success_count));
        } else {
            Output::warning(&format!(
                "{} restored, {} failed",
                success_count, error_count
            ));
        }
    }

    Ok(())
}

//! Tree command implementation
//!
//! Manages griptrees (worktree-based parallel workspaces).

use crate::cli::commands::link::run_link;
use crate::cli::output::Output;
use crate::core::griptree::{GriptreeConfig, GriptreePointer, GriptreeRepoInfo};
use crate::core::manifest::Manifest;
use crate::core::manifest_paths;
use crate::core::repo::{filter_repos, get_manifest_repo_info, RepoInfo};
use crate::git::branch::{
    branch_exists, checkout_branch, delete_local_branch, remote_branch_exists,
};
use crate::git::remote::{delete_remote_branch, get_upstream_branch, set_branch_upstream_ref};
use crate::git::status::get_cached_status;
use crate::git::{get_current_branch, open_repo, path_exists};
use crate::util::log_cmd;
use chrono::Utc;
use std::collections::{HashMap, HashSet};
use std::path::{Path, PathBuf};
use std::process::Command;

/// Griptrees list file structure
#[derive(Debug, Clone, Default, serde::Serialize, serde::Deserialize)]
struct GriptreesList {
    griptrees: HashMap<String, GriptreeEntry>,
}

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
struct GriptreeEntry {
    path: String,
    branch: String,
    locked: bool,
    lock_reason: Option<String>,
}

/// Context for tracking griptree creation progress (for rollback on failure)
struct GriptreeCreationContext {
    /// List of (main_repo_path, worktree_name) for created worktrees
    created_worktrees: Vec<(PathBuf, String)>,
    /// The griptree directory being created
    tree_path: PathBuf,
}

impl GriptreeCreationContext {
    fn new(tree_path: PathBuf) -> Self {
        Self {
            created_worktrees: Vec::new(),
            tree_path,
        }
    }

    fn record_worktree(&mut self, main_repo_path: PathBuf, worktree_name: String) {
        self.created_worktrees.push((main_repo_path, worktree_name));
    }

    fn rollback(&self) {
        // Remove worktrees in reverse order
        for (repo_path, wt_name) in self.created_worktrees.iter().rev() {
            if let Ok(repo) = open_repo(repo_path) {
                if let Ok(wt) = repo.find_worktree(wt_name) {
                    let mut opts = git2::WorktreePruneOptions::new();
                    opts.valid(true);
                    let _ = wt.prune(Some(&mut opts));
                }
            }
        }
        // Remove griptree directory
        let _ = std::fs::remove_dir_all(&self.tree_path);
    }
}

/// Run tree add command
pub fn run_tree_add(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    branch: &str,
) -> anyhow::Result<()> {
    Output::header(&format!("Creating griptree for branch '{}'", branch));
    println!();

    // Load or create griptrees list
    let config_path = workspace_root.join(".gitgrip").join("griptrees.json");
    let mut griptrees: GriptreesList = if config_path.exists() {
        let content = std::fs::read_to_string(&config_path)?;
        serde_json::from_str(&content)?
    } else {
        GriptreesList::default()
    };

    // Check if griptree already exists
    if griptrees.griptrees.contains_key(branch) {
        anyhow::bail!("Griptree for '{}' already exists", branch);
    }

    // Calculate griptree path (sibling to workspace)
    let tree_name = branch.replace('/', "-");
    let tree_path = workspace_root
        .parent()
        .ok_or_else(|| anyhow::anyhow!("Cannot determine parent directory"))?
        .join(&tree_name);

    if tree_path.exists() {
        anyhow::bail!("Directory already exists: {:?}", tree_path);
    }

    // Create griptree directory
    std::fs::create_dir_all(&tree_path)?;

    // Initialize rollback context
    let mut ctx = GriptreeCreationContext::new(tree_path.clone());

    // Get all repos
    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    let mut success_count = 0;
    let mut error_count = 0;

    // Track original branches for each repo
    let mut repo_branches: Vec<GriptreeRepoInfo> = Vec::new();

    for repo in &repos {
        if !path_exists(&repo.absolute_path) {
            if repo.name == "opencode" {
                Output::error(&format!(
                    "{}: not cloned, skipping - this repo is required",
                    repo.name
                ));
            } else {
                Output::warning(&format!("{}: not cloned, skipping", repo.name));
            }
            continue;
        }

        // Get current branch from main workspace
        let git_repo = match open_repo(&repo.absolute_path) {
            Ok(r) => r,
            Err(e) => {
                Output::warning(&format!("{}: failed to open - {}", repo.name, e));
                continue;
            }
        };

        let current_branch = match get_current_branch(&git_repo) {
            Ok(b) => b,
            Err(e) => {
                Output::warning(&format!("{}: failed to get branch - {}", repo.name, e));
                continue;
            }
        };

        let worktree_path = tree_path.join(&repo.path);
        let spinner = Output::spinner(&format!("{}...", repo.name));

        // For reference repos: try to sync with upstream before creating worktree
        // Sync failure is not fatal - we'll create the worktree with current state
        let sync_warning = if repo.reference {
            match sync_repo_with_upstream(&repo.absolute_path, &repo.default_branch) {
                Ok(_) => None,
                Err(e) => Some(format!("sync skipped: {}", e)),
            }
        } else {
            None
        };

        // Create worktree on the griptree branch (creates branch if needed)
        // Base the new branch off the repo's default branch, not current HEAD
        match create_worktree(
            &repo.absolute_path,
            &worktree_path,
            branch,
            Some(&repo.default_branch),
        ) {
            Ok(_) => {
                let expected_upstream = format!("origin/{}", repo.default_branch);
                let upstream_warning = match open_repo(&worktree_path) {
                    Ok(repo_handle) => {
                        match set_branch_upstream_ref(&repo_handle, branch, &expected_upstream) {
                            Ok(()) => None,
                            Err(e) => Some(format!("upstream not set ({})", e)),
                        }
                    }
                    Err(e) => Some(format!("upstream not set ({})", e)),
                };

                // Record for rollback (use sanitized name matching create_worktree)
                let worktree_name = branch.replace('/', "-");
                ctx.record_worktree(repo.absolute_path.clone(), worktree_name.clone());

                // Track original branch for this repo (for merging back later)
                repo_branches.push(GriptreeRepoInfo {
                    name: repo.name.clone(),
                    original_branch: current_branch.clone(),
                    is_reference: repo.reference,
                    worktree_name: Some(worktree_name),
                    worktree_path: Some(worktree_path.to_string_lossy().to_string()),
                    main_repo_path: Some(repo.absolute_path.to_string_lossy().to_string()),
                });

                let mut status_msg = if repo.reference {
                    if let Some(ref warning) = sync_warning {
                        format!("{}: created on {} ({})", repo.name, branch, warning)
                    } else {
                        format!("{}: synced & created on {}", repo.name, branch)
                    }
                } else {
                    format!(
                        "{}: created on {} (from {})",
                        repo.name, branch, repo.default_branch
                    )
                };
                if let Some(warning) = upstream_warning {
                    status_msg.push_str(&format!(" ({})", warning));
                }
                spinner.finish_with_message(status_msg);
                success_count += 1;
            }
            Err(e) => {
                spinner.finish_with_message(format!("{}: failed - {}", repo.name, e));
                error_count += 1;
            }
        }
    }

    // Create .griptree structure in griptree
    let tree_gitgrip = tree_path.join(".gitgrip");
    std::fs::create_dir_all(&tree_gitgrip)?;

    // Initialize state.json for this griptree
    let state_path = tree_gitgrip.join("state.json");
    std::fs::write(&state_path, "{}")?;

    // Create manifest worktree if main workspace has a manifest repo
    let main_manifests_dir = manifest_paths::resolve_manifest_repo_dir(workspace_root);
    let (manifest_branch_option, manifest_worktree_name): (Option<String>, Option<String>) =
        if let Some(main_manifests_dir) = main_manifests_dir {
            let main_manifest_git_dir = main_manifests_dir.join(".git");
            if main_manifest_git_dir.exists() {
                // Main workspace has a manifest git repo - create worktree in griptree
                let tree_manifests_dir = tree_gitgrip.join("spaces").join("main");
                let manifest_spinner = Output::spinner("manifest");

                match create_manifest_worktree(&main_manifests_dir, &tree_manifests_dir, branch) {
                    Ok(manifest_branch) => {
                        manifest_spinner.finish_with_message(format!(
                            "manifest: created on {}",
                            manifest_branch
                        ));
                        success_count += 1;
                        (Some(manifest_branch.clone()), Some(manifest_branch))
                    }
                    Err(e) => {
                        manifest_spinner.finish_with_message(format!("manifest: failed - {}", e));
                        error_count += 1;
                        (None, None)
                    }
                }
            } else {
                (None, None)
            }
        } else {
            (None, None)
        };

    // Save griptree config in the griptree directory (include upstream mapping)
    let mut repo_upstreams: HashMap<String, String> = HashMap::new();
    for repo in &repos {
        let worktree_path = tree_path.join(&repo.path);
        if !worktree_path.exists() {
            continue;
        }

        let upstream = match open_repo(&worktree_path) {
            Ok(repo_handle) => match get_upstream_branch(&repo_handle, Some(branch)) {
                Ok(Some(name)) => name,
                _ => format!("origin/{}", repo.default_branch),
            },
            Err(_) => format!("origin/{}", repo.default_branch),
        };

        repo_upstreams.insert(repo.name.clone(), upstream);
    }

    let mut griptree_config = GriptreeConfig::new(branch, &tree_path.to_string_lossy());
    griptree_config.repo_upstreams = repo_upstreams;
    let griptree_config_path = tree_gitgrip.join("griptree.json");
    griptree_config.save(&griptree_config_path)?;

    // Create .griptree pointer file at root of griptree
    // This allows `gr status` to detect when running from within a griptree
    let pointer = GriptreePointer {
        main_workspace: workspace_root.to_string_lossy().to_string(),
        branch: branch.to_string(),
        locked: false,
        created_at: Some(Utc::now()),
        repos: repo_branches,
        manifest_branch: manifest_branch_option,
        manifest_worktree_name,
    };
    let pointer_path = tree_path.join(".griptree");
    let pointer_json = serde_json::to_string_pretty(&pointer)?;
    std::fs::write(&pointer_path, pointer_json)?;

    // Add to griptrees list
    // Check if we should rollback due to too many failures BEFORE saving config
    if success_count == 0 && error_count > 0 {
        Output::error("Griptree creation failed - no worktrees were created successfully");
        ctx.rollback();
        anyhow::bail!("Griptree creation failed, rolled back");
    }

    griptrees.griptrees.insert(
        branch.to_string(),
        GriptreeEntry {
            path: tree_path.to_string_lossy().to_string(),
            branch: branch.to_string(),
            locked: false,
            lock_reason: None,
        },
    );

    // Save griptrees list
    let config_json = serde_json::to_string_pretty(&griptrees)?;
    std::fs::write(&config_path, config_json)?;

    println!();
    if error_count == 0 {
        Output::success(&format!(
            "Griptree created at {:?} with {} repo(s)",
            tree_path, success_count
        ));
    } else {
        Output::warning(&format!(
            "Griptree created with {} success, {} errors",
            success_count, error_count
        ));
    }

    // Apply links in the new griptree
    if let Some(tree_manifest_path) = manifest_paths::resolve_gripspace_manifest_path(&tree_path) {
        println!();
        if let Ok(tree_manifest) = Manifest::load(&tree_manifest_path) {
            if let Err(e) = run_link(&tree_path, &tree_manifest, false, true, false) {
                Output::warning(&format!("Failed to apply links: {}", e));
            }
        }
    }

    println!();
    println!("To use the griptree:");
    println!("  cd {:?}", tree_path);

    Ok(())
}

/// Run tree list command
pub fn run_tree_list(workspace_root: &PathBuf) -> anyhow::Result<()> {
    Output::header("Griptrees");
    println!();

    let griptrees_root = resolve_griptrees_workspace_root(workspace_root);
    let config_path = griptrees_root.join(".gitgrip").join("griptrees.json");
    let griptrees: GriptreesList = if config_path.exists() {
        let content = std::fs::read_to_string(&config_path)?;
        serde_json::from_str(&content)?
    } else {
        GriptreesList::default()
    };

    if griptrees.griptrees.is_empty() {
        println!("No griptrees configured.");
    } else {
        for (branch, entry) in &griptrees.griptrees {
            let exists = PathBuf::from(&entry.path).exists();
            let status = if !exists {
                " (missing)"
            } else if entry.locked {
                " (locked)"
            } else {
                ""
            };

            println!("  {} -> {}{}", branch, entry.path, status);
            if let Some(ref reason) = entry.lock_reason {
                println!("    Lock reason: {}", reason);
            }
        }
    }

    // Discover unregistered griptrees
    let discovered = discover_legacy_griptrees(&griptrees_root, &griptrees)?;
    if !discovered.is_empty() {
        println!();
        Output::warning("Found unregistered griptrees:");
        for (path, branch) in &discovered {
            println!("  {} -> {} (unregistered)", branch, path.display());
        }
        println!();
        println!("These griptrees point to this workspace but are not in griptrees.json.");
        println!("You can manually add them to griptrees.json if needed.");
    }

    Ok(())
}

/// Return to the griptree base branch, sync upstreams, and optionally prune a branch.
pub async fn run_tree_return(
    workspace_root: &PathBuf,
    manifest: &Manifest,
    base_override: Option<&str>,
    no_sync: bool,
    autostash: bool,
    prune_branch: Option<&str>,
    prune_current: bool,
    prune_remote: bool,
    force: bool,
) -> anyhow::Result<()> {
    let griptree_config = GriptreeConfig::load_from_workspace(workspace_root)?;
    let base_branch = match (base_override, griptree_config.as_ref()) {
        (Some(base), _) => base.to_string(),
        (None, Some(cfg)) => cfg.branch.clone(),
        (None, None) => {
            anyhow::bail!(
                "No griptree config found. Use --base <branch> to specify the base branch."
            );
        }
    };

    let mut repos: Vec<RepoInfo> = filter_repos(
        manifest,
        workspace_root,
        None,
        None,
        false, /* include_reference */
    );
    if let Some(manifest_repo) = get_manifest_repo_info(manifest, workspace_root) {
        repos.push(manifest_repo);
    }

    Output::header(&format!(
        "Returning to {} and syncing upstreams...",
        Output::branch_name(&base_branch)
    ));
    println!();

    let mut dirty_repos: Vec<String> = Vec::new();
    let mut current_branches: HashMap<String, String> = HashMap::new();

    for repo in &repos {
        if !repo.exists() {
            continue;
        }
        let status = get_cached_status(&repo.absolute_path)?;
        current_branches.insert(repo.name.clone(), status.current_branch.clone());
        if !status.is_clean {
            dirty_repos.push(repo.name.clone());
        }
    }

    if !dirty_repos.is_empty() && !autostash {
        anyhow::bail!(
            "Uncommitted changes in: {}. Use --autostash to proceed.",
            dirty_repos.join(", ")
        );
    }

    let mut stashed_repos: Vec<PathBuf> = Vec::new();
    if autostash {
        for repo in &repos {
            if !dirty_repos.contains(&repo.name) || !repo.exists() {
                continue;
            }
            match stash_repo(&repo.absolute_path, "gr tree return") {
                Ok(true) => stashed_repos.push(repo.absolute_path.clone()),
                Ok(false) => {}
                Err(e) => Output::error(&format!("{}: stash failed - {}", repo.name, e)),
            }
        }
    }

    let mut checkout_failures = 0;
    for repo in &repos {
        if !repo.exists() {
            Output::warning(&format!("{}: not cloned, skipping", repo.name));
            continue;
        }
        let git_repo = open_repo(&repo.absolute_path)?;
        if let Ok(current) = get_current_branch(&git_repo) {
            if current == base_branch {
                Output::success(&format!("{}: already on {}", repo.name, base_branch));
                continue;
            }
        }
        if !branch_exists(&git_repo, &base_branch) {
            Output::warning(&format!(
                "{}: branch '{}' does not exist, skipping",
                repo.name, base_branch
            ));
            checkout_failures += 1;
            continue;
        }
        match checkout_branch(&git_repo, &base_branch) {
            Ok(()) => Output::success(&format!("{}: checked out {}", repo.name, base_branch)),
            Err(e) => {
                Output::error(&format!("{}: {}", repo.name, e));
                checkout_failures += 1;
            }
        }
    }

    if !no_sync {
        println!();
        let _ = crate::cli::commands::sync::run_sync(
            workspace_root,
            manifest,
            false,
            false,
            None,
            false,
            false,
            false,
            false,
        )
        .await;
    }

    if prune_branch.is_some() || prune_current {
        println!();
        let prune_target = prune_branch.map(|b| b.to_string());
        for repo in &repos {
            if !repo.exists() {
                continue;
            }
            let git_repo = open_repo(&repo.absolute_path)?;
            let target_branch = match &prune_target {
                Some(branch) => branch.clone(),
                None => current_branches
                    .get(&repo.name)
                    .cloned()
                    .unwrap_or_default(),
            };
            if target_branch.is_empty() || target_branch == base_branch {
                continue;
            }
            if !branch_exists(&git_repo, &target_branch) {
                Output::info(&format!(
                    "{}: branch '{}' not found, skipping",
                    repo.name, target_branch
                ));
                continue;
            }
            if let Err(e) = delete_local_branch(&git_repo, &target_branch, force) {
                Output::warning(&format!(
                    "{}: failed to delete '{}' - {}",
                    repo.name, target_branch, e
                ));
                continue;
            }
            Output::success(&format!(
                "{}: deleted local branch '{}'",
                repo.name, target_branch
            ));

            if prune_remote {
                let remote = "origin";
                if remote_branch_exists(&git_repo, &target_branch, remote) {
                    match delete_remote_branch(&git_repo, &target_branch, remote) {
                        Ok(()) => Output::success(&format!(
                            "{}: deleted remote branch '{}/{}'",
                            repo.name, remote, target_branch
                        )),
                        Err(e) => Output::warning(&format!(
                            "{}: failed to delete remote '{}/{}' - {}",
                            repo.name, remote, target_branch, e
                        )),
                    }
                } else {
                    Output::info(&format!(
                        "{}: remote branch '{}/{}' not found, skipping",
                        repo.name, remote, target_branch
                    ));
                }
            }
        }
    }

    if autostash && !stashed_repos.is_empty() {
        println!();
        for repo_path in &stashed_repos {
            if let Err(e) = stash_pop_repo(repo_path) {
                Output::warning(&format!(
                    "{}: stash pop failed - {}",
                    repo_path.display(),
                    e
                ));
            }
        }
    }

    if checkout_failures > 0 {
        Output::warning(&format!(
            "Return completed with {} checkout error(s)",
            checkout_failures
        ));
    } else {
        Output::success("Return completed");
    }

    Ok(())
}

/// Discover legacy/unregistered griptrees that point to this workspace
fn discover_legacy_griptrees(
    workspace_root: &Path,
    registered: &GriptreesList,
) -> anyhow::Result<Vec<(PathBuf, String)>> {
    let mut discovered = Vec::new();

    let parent = match workspace_root.parent() {
        Some(p) => p,
        None => return Ok(discovered),
    };

    // Build set of registered paths for quick lookup
    let registered_paths: HashSet<String> = registered
        .griptrees
        .values()
        .map(|e| e.path.clone())
        .collect();

    // Scan sibling directories
    let entries = match std::fs::read_dir(parent) {
        Ok(e) => e,
        Err(_) => return Ok(discovered),
    };

    for entry in entries.flatten() {
        let path = entry.path();

        if !path.is_dir() {
            continue;
        }
        if path == workspace_root {
            continue;
        }
        if registered_paths.contains(&path.to_string_lossy().to_string()) {
            continue;
        }

        // Check for .griptree pointer file
        let pointer_path = path.join(".griptree");
        if pointer_path.exists() {
            if let Ok(pointer) = GriptreePointer::load(&pointer_path) {
                // Check if it points to this workspace
                if pointer.main_workspace == workspace_root.to_string_lossy() {
                    discovered.push((path, pointer.branch));
                }
            }
        }
    }

    Ok(discovered)
}

fn resolve_griptrees_workspace_root(workspace_root: &PathBuf) -> PathBuf {
    let local_registry = workspace_root.join(".gitgrip").join("griptrees.json");
    if local_registry.exists() {
        return workspace_root.clone();
    }

    let pointer_path = workspace_root.join(".griptree");
    if pointer_path.exists() {
        if let Ok(pointer) = GriptreePointer::load(&pointer_path) {
            let main_workspace = PathBuf::from(pointer.main_workspace);
            let main_registry = main_workspace.join(".gitgrip").join("griptrees.json");
            if main_registry.exists() {
                return main_workspace;
            }
        }
    }

    workspace_root.clone()
}

/// Run tree remove command
pub fn run_tree_remove(workspace_root: &PathBuf, branch: &str, force: bool) -> anyhow::Result<()> {
    Output::header(&format!("Removing griptree for '{}'", branch));
    println!();

    let griptrees_root = resolve_griptrees_workspace_root(workspace_root);
    let config_path = griptrees_root.join(".gitgrip").join("griptrees.json");
    if !config_path.exists() {
        anyhow::bail!("No griptrees configured");
    }

    let content = std::fs::read_to_string(&config_path)?;
    let mut griptrees: GriptreesList = serde_json::from_str(&content)?;

    let entry = griptrees
        .griptrees
        .get(branch)
        .ok_or_else(|| anyhow::anyhow!("Griptree '{}' not found", branch))?;

    if entry.locked && !force {
        anyhow::bail!(
            "Griptree '{}' is locked{}. Use --force to remove anyway.",
            branch,
            entry
                .lock_reason
                .as_ref()
                .map(|r| format!(": {}", r))
                .unwrap_or_default()
        );
    }

    let tree_path = PathBuf::from(&entry.path);

    // Load griptree pointer to get worktree info for cleanup
    let pointer_path = tree_path.join(".griptree");
    let pointer = if pointer_path.exists() {
        GriptreePointer::load(&pointer_path).ok()
    } else {
        None
    };

    // Prune each repo's worktree properly before removing directory
    if let Some(ref ptr) = pointer {
        let cleanup_spinner = Output::spinner("Cleaning up worktrees...");

        for repo_info in &ptr.repos {
            // Use stored main_repo_path if available, otherwise fall back to workspace/name
            let main_repo_path = repo_info
                .main_repo_path
                .as_ref()
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from(&ptr.main_workspace).join(&repo_info.name));

            if let Ok(repo) = open_repo(&main_repo_path) {
                // Use stored worktree name if available, otherwise fall back to original branch
                let wt_name = repo_info
                    .worktree_name
                    .as_deref()
                    .unwrap_or(&repo_info.original_branch);
                prune_worktree(&repo, wt_name);
            }
        }

        // Remove manifest worktree
        if let Some(ref manifest_wt_name) = ptr.manifest_worktree_name {
            let main_workspace = PathBuf::from(&ptr.main_workspace);
            if let Some(main_manifest_path) =
                manifest_paths::resolve_manifest_repo_dir(&main_workspace)
            {
                if let Ok(repo) = open_repo(&main_manifest_path) {
                    prune_worktree(&repo, manifest_wt_name);
                }
            }
        }

        cleanup_spinner.finish_with_message("Worktrees cleaned up");
    }

    // Remove directory
    if tree_path.exists() {
        let spinner = Output::spinner("Removing griptree directory...");
        std::fs::remove_dir_all(&tree_path)?;
        spinner.finish_with_message("Directory removed");
    }

    // Update griptrees list
    griptrees.griptrees.remove(branch);
    let config_json = serde_json::to_string_pretty(&griptrees)?;
    std::fs::write(&config_path, config_json)?;

    Output::success(&format!("Griptree '{}' removed", branch));
    Ok(())
}

/// Prune a worktree from a repository
fn prune_worktree(repo: &git2::Repository, worktree_name: &str) {
    if let Ok(wt) = repo.find_worktree(worktree_name) {
        let mut opts = git2::WorktreePruneOptions::new();
        opts.valid(true); // Prune even if valid
        let _ = wt.prune(Some(&mut opts));
    }
}

/// Run tree lock command
pub fn run_tree_lock(
    workspace_root: &PathBuf,
    branch: &str,
    reason: Option<&str>,
) -> anyhow::Result<()> {
    let griptrees_root = resolve_griptrees_workspace_root(workspace_root);
    let config_path = griptrees_root.join(".gitgrip").join("griptrees.json");
    if !config_path.exists() {
        anyhow::bail!("No griptrees configured");
    }

    let content = std::fs::read_to_string(&config_path)?;
    let mut griptrees: GriptreesList = serde_json::from_str(&content)?;

    let entry = griptrees
        .griptrees
        .get_mut(branch)
        .ok_or_else(|| anyhow::anyhow!("Griptree '{}' not found", branch))?;

    entry.locked = true;
    entry.lock_reason = reason.map(|s| s.to_string());
    let entry_path = entry.path.clone();

    let config_json = serde_json::to_string_pretty(&griptrees)?;
    std::fs::write(&config_path, config_json)?;

    // Update .griptree pointer file if it exists
    let pointer_path = PathBuf::from(&entry_path).join(".griptree");
    if pointer_path.exists() {
        if let Ok(mut pointer) = GriptreePointer::load(&pointer_path) {
            pointer.locked = true;
            let pointer_json = serde_json::to_string_pretty(&pointer)?;
            std::fs::write(&pointer_path, pointer_json)?;
        }
    }

    Output::success(&format!("Griptree '{}' locked", branch));
    Ok(())
}

/// Run tree unlock command
pub fn run_tree_unlock(workspace_root: &PathBuf, branch: &str) -> anyhow::Result<()> {
    let griptrees_root = resolve_griptrees_workspace_root(workspace_root);
    let config_path = griptrees_root.join(".gitgrip").join("griptrees.json");
    if !config_path.exists() {
        anyhow::bail!("No griptrees configured");
    }

    let content = std::fs::read_to_string(&config_path)?;
    let mut griptrees: GriptreesList = serde_json::from_str(&content)?;

    let entry = griptrees
        .griptrees
        .get_mut(branch)
        .ok_or_else(|| anyhow::anyhow!("Griptree '{}' not found", branch))?;

    entry.locked = false;
    entry.lock_reason = None;
    let entry_path = entry.path.clone();

    let config_json = serde_json::to_string_pretty(&griptrees)?;
    std::fs::write(&config_path, config_json)?;

    // Update .griptree pointer file if it exists
    let pointer_path = PathBuf::from(&entry_path).join(".griptree");
    if pointer_path.exists() {
        if let Ok(mut pointer) = GriptreePointer::load(&pointer_path) {
            pointer.locked = false;
            let pointer_json = serde_json::to_string_pretty(&pointer)?;
            std::fs::write(&pointer_path, pointer_json)?;
        }
    }

    Output::success(&format!("Griptree '{}' unlocked", branch));
    Ok(())
}

/// Create manifest worktree for a griptree
fn create_manifest_worktree(
    main_manifests_dir: &PathBuf,
    tree_manifests_dir: &PathBuf,
    branch: &str,
) -> anyhow::Result<String> {
    let repo = open_repo(main_manifests_dir)?;

    // Get current branch from main manifests (unused but kept for context)
    let _current_branch = get_current_branch(&repo)?;

    // Create worktree at griptree's .gitgrip/spaces/main/
    // Use the griptree branch name for the manifest worktree
    // Manifest worktrees create from HEAD since there's no "default branch" concept
    let worktree_name = format!("griptree-{}", branch.replace('/', "-"));
    create_worktree(main_manifests_dir, tree_manifests_dir, &worktree_name, None)?;

    // Ensure a supported workspace manifest file exists in the new worktree.
    if manifest_paths::resolve_manifest_file_in_dir(tree_manifests_dir).is_none() {
        if let Some(main_manifest) =
            manifest_paths::resolve_manifest_file_in_dir(main_manifests_dir)
        {
            let target_manifest = tree_manifests_dir.join(manifest_paths::PRIMARY_FILE_NAME);
            std::fs::copy(main_manifest, target_manifest)?;
        }
    }

    Ok(worktree_name)
}
/// Create a git worktree using git2
///
/// When creating a new branch, bases it off `base_branch` (e.g., "main") instead of HEAD.
/// This ensures griptrees start from the default branch, not whatever branch the workspace is on.
fn create_worktree(
    repo_path: &PathBuf,
    worktree_path: &PathBuf,
    branch: &str,
    base_branch: Option<&str>,
) -> anyhow::Result<()> {
    let repo = open_repo(repo_path)?;

    // Create parent directory if needed
    if let Some(parent) = worktree_path.parent() {
        std::fs::create_dir_all(parent)?;
    }

    // Sanitize worktree name: git2 uses this as a directory name under
    // .git/worktrees/<name>, so slashes would create nested directories
    // that don't exist. Replace them with dashes.
    let worktree_name = branch.replace('/', "-");

    // Check if branch exists, create if not
    let branch_exists = repo.find_branch(branch, git2::BranchType::Local).is_ok();

    if branch_exists {
        // Add worktree with existing branch
        repo.worktree(
            &worktree_name,
            worktree_path,
            Some(
                git2::WorktreeAddOptions::new().reference(Some(
                    &repo
                        .find_branch(branch, git2::BranchType::Local)?
                        .into_reference(),
                )),
            ),
        )?;
    } else {
        // Create branch from base_branch (default branch) rather than HEAD
        // This ensures griptrees start from a clean state, not from a feature branch
        let base_commit = if let Some(base) = base_branch {
            // Try local branch first, then remote tracking branch
            if let Ok(local_branch) = repo.find_branch(base, git2::BranchType::Local) {
                local_branch.get().peel_to_commit()?
            } else {
                // Try origin/<base>
                let remote_ref = format!("refs/remotes/origin/{}", base);
                repo.revparse_single(&remote_ref)?.peel_to_commit()?
            }
        } else {
            // Fall back to HEAD if no base branch specified
            repo.head()?.peel_to_commit()?
        };

        repo.branch(branch, &base_commit, false)?;

        repo.worktree(
            &worktree_name,
            worktree_path,
            Some(
                git2::WorktreeAddOptions::new().reference(Some(
                    &repo
                        .find_branch(branch, git2::BranchType::Local)?
                        .into_reference(),
                )),
            ),
        )?;
    }

    Ok(())
}

/// Sync reference repo with upstream default branch
fn sync_repo_with_upstream(repo_path: &PathBuf, default_branch: &str) -> anyhow::Result<()> {
    let repo = open_repo(repo_path)?;

    // Fetch from origin main to ensure up-to-date
    let mut remote = repo.find_remote("origin")?;
    remote.fetch(&[default_branch], None, None)?;

    // Reset main worktree HEAD to upstream default branch
    let upstream_ref = format!("refs/remotes/origin/{}", default_branch);
    let upstream_commit = repo.revparse_single(&upstream_ref)?.peel_to_commit()?;
    repo.reset(upstream_commit.as_object(), git2::ResetType::Hard, None)?;

    Ok(())
}

fn stash_repo(repo_path: &PathBuf, message: &str) -> anyhow::Result<bool> {
    let mut cmd = Command::new("git");
    cmd.args(["stash", "push", "-u", "-m", message])
        .current_dir(repo_path);
    log_cmd(&cmd);
    let output = cmd.output()?;
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    if !output.status.success() {
        return Err(anyhow::anyhow!("git stash failed: {}", stderr.trim()));
    }

    let combined = format!("{}{}", stdout, stderr);
    if combined.contains("No local changes to save") {
        return Ok(false);
    }

    Ok(true)
}

fn stash_pop_repo(repo_path: &PathBuf) -> anyhow::Result<()> {
    let mut cmd = Command::new("git");
    cmd.args(["stash", "pop"]).current_dir(repo_path);
    log_cmd(&cmd);
    let output = cmd.output()?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(anyhow::anyhow!("git stash pop failed: {}", stderr.trim()));
    }
    Ok(())
}

//! Verify command implementation
//!
//! Provides boolean pass/fail assertions for agents.
//! Exit code 0 = pass, 1 = fail. With --json, always exits 0
//! and puts pass/fail in the JSON body.

use crate::cli::output::Output;
use crate::core::manifest::Manifest;
use crate::core::repo::{filter_repos, RepoInfo};
use crate::git::path_exists;
use crate::git::status::get_repo_status;
use std::path::PathBuf;

/// JSON-serializable verification result
#[derive(serde::Serialize)]
struct VerifyResult {
    pass: bool,
    checks: Vec<CheckResult>,
}

/// JSON-serializable individual check result
#[derive(serde::Serialize)]
struct CheckResult {
    name: String,
    pass: bool,
    details: Vec<serde_json::Value>,
}

/// Options for the verify command
pub struct VerifyOptions<'a> {
    pub workspace_root: &'a PathBuf,
    pub manifest: &'a Manifest,
    pub group_filter: Option<&'a [String]>,
    pub json: bool,
    pub quiet: bool,
    pub clean: bool,
    pub links: bool,
    pub on_branch: Option<&'a str>,
    pub synced: bool,
}

/// Run the verify command
pub fn run_verify(opts: VerifyOptions) -> anyhow::Result<()> {
    let has_any_check = opts.clean || opts.links || opts.on_branch.is_some() || opts.synced;

    if !has_any_check {
        if opts.json {
            let result = VerifyResult {
                pass: false,
                checks: vec![CheckResult {
                    name: "no-checks".to_string(),
                    pass: false,
                    details: vec![serde_json::json!({
                        "error": "No verification flags provided. Use --clean, --links, --on-branch, or --synced."
                    })],
                }],
            };
            println!("{}", serde_json::to_string_pretty(&result)?);
            return Ok(());
        }
        anyhow::bail!(
            "No verification flags provided. Use --clean, --links, --on-branch, or --synced."
        );
    }

    let repos: Vec<RepoInfo> = filter_repos(
        opts.manifest,
        opts.workspace_root,
        None,
        opts.group_filter,
        false,
    );

    let mut all_checks: Vec<CheckResult> = Vec::new();

    if opts.clean {
        all_checks.push(check_clean(&repos));
    }

    if opts.links {
        all_checks.push(check_links(opts.workspace_root, opts.manifest));
    }

    if let Some(branch) = opts.on_branch {
        all_checks.push(check_on_branch(&repos, branch));
    }

    if opts.synced {
        all_checks.push(check_synced(&repos));
    }

    let all_pass = all_checks.iter().all(|c| c.pass);

    if opts.json {
        let result = VerifyResult {
            pass: all_pass,
            checks: all_checks,
        };
        println!("{}", serde_json::to_string_pretty(&result)?);
        return Ok(());
    }

    // Human-readable output
    if !opts.quiet {
        Output::header("Verify");
        println!();
    }

    for check in &all_checks {
        if check.pass {
            Output::success(&format!("{}: passed", check.name));
        } else {
            Output::error(&format!("{}: failed", check.name));
            for detail in &check.details {
                if let Some(obj) = detail.as_object() {
                    let parts: Vec<String> = obj
                        .iter()
                        .map(|(k, v)| format!("{}={}", k, v.as_str().unwrap_or(&v.to_string())))
                        .collect();
                    println!("    {}", parts.join(", "));
                }
            }
        }
    }

    if !opts.quiet {
        println!();
    }

    if !all_pass {
        std::process::exit(1);
    }

    Ok(())
}

/// Check that all repos are clean (no uncommitted changes)
fn check_clean(repos: &[RepoInfo]) -> CheckResult {
    let mut details = Vec::new();
    let mut pass = true;

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            details.push(serde_json::json!({
                "repo": repo.name,
                "status": "not cloned"
            }));
            pass = false;
            continue;
        }

        let status = get_repo_status(repo);
        if !status.clean {
            details.push(serde_json::json!({
                "repo": repo.name,
                "staged": status.staged,
                "modified": status.modified,
                "untracked": status.untracked
            }));
            pass = false;
        }
    }

    CheckResult {
        name: "clean".to_string(),
        pass,
        details,
    }
}

/// Check that all file links (copyfile/linkfile) are valid
fn check_links(workspace_root: &PathBuf, manifest: &Manifest) -> CheckResult {
    let mut details = Vec::new();
    let mut broken = 0;

    let repos: Vec<RepoInfo> = manifest
        .repos
        .iter()
        .filter_map(|(name, config)| RepoInfo::from_config(name, config, workspace_root))
        .collect();

    for (name, config) in &manifest.repos {
        let repo = repos.iter().find(|r| &r.name == name);

        if let Some(ref copyfiles) = config.copyfile {
            for copyfile in copyfiles {
                let source = repo
                    .map(|r| r.absolute_path.join(&copyfile.src))
                    .unwrap_or_else(|| workspace_root.join(&config.path).join(&copyfile.src));
                let dest = workspace_root.join(&copyfile.dest);

                if !source.exists() || !dest.exists() {
                    broken += 1;
                    let reason = if !source.exists() {
                        "source missing"
                    } else {
                        "dest missing"
                    };
                    details.push(serde_json::json!({
                        "type": "copyfile",
                        "src": copyfile.src,
                        "dest": copyfile.dest,
                        "reason": reason
                    }));
                }
            }
        }

        if let Some(ref linkfiles) = config.linkfile {
            for linkfile in linkfiles {
                let source = repo
                    .map(|r| r.absolute_path.join(&linkfile.src))
                    .unwrap_or_else(|| workspace_root.join(&config.path).join(&linkfile.src));
                let dest = workspace_root.join(&linkfile.dest);

                let is_valid = source.exists() && dest.exists() && dest.is_symlink();
                if !is_valid {
                    broken += 1;
                    let reason = if !source.exists() {
                        "source missing"
                    } else if !dest.exists() {
                        "link missing"
                    } else {
                        "not a symlink"
                    };
                    details.push(serde_json::json!({
                        "type": "linkfile",
                        "src": linkfile.src,
                        "dest": linkfile.dest,
                        "reason": reason
                    }));
                }
            }
        }
    }

    CheckResult {
        name: "links".to_string(),
        pass: broken == 0,
        details,
    }
}

/// Check that all non-reference repos are on the expected branch
fn check_on_branch(repos: &[RepoInfo], expected_branch: &str) -> CheckResult {
    let mut details = Vec::new();
    let mut pass = true;

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            continue;
        }

        let status = get_repo_status(repo);
        if status.branch != expected_branch {
            details.push(serde_json::json!({
                "repo": repo.name,
                "expected": expected_branch,
                "actual": status.branch
            }));
            pass = false;
        }
    }

    CheckResult {
        name: "on-branch".to_string(),
        pass,
        details,
    }
}

/// Check that all repos are synced with their remote (not ahead or behind)
fn check_synced(repos: &[RepoInfo]) -> CheckResult {
    let mut details = Vec::new();
    let mut pass = true;

    for repo in repos {
        if !path_exists(&repo.absolute_path) {
            details.push(serde_json::json!({
                "repo": repo.name,
                "status": "not cloned"
            }));
            pass = false;
            continue;
        }

        let status = get_repo_status(repo);
        if status.ahead > 0 || status.behind > 0 {
            details.push(serde_json::json!({
                "repo": repo.name,
                "ahead": status.ahead,
                "behind": status.behind
            }));
            pass = false;
        }
    }

    CheckResult {
        name: "synced".to_string(),
        pass,
        details,
    }
}

