    /// Return to the griptree base branch, sync, and optionally prune a branch
    Return {
        /// Override base branch (defaults to griptree config)
        #[arg(long)]
        base: Option<String>,
        /// Skip syncing after checkout
        #[arg(long)]
        no_sync: bool,
        /// Stash and restore local changes automatically
        #[arg(long)]
        autostash: bool,
        /// Prune this branch after returning
        #[arg(long)]
        prune: Option<String>,
        /// Prune the current branch (pre-return) after returning
        #[arg(long, conflicts_with = "prune")]
        prune_current: bool,
        /// Also prune the remote branch (origin)
        #[arg(long)]
        prune_remote: bool,
        /// Force delete local branches even if not merged
        #[arg(short, long)]
        force: bool,
    },
}

#[derive(Subcommand)]
enum GroupCommands {
    /// List all groups and their repos
    List,
    /// Add repo(s) to a group
    Add {
        /// Group name
        group: String,
        /// Repository names
        #[arg(required = true)]
        repos: Vec<String>,
    },
    /// Remove repo(s) from a group
    Remove {
        /// Group name
        group: String,
        /// Repository names
        #[arg(required = true)]
        repos: Vec<String>,
    },
    /// Create a new empty group (for documentation purposes)
    Create {
        /// Group name
        name: String,
    },
}

#[derive(Subcommand)]
enum CiCommands {
    /// Run a CI pipeline
    Run {
        /// Pipeline name
        name: String,
    },
    /// List available pipelines
    List,
    /// Show status of last CI runs
    Status,
}

#[derive(Subcommand)]
enum ManifestCommands {
    /// Convert git-repo XML manifest to gitgrip YAML
    Import {
        /// Path to XML manifest (e.g., .repo/manifests/default.xml)
        path: String,
        /// Output path for YAML manifest
        #[arg(short, long)]
        output: Option<String>,
    },
    /// Re-sync gitgrip YAML from .repo/ manifest after repo sync
    Sync,
    /// Show manifest schema specification
    Schema {
        /// Output format (yaml, json, markdown)
        #[arg(long, default_value = "yaml")]
        format: String,
    },
}

#[derive(Subcommand)]
enum RepoCommands {
    /// List repositories
    List,
    /// Add a repository
    Add {
        /// Repository URL
        url: String,
        /// Local path
        #[arg(short, long)]
        path: Option<String>,
        /// Default branch
        #[arg(short, long)]
        branch: Option<String>,
    },
    /// Remove a repository
    Remove {
        /// Repository name
        name: String,
        /// Delete files from disk
        #[arg(long)]
        delete: bool,
    },
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();

    // Initialize tracing — `--verbose` enables debug logging for gitgrip
    if cli.verbose {
        tracing_subscriber::fmt()
            .with_env_filter("gitgrip=debug")
            .with_target(false)
            .init();
    } else {
        tracing_subscriber::fmt()
            .with_env_filter(tracing_subscriber::EnvFilter::from_default_env())
            .init();
    }

    // Extract Copy flags before match moves cli.command
    let cli_quiet = cli.quiet;
    let cli_verbose = cli.verbose;
    let cli_json = cli.json;

    match cli.command {
        Some(Commands::Status { verbose, group }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::status::run_status(
                &ctx.workspace_root,
                &ctx.manifest,
                verbose,
                ctx.quiet,
                group.as_deref(),
                ctx.json,
            )?;
        }
        Some(Commands::Sync {
            force,
            reset_refs,
            group,
            sequential,
            no_hooks,
            rollback,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            if rollback {
                gitgrip::cli::commands::sync::run_sync_rollback(
                    &ctx.workspace_root,
                    &ctx.manifest,
                    ctx.quiet,
                    ctx.json,
                )
                .await?;
            } else {
                gitgrip::cli::commands::sync::run_sync(
                    &ctx.workspace_root,
                    &ctx.manifest,
                    force,
                    ctx.quiet,
                    group.as_deref(),
                    sequential,
                    reset_refs,
                    ctx.json,
                    no_hooks,
                )
                .await?;
            }
        }
        Some(Commands::Branch {
            name,
            delete,
            r#move,
            repo,
            include_manifest: _,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::branch::run_branch(
                gitgrip::cli::commands::branch::BranchOptions {
                    workspace_root: &ctx.workspace_root,
                    manifest: &ctx.manifest,
                    name: name.as_deref(),
                    delete,
                    move_commits: r#move,
                    repos_filter: repo.as_deref(),
                    group_filter: group.as_deref(),
                    json: ctx.json,
                },
            )?;
        }
        Some(Commands::Checkout { name, create, base }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            let branch = if base {
                let config = gitgrip::core::griptree::GriptreeConfig::load_from_workspace(
                    &ctx.workspace_root,
                )?
                .ok_or_else(|| anyhow::anyhow!("Not in a griptree workspace"))?;
                config.branch
            } else {
                name.ok_or_else(|| anyhow::anyhow!("Branch name is required"))?
            };

            gitgrip::cli::commands::checkout::run_checkout(
                &ctx.workspace_root,
                &ctx.manifest,
                &branch,
                create,
            )?;
        }
        Some(Commands::Add { files }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::add::run_add(&ctx.workspace_root, &ctx.manifest, &files)?;
        }
        Some(Commands::Diff { staged }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::diff::run_diff(
                &ctx.workspace_root,
                &ctx.manifest,
                staged,
                ctx.json,
            )?;
        }
        Some(Commands::Commit { message, amend }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            let msg = message.unwrap_or_else(|| {
                eprintln!("Error: commit message required (-m)");
                std::process::exit(1);
            });
            gitgrip::cli::commands::commit::run_commit(
                &ctx.workspace_root,
                &ctx.manifest,
                &msg,
                amend,
                ctx.json,
            )?;
        }
        Some(Commands::Push {
            set_upstream,
            force,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::push::run_push(
                &ctx.workspace_root,
                &ctx.manifest,
                set_upstream,
                force,
                ctx.quiet,
                ctx.json,
            )?;
        }
        Some(Commands::Prune {
            execute,
            remote,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::prune::run_prune(
                &ctx.workspace_root,
                &ctx.manifest,
                execute,
                remote,
                group.as_deref(),
            )?;
        }
        Some(Commands::Pr { action }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            match action {
                PrCommands::Create {
                    title,
                    body,
                    push,
                    draft,
                    dry_run,
                } => {
                    gitgrip::cli::commands::pr::run_pr_create(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        title.as_deref(),
                        body.as_deref(),
                        draft,
                        push,
                        dry_run,
                        ctx.json,
                    )
                    .await?;
                }
                PrCommands::Status => {
                    gitgrip::cli::commands::pr::run_pr_status(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        ctx.json,
                    )
                    .await?;
                }
                PrCommands::Merge {
                    method,
                    force,
                    update,
                    auto,
                    wait,
                    timeout,
                } => {
                    gitgrip::cli::commands::pr::run_pr_merge(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        method.as_deref(),
                        force,
                        update,
                        auto,
                        ctx.json,
                        wait,
                        timeout,
                    )
                    .await?;
                }
                PrCommands::Checks => {
                    gitgrip::cli::commands::pr::run_pr_checks(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        ctx.json,
                    )
                    .await?;
                }
                PrCommands::Diff { stat } => {
                    gitgrip::cli::commands::pr::run_pr_diff(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        stat,
                    )
                    .await?;
                }
            }
        }
        Some(Commands::Init {
            url,
            path,
            from_dirs,
            dirs,
            interactive,
            create_manifest,
            manifest_name,
            private,
            from_repo,
        }) => {
            gitgrip::cli::commands::init::run_init(gitgrip::cli::commands::init::InitOptions {
                url: url.as_deref(),
                path: path.as_deref(),
                from_dirs,
                dirs: &dirs,
                interactive,
                create_manifest,
                manifest_name: manifest_name.as_deref(),
                private,
                from_repo,
            })
            .await?;
        }
        Some(Commands::Tree { action }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            match action {
                TreeCommands::Add { branch } => {
                    gitgrip::cli::commands::tree::run_tree_add(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        &branch,
                    )?;
                }
                TreeCommands::List => {
                    gitgrip::cli::commands::tree::run_tree_list(&ctx.workspace_root)?;
                }
                TreeCommands::Remove { branch, force } => {
                    gitgrip::cli::commands::tree::run_tree_remove(
                        &ctx.workspace_root,
                        &branch,
                        force,
                    )?;
                }
                TreeCommands::Lock { branch, reason } => {
                    gitgrip::cli::commands::tree::run_tree_lock(
                        &ctx.workspace_root,
                        &branch,
                        reason.as_deref(),
                    )?;
                }
                TreeCommands::Unlock { branch } => {
                    gitgrip::cli::commands::tree::run_tree_unlock(&ctx.workspace_root, &branch)?;
                }
                TreeCommands::Return {
                    base,
                    no_sync,
                    autostash,
                    prune,
                    prune_current,
                    prune_remote,
                    force,
                } => {
                    gitgrip::cli::commands::tree::run_tree_return(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        base.as_deref(),
                        no_sync,
                        autostash,
                        prune.as_deref(),
                        prune_current,
                        prune_remote,
                        force,
                    )
                    .await?;
                }
            }
        }
        Some(Commands::Grep {
            pattern,
            ignore_case,
            parallel,
            pathspec,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::grep::run_grep(
                &ctx.workspace_root,
                &ctx.manifest,
                &pattern,
                ignore_case,
                parallel,
                &pathspec,
                group.as_deref(),
            )?;
        }
        Some(Commands::Forall {
            command,
            parallel,
            all,
            no_intercept,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::forall::run_forall(
                &ctx.workspace_root,
                &ctx.manifest,
                &command,
                parallel,
                !all, // Default: only repos with changes (changed_only=true unless --all)
                no_intercept,
                group.as_deref(),
            )?;
        }
        Some(Commands::Rebase {
            onto,
            upstream,
            abort,
            continue_rebase,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::rebase::run_rebase(
                &ctx.workspace_root,
                &ctx.manifest,
                onto.as_deref(),
                upstream,
                abort,
                continue_rebase,
            )?;
        }
        Some(Commands::Pull {
            rebase,
            group,
            sequential,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::pull::run_pull(
                &ctx.workspace_root,
                &ctx.manifest,
                rebase,
                group.as_deref(),
                sequential,
                ctx.quiet,
            )
            .await?;
        }
        Some(Commands::Link { status, apply }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::link::run_link(
                &ctx.workspace_root,
                &ctx.manifest,
                status,
                apply,
                ctx.json,
            )?;
        }
        Some(Commands::Run { name, list }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::run::run_run(
                &ctx.workspace_root,
                &ctx.manifest,
                name.as_deref(),
                list,
            )?;
        }
        Some(Commands::Env) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::env::run_env(&ctx.workspace_root, &ctx.manifest)?;
        }
        Some(Commands::Repo { action }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            match action {
                RepoCommands::List => {
                    gitgrip::cli::commands::repo::run_repo_list(
                        &ctx.workspace_root,
                        &ctx.manifest,
                    )?;
                }
                RepoCommands::Add { url, path, branch } => {
                    gitgrip::cli::commands::repo::run_repo_add(
                        &ctx.workspace_root,
                        &url,
                        path.as_deref(),
                        branch.as_deref(),
                    )?;
                }
                RepoCommands::Remove { name, delete } => {
                    gitgrip::cli::commands::repo::run_repo_remove(
                        &ctx.workspace_root,
                        &name,
                        delete,
                    )?;
                }
            }
        }
        Some(Commands::Group { action }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            match action {
                GroupCommands::List => {
                    gitgrip::cli::commands::group::run_group_list(
                        &ctx.workspace_root,
                        &ctx.manifest,
                    )?;
                }
                GroupCommands::Add { group, repos } => {
                    gitgrip::cli::commands::group::run_group_add(
                        &ctx.workspace_root,
                        &group,
                        &repos,
                    )?;
                }
                GroupCommands::Remove { group, repos } => {
                    gitgrip::cli::commands::group::run_group_remove(
                        &ctx.workspace_root,
                        &group,
                        &repos,
                    )?;
                }
                GroupCommands::Create { name } => {
                    gitgrip::cli::commands::group::run_group_create(&ctx.workspace_root, &name)?;
                }
            }
        }
        Some(Commands::Gc {
            aggressive,
            dry_run,
            repo,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::gc::run_gc(
                &ctx.workspace_root,
                &ctx.manifest,
                aggressive,
                dry_run,
                repo.as_deref(),
                group.as_deref(),
            )?;
        }
        Some(Commands::CherryPick {
            commit,
            abort,
            continue_pick,
            repo,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::cherry_pick::run_cherry_pick(
                &ctx.workspace_root,
                &ctx.manifest,
                commit.as_deref(),
                abort,
                continue_pick,
                repo.as_deref(),
                group.as_deref(),
            )?;
        }
        Some(Commands::Ci { action }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            match action {
                CiCommands::Run { name } => {
                    gitgrip::cli::commands::ci::run_ci_run(
                        &ctx.workspace_root,
                        &ctx.manifest,
