                    )?;
                }
                AgentCommands::Build { repo } => {
                    gitgrip::cli::commands::agent::run_agent_build(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        repo.as_deref(),
                    )?;
                }
                AgentCommands::Test { repo } => {
                    gitgrip::cli::commands::agent::run_agent_test(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        repo.as_deref(),
                    )?;
                }
                AgentCommands::Verify { repo } => {
                    gitgrip::cli::commands::agent::run_agent_verify(
                        &ctx.workspace_root,
                        &ctx.manifest,
                        repo.as_deref(),
                    )?;
