            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::release::run_release(
                gitgrip::cli::commands::release::ReleaseOptions {
                    workspace_root: &ctx.workspace_root,
