                    dry_run,
                    skip_pr,
                    target_repo: repo.as_deref(),
                    json: ctx.json,
                    quiet: ctx.quiet,
                    timeout,
                },
            )
            .await?;
        }
        Some(Commands::Completions { shell }) => {
            let mut cmd = Cli::command();
            generate(shell, &mut cmd, "gr", &mut std::io::stdout());
        }
        Some(Commands::Verify {
            clean,
            links,
            on_branch,
            synced,
            group,
        }) => {
            let ctx = load_workspace_context(cli_quiet, cli_verbose, cli_json)?;
            gitgrip::cli::commands::verify::run_verify(
                gitgrip::cli::commands::verify::VerifyOptions {
                    workspace_root: &ctx.workspace_root,
                    manifest: &ctx.manifest,
                    group_filter: group.as_deref(),
                    json: ctx.json,
                    quiet: ctx.quiet,
                    clean,
                    links,
                    on_branch: on_branch.as_deref(),
                    synced,
                },
            )?;
        }
        None => {
            let logo = r#"
                *    *
           *    |    |
           |    |    |
      *    |    |    |
      |    \    \    \
       \    \    \    \       *
        *    *    *    *       \
         \    \    \    \      *
          \    \    \    \    /
           *----*----*----*--*
            \        |      /
             \       |     /
              *------*----*
"#;
            let wordmark = r#"
        __ _ _ _              _
       / _` (_) |_ __ _ _ _ _(_)_ __
      | (_| | |  _/ _` | '_| | '_ \
       \__, |_|\__\__, |_| |_| .__/
       |___/      |___/      |_|
"#;
            print!("{}", logo.truecolor(251, 146, 60));
            print!("{}", wordmark.bold());
            println!("{}", "              git a grip.".truecolor(251, 146, 60));
            println!();
            println!("  Run {} for usage", "'gr --help'".dimmed());
        }
    }

    Ok(())
}

/// Load the gripspace manifest
fn load_gripspace() -> anyhow::Result<(std::path::PathBuf, gitgrip::core::manifest::Manifest)> {
    let current = std::env::current_dir()?;

    // First, check if we're in a griptree (has .griptree pointer file)
    if let Some((griptree_path, pointer)) =
        gitgrip::core::griptree::GriptreePointer::find_in_ancestors(&current)
    {
        return load_from_griptree(&griptree_path, &pointer);
    }

    // Not in a griptree - search parent directories for workspace root
    load_from_workspace(&current)
}

/// Load the gripspace manifest and return a WorkspaceContext with global CLI flags.
fn load_workspace_context(
    quiet: bool,
    verbose: bool,
    json: bool,
) -> anyhow::Result<gitgrip::cli::context::WorkspaceContext> {
    let (workspace_root, manifest) = load_gripspace()?;
    Ok(gitgrip::cli::context::WorkspaceContext::new(
        workspace_root,
        manifest,
        quiet,
        verbose,
        json,
    ))
}

/// Load manifest from a griptree workspace.
fn load_from_griptree(
    griptree_path: &std::path::Path,
    pointer: &gitgrip::core::griptree::GriptreePointer,
) -> anyhow::Result<(std::path::PathBuf, gitgrip::core::manifest::Manifest)> {
    let griptree_manifest_path =
        gitgrip::core::manifest_paths::resolve_gripspace_manifest_path(griptree_path);

    let content = if let Some(path) = griptree_manifest_path {
        std::fs::read_to_string(path)?
    } else {
        let main_workspace = std::path::PathBuf::from(&pointer.main_workspace);
        let main_manifest_path =
            gitgrip::core::manifest_paths::resolve_gripspace_manifest_path(&main_workspace);

        let main_path = main_manifest_path.ok_or_else(|| {
            anyhow::anyhow!(
                "Griptree points to main workspace '{}' but no gripspace manifest was found",
                pointer.main_workspace
            )
        })?;
        std::fs::read_to_string(main_path)?
    };

    let mut manifest = gitgrip::core::manifest::Manifest::parse(&content)?;
    resolve_gripspace_includes(&mut manifest, griptree_path);
    Ok((griptree_path.to_path_buf(), manifest))
}

/// Search parent directories for a workspace root and load its manifest.
fn load_from_workspace(
    start: &std::path::Path,
) -> anyhow::Result<(std::path::PathBuf, gitgrip::core::manifest::Manifest)> {
    let mut search_path = start.to_path_buf();
    loop {
        // Check for .gitgrip directory with gripspace manifest
        let gitgrip_dir = search_path.join(".gitgrip");
        if gitgrip_dir.exists() {
            if let Some(manifest_path) =
                gitgrip::core::manifest_paths::resolve_gripspace_manifest_path(&search_path)
            {
                let content = std::fs::read_to_string(&manifest_path)?;
                let mut manifest = gitgrip::core::manifest::Manifest::parse(&content)?;
                resolve_gripspace_includes(&mut manifest, &search_path);
                return Ok((search_path, manifest));
            }
        }

        // Check for legacy repo.yaml
        if let Some(repo_yaml) =
            gitgrip::core::manifest_paths::resolve_repo_manifest_path(&search_path)
        {
            let content = std::fs::read_to_string(repo_yaml)?;
            let mut manifest = gitgrip::core::manifest::Manifest::parse(&content)?;
            resolve_gripspace_includes(&mut manifest, &search_path);
            return Ok((search_path, manifest));
        }

        // Fallback: parse .repo/manifest.xml directly (zero-config — just works)
        let repo_xml = search_path.join(".repo").join("manifest.xml");
        if repo_xml.exists() {
            let xml_manifest = gitgrip::core::repo_manifest::XmlManifest::parse_file(&repo_xml)?;
            let result = xml_manifest.to_manifest()?;
            return Ok((search_path, result.manifest));
        }

        match search_path.parent() {
            Some(parent) => search_path = parent.to_path_buf(),
            None => {
                anyhow::bail!("Not in a gitgrip workspace (no .gitgrip or .repo directory found)");
            }
        }
    }
}

/// Resolve gripspace includes (merge inherited repos/scripts/env/hooks) if spaces dir exists.
fn resolve_gripspace_includes(
    manifest: &mut gitgrip::core::manifest::Manifest,
    workspace_root: &std::path::Path,
) {
    let spaces_dir = gitgrip::core::manifest_paths::spaces_dir(workspace_root);
    if spaces_dir.exists() {
        let _ = gitgrip::core::gripspace::resolve_all_gripspaces(manifest, &spaces_dir);
    }
}

//! Azure DevOps platform adapter

use async_trait::async_trait;
use base64::{engine::general_purpose::STANDARD, Engine};
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::time::Duration;

use super::traits::{HostingPlatform, LinkedPRRef, PlatformError};
use super::types::*;
use crate::core::manifest::PlatformType;
use tracing::debug;

/// Default connection timeout in seconds
const CONNECT_TIMEOUT_SECS: u64 = 10;
/// Default request timeout in seconds
const REQUEST_TIMEOUT_SECS: u64 = 30;

/// Azure DevOps context parsed from URL
#[derive(Debug, Clone)]
struct AzureContext {
    organization: String,
    project: String,
    repository: String,
}

/// Azure DevOps pull request response
#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
struct AzurePullRequest {
    pull_request_id: u64,
    title: String,
    description: Option<String>,
    status: String, // active, abandoned, completed
    merge_status: Option<String>,
    source_ref_name: String,
    target_ref_name: String,
    last_merge_source_commit: Option<AzureCommit>,
}

#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
struct AzureCommit {
    commit_id: String,
}

/// Azure DevOps reviewer
#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
struct AzureReviewer {
    vote: i32, // 10 = approved, -10 = rejected, 0 = no vote, 5 = approved with suggestions, -5 = waiting for author
    display_name: Option<String>,
    unique_name: Option<String>,
}

/// Azure DevOps build
#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
struct AzureBuild {
    result: Option<String>,
    status: String,
}

/// List response wrapper
#[derive(Debug, Deserialize)]
struct ListResponse<T> {
    value: Vec<T>,
}

/// PR with reviewers
#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
struct AzurePullRequestWithReviewers {
    reviewers: Option<Vec<AzureReviewer>>,
}

/// Azure DevOps API adapter
pub struct AzureDevOpsAdapter {
    base_url: String,
    http_client: Client,
}

impl AzureDevOpsAdapter {
    /// Create a new Azure DevOps adapter
    pub fn new(base_url: Option<&str>) -> Self {
        let http_client = Client::builder()
            .connect_timeout(Duration::from_secs(CONNECT_TIMEOUT_SECS))
            .timeout(Duration::from_secs(REQUEST_TIMEOUT_SECS))
            .build()
            .unwrap_or_else(|_| Client::new());

        Self {
            base_url: base_url.unwrap_or("https://dev.azure.com").to_string(),
            http_client,
        }
    }

    /// Parse Azure DevOps context from owner string
    /// Format: "org/project" where owner is org and repo is separate
    fn parse_context(&self, owner: &str, repo: &str) -> AzureContext {
        let parts: Vec<&str> = owner.split('/').collect();
        if parts.len() >= 2 {
            AzureContext {
                organization: parts[0].to_string(),
                project: parts[1..].join("/"),
                repository: repo.to_string(),
            }
        } else {
            // Fallback: owner is org, use repo as both project and repo
            AzureContext {
                organization: owner.to_string(),
                project: repo.to_string(),
                repository: repo.to_string(),
            }
        }
    }

    /// Make authenticated API request
    async fn api_request<T: for<'de> Deserialize<'de>>(
        &self,
        method: reqwest::Method,
        ctx: &AzureContext,
        endpoint: &str,
        body: Option<impl Serialize>,
    ) -> Result<T, PlatformError> {
        let token = self.get_token().await?;
        let url = format!(
            "{}/{}/{}/_apis{}?api-version=7.0",
            self.base_url, ctx.organization, ctx.project, endpoint
        );

        // Azure DevOps uses Basic auth with PAT (username can be empty)
        let auth = STANDARD.encode(format!(":{}", token));

        let mut request = self
            .http_client
            .request(method, &url)
            .header("Authorization", format!("Basic {}", auth))
            .header("Content-Type", "application/json");

        if let Some(b) = body {
            request = request.json(&b);
        }

        let response = request
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Azure DevOps API error ({}): {}",
                status, error_text
            )));
        }

        response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))
    }

    /// Make PATCH request (used for updates)
    async fn api_patch(
        &self,
        ctx: &AzureContext,
        endpoint: &str,
        body: impl Serialize,
    ) -> Result<(), PlatformError> {
        let token = self.get_token().await?;
        let url = format!(
            "{}/{}/{}/_apis{}?api-version=7.0",
            self.base_url, ctx.organization, ctx.project, endpoint
        );

        let auth = STANDARD.encode(format!(":{}", token));

        let response = self
            .http_client
            .patch(&url)
            .header("Authorization", format!("Basic {}", auth))
            .header("Content-Type", "application/json")
            .json(&body)
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Azure DevOps API error ({}): {}",
                status, error_text
            )));
        }

        Ok(())
    }

    /// Build PR web URL
    fn build_pr_url(&self, ctx: &AzureContext, pr_id: u64) -> String {
        format!(
            "{}/{}/{}/_git/{}/pullrequest/{}",
            self.base_url, ctx.organization, ctx.project, ctx.repository, pr_id
        )
    }
}

#[async_trait]
impl HostingPlatform for AzureDevOpsAdapter {
    fn platform_type(&self) -> PlatformType {
        PlatformType::AzureDevOps
    }

    async fn get_token(&self) -> Result<String, PlatformError> {
        // Try environment variables first
        if let Ok(token) = env::var("AZURE_DEVOPS_TOKEN") {
            return Ok(token);
        }
        if let Ok(token) = env::var("AZURE_DEVOPS_EXT_PAT") {
            return Ok(token);
        }

        // Try az CLI to get access token
        debug!(target: "gitgrip::cmd", program = "az", args = ?["account", "get-access-token", "--resource", "499b84ac-1321-427f-aa17-267ca6975798", "--query", "accessToken", "-o", "tsv"], "exec");
        let output = tokio::process::Command::new("az")
            .args([
                "account",
                "get-access-token",
                "--resource",
                "499b84ac-1321-427f-aa17-267ca6975798",
                "--query",
                "accessToken",
                "-o",
                "tsv",
            ])
            .output()
            .await;

        if let Ok(output) = output {
            if output.status.success() {
                let token = String::from_utf8_lossy(&output.stdout).trim().to_string();
                if !token.is_empty() {
                    return Ok(token);
                }
            }
        }

        Err(PlatformError::AuthError(
            "Azure DevOps token not found. Set AZURE_DEVOPS_TOKEN or use 'az login'".to_string(),
        ))
    }

    async fn create_pull_request(
        &self,
        owner: &str,
        repo: &str,
        head: &str,
        base: &str,
        title: &str,
        body: Option<&str>,
        draft: bool,
    ) -> Result<PRCreateResult, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        #[derive(Serialize)]
        #[serde(rename_all = "camelCase")]
        struct CreatePR {
            source_ref_name: String,
            target_ref_name: String,
            title: String,
            description: String,
            is_draft: bool,
        }

        let pr: AzurePullRequest = self
            .api_request(
                reqwest::Method::POST,
                &ctx,
                &format!("/git/repositories/{}/pullrequests", ctx.repository),
                Some(CreatePR {
                    source_ref_name: format!("refs/heads/{}", head),
                    target_ref_name: format!("refs/heads/{}", base),
                    title: title.to_string(),
                    description: body.unwrap_or("").to_string(),
                    is_draft: draft,
                }),
            )
            .await?;

        Ok(PRCreateResult {
            number: pr.pull_request_id,
            url: self.build_pr_url(&ctx, pr.pull_request_id),
        })
    }

    async fn get_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<PullRequest, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        let pr: AzurePullRequest = self
            .api_request(
                reqwest::Method::GET,
                &ctx,
                &format!(
                    "/git/repositories/{}/pullrequests/{}",
                    ctx.repository, pull_number
                ),
                None::<()>,
            )
            .await?;

        // Map Azure DevOps status to our unified state
        let (state, merged) = match pr.status.as_str() {
            "completed" => {
                let merged = pr.merge_status.as_deref() == Some("succeeded");
                (
                    if merged {
                        PRState::Merged
                    } else {
                        PRState::Closed
                    },
                    merged,
                )
            }
            "abandoned" => (PRState::Closed, false),
            _ => (PRState::Open, false),
        };

        let mergeable = matches!(
            pr.merge_status.as_deref(),
            Some("succeeded") | Some("queued")
        );

        Ok(PullRequest {
            number: pr.pull_request_id,
            url: self.build_pr_url(&ctx, pr.pull_request_id),
            title: pr.title,
            body: pr.description.unwrap_or_default(),
            state,
            merged,
            mergeable: Some(mergeable),
            head: PRHead {
                ref_name: pr.source_ref_name.replace("refs/heads/", ""),
                sha: pr
                    .last_merge_source_commit
                    .map(|c| c.commit_id)
                    .unwrap_or_default(),
            },
            base: PRBase {
                ref_name: pr.target_ref_name.replace("refs/heads/", ""),
            },
        })
    }

    async fn update_pull_request_body(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        body: &str,
    ) -> Result<(), PlatformError> {
        let ctx = self.parse_context(owner, repo);

        #[derive(Serialize)]
        struct UpdateBody {
            description: String,
        }

        self.api_patch(
            &ctx,
            &format!(
                "/git/repositories/{}/pullrequests/{}",
                ctx.repository, pull_number
            ),
            UpdateBody {
                description: body.to_string(),
            },
        )
        .await
    }

    async fn merge_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        method: Option<MergeMethod>,
        delete_branch: bool,
    ) -> Result<bool, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        // Get current PR to get the last merge source commit
        let pr = self.get_pull_request(owner, repo, pull_number).await?;

        #[derive(Serialize)]
        #[serde(rename_all = "camelCase")]
        struct CompletionOptions {
            #[serde(skip_serializing_if = "Option::is_none")]
            delete_source_branch: Option<bool>,
            #[serde(skip_serializing_if = "Option::is_none")]
            merge_strategy: Option<String>,
            #[serde(skip_serializing_if = "Option::is_none")]
            squash_merge: Option<bool>,
        }

        #[derive(Serialize)]
        #[serde(rename_all = "camelCase")]
        struct CompletePR {
            status: String,
            last_merge_source_commit: LastMergeCommit,
            completion_options: CompletionOptions,
        }

        #[derive(Serialize)]
        #[serde(rename_all = "camelCase")]
        struct LastMergeCommit {
            commit_id: String,
        }

        let mut completion_options = CompletionOptions {
            delete_source_branch: if delete_branch { Some(true) } else { None },
            merge_strategy: None,
            squash_merge: None,
        };

        match method {
            Some(MergeMethod::Squash) => {
                completion_options.squash_merge = Some(true);
            }
            Some(MergeMethod::Rebase) => {
                completion_options.merge_strategy = Some("rebase".to_string());
            }
            _ => {}
        }

        let result = self
            .api_patch(
                &ctx,
                &format!(
                    "/git/repositories/{}/pullrequests/{}",
                    ctx.repository, pull_number
                ),
                CompletePR {
                    status: "completed".to_string(),
                    last_merge_source_commit: LastMergeCommit {
                        commit_id: pr.head.sha,
                    },
                    completion_options,
                },
            )
            .await;

        match result {
            Ok(()) => Ok(true),
            Err(_) => Ok(false),
        }
    }

    async fn find_pr_by_branch(
        &self,
        owner: &str,
        repo: &str,
        branch: &str,
    ) -> Result<Option<PRCreateResult>, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        let response: ListResponse<AzurePullRequest> = self
            .api_request(
                reqwest::Method::GET,
                &ctx,
                &format!(
                    "/git/repositories/{}/pullrequests?searchCriteria.sourceRefName=refs/heads/{}&searchCriteria.status=active",
                    ctx.repository,
                    urlencoding::encode(branch)
                ),
                None::<()>,
            )
            .await?;

        if let Some(pr) = response.value.first() {
            Ok(Some(PRCreateResult {
                number: pr.pull_request_id,
                url: self.build_pr_url(&ctx, pr.pull_request_id),
            }))
        } else {
            Ok(None)
        }
    }

    async fn is_pull_request_approved(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<bool, PlatformError> {
        let reviews = self
            .get_pull_request_reviews(owner, repo, pull_number)
            .await?;

        // Azure DevOps: vote 10 = approved, 5 = approved with suggestions
        let has_approval = reviews
            .iter()
            .any(|r| r.state == "APPROVED" || r.state == "APPROVED_WITH_SUGGESTIONS");
        let has_rejection = reviews
            .iter()
            .any(|r| r.state == "REJECTED" || r.state == "WAITING_FOR_AUTHOR");

        Ok(has_approval && !has_rejection)
    }

    async fn get_pull_request_reviews(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<Vec<PRReview>, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        let pr: AzurePullRequestWithReviewers = self
            .api_request(
                reqwest::Method::GET,
                &ctx,
                &format!(
                    "/git/repositories/{}/pullrequests/{}",
                    ctx.repository, pull_number
                ),
                None::<()>,
            )
            .await?;

        let reviewers = pr.reviewers.unwrap_or_default();

        Ok(reviewers
            .iter()
            .map(|r| {
                let state = match r.vote {
                    10 => "APPROVED",
                    5 => "APPROVED_WITH_SUGGESTIONS",
                    -10 => "REJECTED",
                    -5 => "WAITING_FOR_AUTHOR",
                    _ => "PENDING",
                };
                PRReview {
                    state: state.to_string(),
                    user: r
                        .display_name
                        .clone()
                        .or_else(|| r.unique_name.clone())
                        .unwrap_or_default(),
                }
            })
            .collect())
    }

    async fn get_status_checks(
        &self,
        owner: &str,
        repo: &str,
        _ref_name: &str,
    ) -> Result<StatusCheckResult, PlatformError> {
        let ctx = self.parse_context(owner, repo);

        // Get builds for this repository
        let result: Result<ListResponse<AzureBuild>, _> = self
            .api_request(
                reqwest::Method::GET,
                &ctx,
                &format!(
                    "/build/builds?repositoryId={}&repositoryType=TfsGit&$top=5",
                    ctx.repository
                ),
                None::<()>,
            )
            .await;

        match result {
            Ok(response) => {
                if response.value.is_empty() {
                    return Ok(StatusCheckResult {
                        state: CheckState::Success,
                        statuses: vec![],
                    });
                }

                let has_failure = response
                    .value
                    .iter()
                    .any(|b| matches!(b.result.as_deref(), Some("failed") | Some("canceled")));
                let has_in_progress = response.value.iter().any(|b| b.status != "completed");

                let state = if has_failure {
                    CheckState::Failure
                } else if has_in_progress {
                    CheckState::Pending
                } else {
                    CheckState::Success
                };

                let statuses = response
                    .value
                    .iter()
                    .map(|b| StatusCheck {
                        context: "azure-pipeline".to_string(),
                        state: b.result.clone().unwrap_or_else(|| b.status.clone()),
                    })
                    .collect();

                Ok(StatusCheckResult { state, statuses })
            }
            Err(_) => {
                // No builds or API error - assume success
                Ok(StatusCheckResult {
                    state: CheckState::Success,
                    statuses: vec![],
                })
            }
        }
    }

    async fn get_allowed_merge_methods(
        &self,
        _owner: &str,
        _repo: &str,
    ) -> Result<AllowedMergeMethods, PlatformError> {
        // Azure DevOps generally allows all merge methods
        Ok(AllowedMergeMethods {
            merge: true,
            squash: true,
            rebase: true,
        })
    }

    async fn get_pull_request_diff(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<String, PlatformError> {
        let ctx = self.parse_context(owner, repo);
        let token = self.get_token().await?;

        // Azure DevOps doesn't have a direct diff endpoint, so we get the commits
        // and generate a diff URL or message
        let url = format!(
            "{}/{}/{}/_apis/git/repositories/{}/pullRequests/{}/commits?api-version=7.0",
            self.base_url, ctx.organization, ctx.project, ctx.repository, pull_number
        );

        let auth = STANDARD.encode(format!(":{}", token));

        let response = self
            .http_client
            .get(&url)
            .header("Authorization", format!("Basic {}", auth))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            return Err(PlatformError::ApiError(format!(
                "Failed to get PR commits: {}",
                response.status()
            )));
        }

        #[derive(Deserialize)]
        #[serde(rename_all = "camelCase")]
        struct CommitInfo {
            commit_id: String,
            comment: Option<String>,
        }

        #[derive(Deserialize)]
        struct CommitsResponse {
            value: Vec<CommitInfo>,
        }

        let commits: CommitsResponse = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        // Build a summary of commits
        let mut diff = String::new();
        diff.push_str(&format!(
            "Pull Request #{} - {} commits\n\n",
            pull_number,
            commits.value.len()
        ));
        for commit in &commits.value {
            diff.push_str(&format!(
                "{}: {}\n",
                &commit.commit_id[..8.min(commit.commit_id.len())],
                commit.comment.as_deref().unwrap_or("(no message)")
            ));
        }

        Ok(diff)
    }

    fn parse_repo_url(&self, url: &str) -> Option<ParsedRepoInfo> {
        // SSH format: git@ssh.dev.azure.com:v3/org/project/repo
        if let Some(caps) = url.strip_prefix("git@ssh.dev.azure.com:v3/") {
            let parts: Vec<&str> = caps.trim_end_matches(".git").split('/').collect();
            if parts.len() >= 3 {
                return Some(ParsedRepoInfo {
                    owner: format!("{}/{}", parts[0], parts[1]),
                    repo: parts[2].to_string(),
                    project: Some(parts[1].to_string()),
                    platform: Some(PlatformType::AzureDevOps),
                });
            }
        }

        // HTTPS format: https://dev.azure.com/org/project/_git/repo
        if url.contains("dev.azure.com") {
            let parts: Vec<&str> = url.split('/').collect();
            if let Some(git_idx) = parts.iter().position(|&p| p == "_git") {
                if git_idx >= 2 && git_idx + 1 < parts.len() {
                    let org_idx = parts.iter().position(|&p| p == "dev.azure.com")? + 1;
                    if org_idx + 1 < git_idx {
                        return Some(ParsedRepoInfo {
                            owner: format!("{}/{}", parts[org_idx], parts[org_idx + 1]),
                            repo: parts[git_idx + 1].trim_end_matches(".git").to_string(),
                            project: Some(parts[org_idx + 1].to_string()),
                            platform: Some(PlatformType::AzureDevOps),
                        });
                    }
                }
            }
        }

        // Legacy visualstudio.com format: https://org.visualstudio.com/project/_git/repo
        if url.contains(".visualstudio.com") {
            let parts: Vec<&str> = url.split('/').collect();
            if let Some(git_idx) = parts.iter().position(|&p| p == "_git") {
                if git_idx >= 2 && git_idx + 1 < parts.len() {
                    // Extract org from hostname
                    if let Some(host_part) = parts.iter().find(|p| p.contains(".visualstudio.com"))
                    {
                        let org = host_part.split('.').next()?;
                        let project = parts[git_idx - 1];
                        return Some(ParsedRepoInfo {
                            owner: format!("{}/{}", org, project),
                            repo: parts[git_idx + 1].trim_end_matches(".git").to_string(),
                            project: Some(project.to_string()),
                            platform: Some(PlatformType::AzureDevOps),
                        });
                    }
                }
            }
        }

        None
    }

    fn matches_url(&self, url: &str) -> bool {
        url.contains("dev.azure.com")
            || url.contains("visualstudio.com")
            || url.contains("ssh.dev.azure.com")
    }

    async fn create_repository(
        &self,
        owner: &str,
        name: &str,
        _description: Option<&str>,
        _private: bool,
    ) -> Result<String, PlatformError> {
        // Azure DevOps owner format: org/project
        let ctx = self.parse_context(owner, name);

        #[derive(Serialize)]
        struct CreateRepoRequest {
            name: String,
        }

        #[derive(Deserialize)]
        #[serde(rename_all = "camelCase")]
        struct CreateRepoResponse {
            ssh_url: Option<String>,
            remote_url: Option<String>,
        }

        let response: CreateRepoResponse = self
            .api_request(
                reqwest::Method::POST,
                &ctx,
                "/git/repositories",
                Some(CreateRepoRequest {
                    name: name.to_string(),
                }),
            )
            .await?;

        // Prefer SSH URL, fall back to HTTPS
        let clone_url = response.ssh_url.or(response.remote_url).ok_or_else(|| {
            PlatformError::ParseError("No clone URL returned from Azure DevOps".to_string())
        })?;

        Ok(clone_url)
    }

    async fn delete_repository(&self, owner: &str, name: &str) -> Result<(), PlatformError> {
        let ctx = self.parse_context(owner, name);
        let token = self.get_token().await?;

        // First, get the repository ID
        #[derive(Deserialize)]
        #[serde(rename_all = "camelCase")]
        struct RepoInfo {
            id: String,
        }

        let repo_info: RepoInfo = self
            .api_request(
                reqwest::Method::GET,
                &ctx,
                &format!("/git/repositories/{}", ctx.repository),
                None::<()>,
            )
            .await?;

        // Delete the repository by ID
        let url = format!(
            "{}/{}/{}/_apis/git/repositories/{}?api-version=7.0",
            self.base_url, ctx.organization, ctx.project, repo_info.id
        );

        let auth = STANDARD.encode(format!(":{}", token));

        let response = self
            .http_client
            .delete(&url)
            .header("Authorization", format!("Basic {}", auth))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if response.status() == 404 {
            return Err(PlatformError::NotFound(format!(
                "Repository {} not found",
                name
            )));
        }

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to delete repository ({}): {}",
                status, error_text
            )));
        }

        Ok(())
    }

    fn generate_linked_pr_comment(&self, links: &[LinkedPRRef]) -> String {
        if links.is_empty() {
            return String::new();
        }

        let mut comment = String::from("<!-- gitgrip-linked-prs\n");
        for link in links {
            comment.push_str(&format!("{}:{}\n", link.repo_name, link.number));
        }
        comment.push_str("-->");
        comment
    }

    fn parse_linked_pr_comment(&self, body: &str) -> Vec<LinkedPRRef> {
        let start_marker = "<!-- gitgrip-linked-prs";
        let end_marker = "-->";

        let Some(start) = body.find(start_marker) else {
            return Vec::new();
        };

        let content_start = start + start_marker.len();
        let Some(end) = body[content_start..].find(end_marker) else {
            return Vec::new();
        };

        let content = &body[content_start..content_start + end];

        content
            .lines()
            .filter_map(|line| {
                let line = line.trim();
                if line.is_empty() {
                    return None;
                }

                let parts: Vec<&str> = line.splitn(2, ':').collect();
                if parts.len() != 2 {
                    return None;
                }

                let number = parts[1].parse().ok()?;
                Some(LinkedPRRef {
                    repo_name: parts[0].to_string(),
                    number,
                })
            })
            .collect()
    }
}

