            },
        ];
        let comment = adapter.generate_linked_pr_comment(&links);
        assert!(comment.contains("frontend#42"));
        assert!(comment.contains("backend#99"));
    }

    #[test]
    fn test_parse_linked_pr_comment() {
        let adapter = BitbucketAdapter::new(None);
        let parsed = adapter.parse_linked_pr_comment("Linked PRs: frontend#42, backend#99");
        assert_eq!(parsed.len(), 2);
        assert_eq!(parsed[0].repo_name, "frontend");
        assert_eq!(parsed[0].number, 42);
        assert_eq!(parsed[1].repo_name, "backend");
        assert_eq!(parsed[1].number, 99);
    }

    #[test]
    fn test_linked_pr_comment_roundtrip() {
        let adapter = BitbucketAdapter::new(None);
        let links = vec![LinkedPRRef {
            repo_name: "app".to_string(),
            number: 1,
        }];
        let comment = adapter.generate_linked_pr_comment(&links);
        let parsed = adapter.parse_linked_pr_comment(&comment);
        assert_eq!(parsed.len(), 1);
        assert_eq!(parsed[0].repo_name, "app");
        assert_eq!(parsed[0].number, 1);
    }

    #[test]
    fn test_api_base_url() {
        let adapter = BitbucketAdapter::new(None);
        assert_eq!(
            adapter.api_base_url("team", "repo"),
            "https://api.bitbucket.org/2.0/repositories/team/repo"
        );
    }

    #[test]
    fn test_api_base_url_custom() {
        let adapter = BitbucketAdapter::new(Some("https://bb.example.com/api"));
        assert_eq!(
            adapter.api_base_url("team", "repo"),
            "https://bb.example.com/api/repositories/team/repo"
        );
    }
}

//! Platform capability declarations
//!
//! Documents which optional operations each hosting platform supports,
//! allowing callers to check capability before attempting an operation.

use crate::core::manifest::PlatformType;

/// Optional capabilities that a hosting platform may support
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum PlatformCapability {
    /// Create a pull/merge request
    CreatePr,
    /// Merge a pull/merge request
    MergePr,
    /// Find an open PR by branch name
    FindPrByBranch,
    /// Get PR review status
    GetReviews,
    /// Get CI/CD status checks
    StatusChecks,
    /// Get allowed merge methods
    MergeMethods,
    /// Get PR diff
    PrDiff,
    /// Update a PR branch (merge base into head)
    UpdateBranch,
    /// Enable auto-merge when checks pass
    AutoMerge,
    /// Create a repository on the platform
    CreateRepo,
    /// Delete a repository from the platform
    DeleteRepo,
    /// Create a tagged release
    CreateRelease,
}

/// Returns the capabilities supported by the given platform type.
///
/// Core PR operations (create, merge, find, reviews, checks, diff, merge methods)
/// are implemented by all platforms. Optional operations vary.
pub fn platform_capabilities(platform: PlatformType) -> Vec<PlatformCapability> {
    use PlatformCapability::*;

    // All platforms support core PR operations
    let mut caps = vec![
        CreatePr,
        MergePr,
        FindPrByBranch,
        GetReviews,
        StatusChecks,
        MergeMethods,
        PrDiff,
    ];

    match platform {
        PlatformType::GitHub => {
            caps.extend([
                UpdateBranch,
                AutoMerge,
                CreateRepo,
                DeleteRepo,
                CreateRelease,
            ]);
        }
        PlatformType::GitLab => {
            caps.extend([CreateRepo, DeleteRepo]);
        }
        PlatformType::AzureDevOps => {
            caps.extend([CreateRepo, DeleteRepo]);
        }
        PlatformType::Bitbucket => {
            // Bitbucket only supports core PR operations
        }
    }

    caps
}

/// Check if a platform supports a specific capability
pub fn platform_supports(platform: PlatformType, capability: PlatformCapability) -> bool {
    platform_capabilities(platform).contains(&capability)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_github_has_all_capabilities() {
        let caps = platform_capabilities(PlatformType::GitHub);
        assert!(caps.contains(&PlatformCapability::CreatePr));
        assert!(caps.contains(&PlatformCapability::AutoMerge));
        assert!(caps.contains(&PlatformCapability::UpdateBranch));
        assert!(caps.contains(&PlatformCapability::CreateRepo));
        assert!(caps.contains(&PlatformCapability::DeleteRepo));
        assert!(caps.contains(&PlatformCapability::CreateRelease));
    }

    #[test]
    fn test_gitlab_has_repo_management() {
        let caps = platform_capabilities(PlatformType::GitLab);
        assert!(caps.contains(&PlatformCapability::CreatePr));
        assert!(caps.contains(&PlatformCapability::CreateRepo));
        assert!(caps.contains(&PlatformCapability::DeleteRepo));
        assert!(!caps.contains(&PlatformCapability::AutoMerge));
        assert!(!caps.contains(&PlatformCapability::CreateRelease));
    }

    #[test]
    fn test_azure_has_repo_management() {
        let caps = platform_capabilities(PlatformType::AzureDevOps);
        assert!(caps.contains(&PlatformCapability::CreatePr));
        assert!(caps.contains(&PlatformCapability::CreateRepo));
        assert!(!caps.contains(&PlatformCapability::AutoMerge));
    }

    #[test]
    fn test_bitbucket_core_only() {
        let caps = platform_capabilities(PlatformType::Bitbucket);
        assert!(caps.contains(&PlatformCapability::CreatePr));
        assert!(caps.contains(&PlatformCapability::MergePr));
        assert!(!caps.contains(&PlatformCapability::CreateRepo));
        assert!(!caps.contains(&PlatformCapability::AutoMerge));
        assert!(!caps.contains(&PlatformCapability::CreateRelease));
    }

    #[test]
    fn test_platform_supports() {
        assert!(platform_supports(
            PlatformType::GitHub,
            PlatformCapability::AutoMerge
        ));
        assert!(!platform_supports(
            PlatformType::Bitbucket,
            PlatformCapability::AutoMerge
        ));
    }
}

//! GitHub platform adapter

use async_trait::async_trait;
use octocrab::Octocrab;
use std::env;
use std::time::Duration;

use super::traits::{HostingPlatform, LinkedPRRef, PlatformError};
use super::types::*;
use crate::core::manifest::PlatformType;

/// Default connection timeout in seconds
const CONNECT_TIMEOUT_SECS: u64 = 10;
/// Default read timeout in seconds
const READ_TIMEOUT_SECS: u64 = 30;
/// Default write timeout in seconds
const WRITE_TIMEOUT_SECS: u64 = 30;

#[allow(unused_imports)]
use super::rate_limit::{check_rate_limit_warning, parse_github_rate_limits};

#[cfg(feature = "telemetry")]
use crate::telemetry::metrics::GLOBAL_METRICS;
#[cfg(feature = "telemetry")]
use std::time::Instant;
#[cfg(feature = "telemetry")]
use tracing::debug;

#[cfg(not(feature = "telemetry"))]
use tracing::debug;

/// GitHub API adapter
pub struct GitHubAdapter {
    base_url: Option<String>,
}

impl GitHubAdapter {
    /// Create a new GitHub adapter
    pub fn new(base_url: Option<&str>) -> Self {
        Self {
            base_url: base_url.map(|s| s.to_string()),
        }
    }

    /// Create a configured HTTP client with timeouts
    fn http_client() -> reqwest::Client {
        reqwest::Client::builder()
            .connect_timeout(Duration::from_secs(CONNECT_TIMEOUT_SECS))
            .timeout(Duration::from_secs(READ_TIMEOUT_SECS))
            .build()
            .unwrap_or_else(|err| {
                debug!(
                    error = %err,
                    "Failed to build HTTP client with timeouts; falling back to default client"
                );
                reqwest::Client::new()
            })
    }

    /// Get configured Octocrab instance with proper timeouts
    async fn get_client(&self) -> Result<Octocrab, PlatformError> {
        let token = self.get_token().await?;

        let mut builder = Octocrab::builder()
            .personal_token(token)
            .set_connect_timeout(Some(Duration::from_secs(CONNECT_TIMEOUT_SECS)))
            .set_read_timeout(Some(Duration::from_secs(READ_TIMEOUT_SECS)))
            .set_write_timeout(Some(Duration::from_secs(WRITE_TIMEOUT_SECS)));

        if let Some(ref base_url) = self.base_url {
            builder = builder
                .base_uri(base_url)
                .map_err(|e| PlatformError::ApiError(format!("Invalid base URL: {}", e)))?;
        }

        builder
            .build()
            .map_err(|e| PlatformError::ApiError(format!("Failed to create client: {}", e)))
    }
}

#[async_trait]
impl HostingPlatform for GitHubAdapter {
    fn platform_type(&self) -> PlatformType {
        PlatformType::GitHub
    }

    async fn get_token(&self) -> Result<String, PlatformError> {
        // Try environment variables first
        if let Ok(token) = env::var("GITHUB_TOKEN") {
            return Ok(token);
        }
        if let Ok(token) = env::var("GH_TOKEN") {
            return Ok(token);
        }

        // Try gh CLI auth
        debug!(target: "gitgrip::cmd", program = "gh", args = ?["auth", "token"], "exec");
        let output = tokio::process::Command::new("gh")
            .args(["auth", "token"])
            .output()
            .await
            .map_err(|e| PlatformError::AuthError(format!("Failed to run gh auth: {}", e)))?;

        if output.status.success() {
            let token = String::from_utf8_lossy(&output.stdout).trim().to_string();
            if !token.is_empty() {
                return Ok(token);
            }
        }

        Err(PlatformError::AuthError(
            "No GitHub token found. Set GITHUB_TOKEN or run 'gh auth login'".to_string(),
        ))
    }

    async fn create_pull_request(
        &self,
        owner: &str,
        repo: &str,
        head: &str,
        base: &str,
        title: &str,
        body: Option<&str>,
        draft: bool,
    ) -> Result<PRCreateResult, PlatformError> {
        #[cfg(feature = "telemetry")]
        let start = Instant::now();

        let client = self.get_client().await?;

        let result = client
            .pulls(owner, repo)
            .create(title, head, base)
            .body(body.unwrap_or(""))
            .draft(draft)
            .send()
            .await;

        #[cfg(feature = "telemetry")]
        {
            let duration = start.elapsed();
            let success = result.is_ok();
            GLOBAL_METRICS.record_platform("github", "create_pr", duration, success);
            debug!(
                owner,
                repo,
                head,
                base,
                draft,
                success,
                duration_ms = duration.as_millis() as u64,
                "GitHub create PR complete"
            );
        }

        let pr =
            result.map_err(|e| PlatformError::ApiError(format!("Failed to create PR: {}", e)))?;

        Ok(PRCreateResult {
            number: pr.number,
            url: pr.html_url.map(|u| u.to_string()).unwrap_or_default(),
        })
    }

    async fn get_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<PullRequest, PlatformError> {
        let client = self.get_client().await?;

        let pr = client
            .pulls(owner, repo)
            .get(pull_number)
            .await
            .map_err(|e| {
                if e.to_string().contains("404") {
                    PlatformError::NotFound(format!("PR #{} not found", pull_number))
                } else {
                    PlatformError::ApiError(format!("Failed to get PR: {}", e))
                }
            })?;

        let state = if pr.merged_at.is_some() {
            PRState::Merged
        } else {
            match pr.state {
                Some(octocrab::models::IssueState::Open) => PRState::Open,
                Some(octocrab::models::IssueState::Closed) => PRState::Closed,
                _ => PRState::Open,
            }
        };

        Ok(PullRequest {
            number: pr.number,
            url: pr.html_url.map(|u| u.to_string()).unwrap_or_default(),
            title: pr.title.clone().unwrap_or_default(),
            body: pr.body.clone().unwrap_or_default(),
            state,
            merged: pr.merged_at.is_some(),
            mergeable: pr.mergeable,
            head: PRHead {
                ref_name: pr.head.ref_field.clone(),
                sha: pr.head.sha.clone(),
            },
            base: PRBase {
                ref_name: pr.base.ref_field.clone(),
            },
        })
    }

    async fn update_pull_request_body(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        body: &str,
    ) -> Result<(), PlatformError> {
        let client = self.get_client().await?;

        client
            .pulls(owner, repo)
            .update(pull_number)
            .body(body)
            .send()
            .await
            .map_err(|e| PlatformError::ApiError(format!("Failed to update PR body: {}", e)))?;

        Ok(())
    }

    async fn merge_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        method: Option<MergeMethod>,
        _delete_branch: bool,
    ) -> Result<bool, PlatformError> {
        #[cfg(feature = "telemetry")]
        let start = Instant::now();

        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        let merge_method_str = match method.unwrap_or(MergeMethod::Merge) {
            MergeMethod::Merge => "merge",
            MergeMethod::Squash => "squash",
            MergeMethod::Rebase => "rebase",
        };

        let url = format!(
            "{}/repos/{}/{}/pulls/{}/merge",
            base_url, owner, repo, pull_number
        );

        let http_client = Self::http_client();
        let response = http_client
            .put(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .json(&serde_json::json!({ "merge_method": merge_method_str }))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        let status = response.status().as_u16();
        let body_text = response.text().await.unwrap_or_default();

        #[cfg(feature = "telemetry")]
        {
            let duration = start.elapsed();
            let success = status == 200;
            GLOBAL_METRICS.record_platform("github", "merge_pr", duration, success);
            debug!(
                owner,
                repo,
                pull_number,
                success,
                duration_ms = duration.as_millis() as u64,
                "GitHub merge PR complete"
            );
        }

        let body_lower = body_text.to_lowercase();

        match status {
            200 => {
                // Parse merged field from response
                if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(&body_text) {
                    Ok(parsed["merged"].as_bool().unwrap_or(false))
                } else {
                    Ok(true) // 200 status means success
                }
            }
            405 => {
                if body_lower.contains("head branch was behind")
                    || body_lower.contains("not up to date")
                {
                    Err(PlatformError::BranchBehind(format!(
                        "PR #{} branch is behind base branch",
                        pull_number
                    )))
                } else {
                    // Other 405 errors (not mergeable, checks required, etc.)
                    Err(PlatformError::ApiError(format!(
                        "PR #{} merge rejected (405): {}",
                        pull_number, body_text
                    )))
                }
            }
            403 => {
                if body_lower.contains("protected branch") || body_lower.contains("required") {
                    Err(PlatformError::BranchProtected(format!(
                        "PR #{} is blocked by branch protection rules",
                        pull_number
                    )))
                } else {
                    Err(PlatformError::ApiError(format!(
                        "Failed to merge PR (403): {}",
                        body_text
                    )))
                }
            }
            _ => Err(PlatformError::ApiError(format!(
                "Failed to merge PR ({}): {}",
                status, body_text
            ))),
        }
    }

    async fn update_branch(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<bool, PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        let url = format!(
            "{}/repos/{}/{}/pulls/{}/update-branch",
            base_url, owner, repo, pull_number
        );

        let http_client = Self::http_client();
        let response = http_client
            .put(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .json(&serde_json::json!({}))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        match response.status().as_u16() {
            202 => Ok(true),
            422 => Err(PlatformError::ApiError(
                "Cannot update branch: conflicts exist that must be resolved manually".to_string(),
            )),
            status => {
                let error_text = response.text().await.unwrap_or_default();
                Err(PlatformError::ApiError(format!(
                    "Failed to update branch ({}): {}",
                    status, error_text
                )))
            }
        }
    }

    /// Enable auto-merge via `gh` CLI. Uses the CLI instead of the GraphQL API
    /// because the REST API doesn't support auto-merge and the GraphQL mutation
    /// is complex.
    ///
    /// Supports GitHub Enterprise by passing `--hostname` when a custom
    /// `base_url` is configured.
    async fn enable_auto_merge(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        method: Option<MergeMethod>,
    ) -> Result<bool, PlatformError> {
        let merge_flag = match method.unwrap_or(MergeMethod::Squash) {
            MergeMethod::Merge => "--merge",
            MergeMethod::Squash => "--squash",
            MergeMethod::Rebase => "--rebase",
        };

        let repo_arg = format!("{}/{}", owner, repo);
        let pr_str = pull_number.to_string();

        // Extract hostname for GHE instances
        let ghe_hostname = self.base_url.as_ref().and_then(|url| {
            url::Url::parse(url).ok().and_then(|parsed| {
                let host = parsed.host_str()?.to_string();
                if host == "api.github.com" {
                    None // Standard GitHub, no --hostname needed
                } else {
                    Some(host)
                }
            })
        });

        let mut args = vec![
            "pr", "merge", &pr_str, "--auto", merge_flag, "--repo", &repo_arg,
        ];
        if let Some(ref hostname) = ghe_hostname {
            args.push("--hostname");
            args.push(hostname);
        }

        let mut cmd = tokio::process::Command::new("gh");
        cmd.args(&args);

        debug!(target: "gitgrip::cmd", program = "gh", args = ?args, "exec");
        let output = cmd
            .output()
            .await
            .map_err(|e| PlatformError::ApiError(format!("Failed to run gh CLI: {}", e)))?;

        if output.status.success() {
            Ok(true)
        } else {
            let stderr = String::from_utf8_lossy(&output.stderr);
            Err(PlatformError::ApiError(format!(
                "Failed to enable auto-merge for PR #{}: {}",
                pull_number,
                stderr.trim()
            )))
        }
    }

    async fn find_pr_by_branch(
        &self,
        owner: &str,
        repo: &str,
        branch: &str,
    ) -> Result<Option<PRCreateResult>, PlatformError> {
        let client = self.get_client().await?;

        let prs = client
            .pulls(owner, repo)
            .list()
            .state(octocrab::params::State::Open)
            .head(format!("{}:{}", owner, branch))
            .send()
            .await
            .map_err(|e| PlatformError::ApiError(format!("Failed to find PR: {}", e)))?;

        if let Some(pr) = prs.items.first() {
            Ok(Some(PRCreateResult {
                number: pr.number,
                url: pr
                    .html_url
                    .as_ref()
                    .map(|u| u.to_string())
                    .unwrap_or_default(),
            }))
        } else {
            Ok(None)
        }
    }

    async fn is_pull_request_approved(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<bool, PlatformError> {
        let reviews = self
            .get_pull_request_reviews(owner, repo, pull_number)
            .await?;

        // Check for at least one approval and no changes requested.
        // State comes from Debug formatting of octocrab's ReviewState enum,
        // which gives title case without underscores (e.g. "Approved", "ChangesRequested").
        let state_matches = |state: &str, target: &str| -> bool {
            let normalized: String = state.chars().filter(|c| *c != '_').collect();
            normalized.eq_ignore_ascii_case(target)
        };
        let has_approval = reviews.iter().any(|r| state_matches(&r.state, "Approved"));
        let has_changes_requested = reviews
            .iter()
            .any(|r| state_matches(&r.state, "ChangesRequested"));

        Ok(has_approval && !has_changes_requested)
    }

    async fn get_pull_request_reviews(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<Vec<PRReview>, PlatformError> {
        let client = self.get_client().await?;

        let reviews = client
            .pulls(owner, repo)
            .list_reviews(pull_number)
            .send()
            .await
            .map_err(|e| PlatformError::ApiError(format!("Failed to get reviews: {}", e)))?;

        Ok(reviews
            .items
            .iter()
            .map(|r| PRReview {
                state: r.state.map(|s| format!("{:?}", s)).unwrap_or_default(),
                user: r.user.as_ref().map(|u| u.login.clone()).unwrap_or_default(),
            })
            .collect())
    }

    async fn get_status_checks(
        &self,
        owner: &str,
        repo: &str,
        ref_name: &str,
    ) -> Result<StatusCheckResult, PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        // Try Check Runs API first (newer GitHub Actions)
        let check_runs_url = format!(
            "{}/repos/{}/{}/commits/{}/check-runs",
            base_url, owner, repo, ref_name
        );

        let http_client = Self::http_client();
        let response = http_client
            .get(&check_runs_url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if response.status().is_success() {
            #[derive(serde::Deserialize)]
            struct CheckRunsResponse {
                total_count: i64,
                check_runs: Vec<CheckRun>,
            }

            #[derive(serde::Deserialize)]
            struct CheckRun {
                name: String,
                status: String,
                conclusion: Option<String>,
            }

            let check_runs: CheckRunsResponse = response
                .json()
                .await
                .map_err(|e| PlatformError::ParseError(e.to_string()))?;

            if check_runs.total_count > 0 {
                // Determine overall state from check runs
                let (aggregate_state, statuses): (CheckState, Vec<StatusCheck>) =
                    check_runs.check_runs.into_iter().fold(
                        (CheckState::Success, Vec::new()),
                        |(aggregate_state, mut acc), cr| {
                            let check_state = match cr.conclusion.as_deref() {
                                Some("success") => CheckState::Success,
                                Some("failure") | Some("timed_out") => CheckState::Failure,
                                Some("cancelled") => CheckState::Failure,
                                _ => CheckState::Pending, // "in_progress", "queued", "neutral", or null
                            };

                            // Aggregate: any failure = failure, any pending = pending
                            let new_aggregate = match (aggregate_state, check_state) {
                                (CheckState::Failure, _) => CheckState::Failure,
                                (_, CheckState::Failure) => CheckState::Failure,
                                (CheckState::Pending, _) | (_, CheckState::Pending) => {
                                    CheckState::Pending
                                }
                                (CheckState::Success, CheckState::Success) => CheckState::Success,
                            };

                            acc.push(StatusCheck {
                                context: cr.name.clone(),
                                state: cr.conclusion.unwrap_or(cr.status),
                            });

                            (new_aggregate, acc)
                        },
                    );

                return Ok(StatusCheckResult {
                    state: aggregate_state,
                    statuses,
                });
            }
        }

        // Fallback to legacy status checks API
        let status_url = format!(
            "{}/repos/{}/{}/commits/{}/status",
            base_url, owner, repo, ref_name
        );

        let response = http_client
            .get(&status_url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            return Err(PlatformError::ApiError(format!(
                "Failed to get status: {}",
                response.status()
            )));
        }

        #[derive(serde::Deserialize)]
        struct CombinedStatus {
            state: String,
            statuses: Vec<StatusEntry>,
        }

        #[derive(serde::Deserialize)]
        struct StatusEntry {
            context: Option<String>,
            state: String,
        }

        let status: CombinedStatus = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        let state = match status.state.as_str() {
            "success" => CheckState::Success,
            "failure" | "error" => CheckState::Failure,
            _ => CheckState::Pending,
        };

        let statuses = status
            .statuses
            .iter()
            .map(|s| StatusCheck {
                context: s.context.clone().unwrap_or_default(),
                state: s.state.clone(),
            })
            .collect();

        Ok(StatusCheckResult { state, statuses })
    }

    async fn get_allowed_merge_methods(
        &self,
        owner: &str,
        repo: &str,
    ) -> Result<AllowedMergeMethods, PlatformError> {
        let client = self.get_client().await?;

        let repo_info = client
            .repos(owner, repo)
            .get()
            .await
            .map_err(|e| PlatformError::ApiError(format!("Failed to get repo: {}", e)))?;

        Ok(AllowedMergeMethods {
            merge: repo_info.allow_merge_commit.unwrap_or(true),
            squash: repo_info.allow_squash_merge.unwrap_or(true),
            rebase: repo_info.allow_rebase_merge.unwrap_or(true),
        })
    }

    async fn get_pull_request_diff(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<String, PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        let url = format!(
            "{}/repos/{}/{}/pulls/{}",
            base_url, owner, repo, pull_number
        );

        let client = Self::http_client();
        let response = client
            .get(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3.diff")
            .header("User-Agent", "gitgrip")
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            return Err(PlatformError::ApiError(format!(
                "Failed to get diff: {}",
                response.status()
            )));
        }

        response
            .text()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))
    }

    fn parse_repo_url(&self, url: &str) -> Option<ParsedRepoInfo> {
        // SSH format: git@github.com:owner/repo.git
        if url.starts_with("git@github.com:") {
            let path = url.trim_start_matches("git@github.com:");
            let path = path.trim_end_matches(".git");
            let parts: Vec<&str> = path.split('/').collect();
            if parts.len() >= 2 {
                return Some(ParsedRepoInfo {
                    owner: parts[0].to_string(),
                    repo: parts[parts.len() - 1].to_string(),
                    project: None,
                    platform: Some(PlatformType::GitHub),
                });
            }
        }

        // HTTPS format: https://github.com/owner/repo.git
        if url.contains("github.com") {
            let url = url.trim_end_matches(".git");
            let parts: Vec<&str> = url.split('/').collect();
            if parts.len() >= 2 {
                let owner_idx = parts.iter().position(|&p| p == "github.com")? + 1;
                if owner_idx + 1 < parts.len() {
                    return Some(ParsedRepoInfo {
                        owner: parts[owner_idx].to_string(),
                        repo: parts[owner_idx + 1].to_string(),
                        project: None,
                        platform: Some(PlatformType::GitHub),
                    });
                }
            }
        }

        None
    }

    fn matches_url(&self, url: &str) -> bool {
        url.contains("github.com")
    }

    async fn create_repository(
        &self,
        owner: &str,
        name: &str,
        description: Option<&str>,
        private: bool,
    ) -> Result<String, PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        // Check if owner is the authenticated user or an org
        // First, get the authenticated user
        let http_client = Self::http_client();

        let user_response = http_client
            .get(format!("{}/user", base_url))
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        #[derive(serde::Deserialize)]
        struct User {
            login: String,
        }

        let current_user: User = user_response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        // Determine the API endpoint based on whether owner is the user or an org
        let url = if owner.eq_ignore_ascii_case(&current_user.login) {
            format!("{}/user/repos", base_url)
        } else {
            format!("{}/orgs/{}/repos", base_url, owner)
        };

        #[derive(serde::Serialize)]
        struct CreateRepoRequest {
            name: String,
            #[serde(skip_serializing_if = "Option::is_none")]
            description: Option<String>,
            private: bool,
            auto_init: bool,
        }

        let response = http_client
            .post(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .json(&CreateRepoRequest {
                name: name.to_string(),
                description: description.map(|s| s.to_string()),
                private,
                auto_init: true, // Initialize with a README so there's a default branch
            })
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to create repository ({}): {}",
                status, error_text
            )));
        }

        #[derive(serde::Deserialize)]
        struct RepoResponse {
            ssh_url: String,
        }

        let repo: RepoResponse = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        Ok(repo.ssh_url)
    }

    async fn delete_repository(&self, owner: &str, name: &str) -> Result<(), PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");

        let http_client = Self::http_client();
        let url = format!("{}/repos/{}/{}", base_url, owner, name);

        let response = http_client
            .delete(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if response.status() == 404 {
            return Err(PlatformError::NotFound(format!(
                "Repository {}/{} not found",
                owner, name
            )));
        }

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to delete repository ({}): {}",
                status, error_text
            )));
        }

        Ok(())
    }

    async fn create_release(
        &self,
        owner: &str,
        repo: &str,
        tag: &str,
        name: &str,
        body: Option<&str>,
        target_commitish: &str,
        draft: bool,
        prerelease: bool,
    ) -> Result<ReleaseResult, PlatformError> {
        let token = self.get_token().await?;
        let base_url = self.base_url.as_deref().unwrap_or("https://api.github.com");
        let http_client = Self::http_client();

        #[derive(serde::Serialize)]
        struct CreateReleaseRequest {
            tag_name: String,
            target_commitish: String,
            name: String,
            #[serde(skip_serializing_if = "Option::is_none")]
            body: Option<String>,
            draft: bool,
            prerelease: bool,
        }

        let url = format!("{}/repos/{}/{}/releases", base_url, owner, repo);
        let response = http_client
            .post(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Accept", "application/vnd.github.v3+json")
            .header("User-Agent", "gitgrip")
            .json(&CreateReleaseRequest {
                tag_name: tag.to_string(),
                target_commitish: target_commitish.to_string(),
                name: name.to_string(),
                body: body.map(|s| s.to_string()),
                draft,
                prerelease,
            })
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to create release ({}): {}",
                status, error_text
            )));
        }

        #[derive(serde::Deserialize)]
        struct ReleaseResponse {
            id: u64,
            tag_name: String,
            html_url: String,
        }

        let release: ReleaseResponse = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        Ok(ReleaseResult {
            id: release.id,
            tag: release.tag_name,
            url: release.html_url,
        })
    }

    fn generate_linked_pr_comment(&self, links: &[LinkedPRRef]) -> String {
        if links.is_empty() {
            return String::new();
        }

        let mut comment = String::from("<!-- gitgrip-linked-prs\n");
        for link in links {
            comment.push_str(&format!("{}:{}\n", link.repo_name, link.number));
        }
        comment.push_str("-->");
        comment
    }

    fn parse_linked_pr_comment(&self, body: &str) -> Vec<LinkedPRRef> {
        let start_marker = "<!-- gitgrip-linked-prs";
        let end_marker = "-->";

        let Some(start) = body.find(start_marker) else {
            return Vec::new();
        };

        let content_start = start + start_marker.len();
        let Some(end) = body[content_start..].find(end_marker) else {
            return Vec::new();
        };

        let content = &body[content_start..content_start + end];

        content
            .lines()
            .filter_map(|line| {
                let line = line.trim();
                if line.is_empty() {
                    return None;
                }

                let parts: Vec<&str> = line.splitn(2, ':').collect();
                if parts.len() != 2 {
                    return None;
                }

                let number = parts[1].parse().ok()?;
                Some(LinkedPRRef {
                    repo_name: parts[0].to_string(),
                    number,
                })
            })
            .collect()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_github_ssh_url() {
        let adapter = GitHubAdapter::new(None);

        let result = adapter.parse_repo_url("git@github.com:user/repo.git");
        assert!(result.is_some());
        let info = result.unwrap();
        assert_eq!(info.owner, "user");
        assert_eq!(info.repo, "repo");
    }

    #[test]
    fn test_parse_github_https_url() {
        let adapter = GitHubAdapter::new(None);

        let result = adapter.parse_repo_url("https://github.com/user/repo.git");
        assert!(result.is_some());
        let info = result.unwrap();
        assert_eq!(info.owner, "user");
        assert_eq!(info.repo, "repo");
    }

    #[test]
    fn test_matches_url() {
        let adapter = GitHubAdapter::new(None);

        assert!(adapter.matches_url("git@github.com:user/repo.git"));
        assert!(adapter.matches_url("https://github.com/user/repo.git"));
        assert!(!adapter.matches_url("git@gitlab.com:user/repo.git"));
    }

    #[test]
    fn test_linked_pr_comment_roundtrip() {
        let adapter = GitHubAdapter::new(None);

        let links = vec![
            LinkedPRRef {
                repo_name: "frontend".to_string(),
                number: 42,
            },
            LinkedPRRef {
                repo_name: "backend".to_string(),
                number: 123,
            },
        ];

        let comment = adapter.generate_linked_pr_comment(&links);
        let parsed = adapter.parse_linked_pr_comment(&comment);

        assert_eq!(parsed.len(), 2);
        assert_eq!(parsed[0].repo_name, "frontend");
        assert_eq!(parsed[0].number, 42);
        assert_eq!(parsed[1].repo_name, "backend");
        assert_eq!(parsed[1].number, 123);
    }
}

//! GitLab platform adapter

use async_trait::async_trait;
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::time::Duration;

use super::traits::{HostingPlatform, LinkedPRRef, PlatformError};
use super::types::*;
use crate::core::manifest::PlatformType;
use tracing::debug;

/// Default connection timeout in seconds
const CONNECT_TIMEOUT_SECS: u64 = 10;
/// Default request timeout in seconds
const REQUEST_TIMEOUT_SECS: u64 = 30;

/// GitLab merge request response
#[derive(Debug, Deserialize)]
struct GitLabMergeRequest {
    iid: u64,
    web_url: String,
    title: String,
    description: Option<String>,
    state: String, // opened, closed, merged
    merge_status: Option<String>,
    detailed_merge_status: Option<String>,
    source_branch: String,
    target_branch: String,
    sha: String,
}

/// GitLab approval response
#[derive(Debug, Deserialize)]
struct GitLabApproval {
    approved: bool,
    approved_by: Vec<ApprovedBy>,
}

#[derive(Debug, Deserialize)]
struct ApprovedBy {
    user: ApprovalUser,
}

#[derive(Debug, Deserialize)]
struct ApprovalUser {
    username: String,
}

/// GitLab pipeline
#[derive(Debug, Deserialize)]
struct GitLabPipeline {
    status: String, // success, failed, running, pending, canceled, skipped
}

/// GitLab API adapter
pub struct GitLabAdapter {
    base_url: String,
    http_client: Client,
}

impl GitLabAdapter {
    /// Create a new GitLab adapter
    pub fn new(base_url: Option<&str>) -> Self {
        let http_client = Client::builder()
            .connect_timeout(Duration::from_secs(CONNECT_TIMEOUT_SECS))
            .timeout(Duration::from_secs(REQUEST_TIMEOUT_SECS))
            .build()
            .unwrap_or_else(|_| Client::new());

        Self {
            base_url: base_url.unwrap_or("https://gitlab.com").to_string(),
            http_client,
        }
    }

    /// Encode project path for GitLab API (owner/repo -> owner%2Frepo)
    fn encode_project(&self, owner: &str, repo: &str) -> String {
        urlencoding::encode(&format!("{}/{}", owner, repo)).into_owned()
    }

    /// Get the namespace (group) ID for the given owner/path
    async fn get_namespace_id(&self, owner: &str) -> Result<Option<u64>, PlatformError> {
        let token = self.get_token().await?;
        let encoded_owner = urlencoding::encode(owner);
        let url = format!("{}/api/v4/namespaces/{}", self.base_url, encoded_owner);

        let response = self
            .http_client
            .get(&url)
            .header("Authorization", format!("Bearer {}", token))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if response.status() == 404 {
            // Namespace not found - might be the user's personal namespace
            return Ok(None);
        }

        if !response.status().is_success() {
            // Just return None if we can't find it - GitLab will use the user's namespace
            return Ok(None);
        }

        #[derive(Deserialize)]
        struct Namespace {
            id: u64,
        }

        let namespace: Namespace = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        Ok(Some(namespace.id))
    }

    /// Make authenticated API request
    async fn api_request<T: for<'de> Deserialize<'de>>(
        &self,
        method: reqwest::Method,
        endpoint: &str,
        body: Option<impl Serialize>,
    ) -> Result<T, PlatformError> {
        let token = self.get_token().await?;
        let url = format!("{}/api/v4{}", self.base_url, endpoint);

        let mut request = self
            .http_client
            .request(method, &url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Content-Type", "application/json");

        if let Some(b) = body {
            request = request.json(&b);
        }

        let response = request
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "GitLab API error ({}): {}",
                status, error_text
            )));
        }

        response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))
    }

    /// Make PUT request
    async fn api_put(
        &self,
        endpoint: &str,
        body: Option<impl Serialize>,
    ) -> Result<(), PlatformError> {
        let token = self.get_token().await?;
        let url = format!("{}/api/v4{}", self.base_url, endpoint);

        let mut request = self
            .http_client
            .put(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Content-Type", "application/json");

        if let Some(b) = body {
            request = request.json(&b);
        }

        let response = request
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "GitLab API error ({}): {}",
                status, error_text
            )));
        }

        Ok(())
    }
}

#[async_trait]
impl HostingPlatform for GitLabAdapter {
    fn platform_type(&self) -> PlatformType {
        PlatformType::GitLab
    }

    async fn get_token(&self) -> Result<String, PlatformError> {
        // Try environment variable first
        if let Ok(token) = env::var("GITLAB_TOKEN") {
            return Ok(token);
        }

        // Try glab CLI
        debug!(target: "gitgrip::cmd", program = "glab", args = ?["auth", "status", "-t"], "exec");
        let output = tokio::process::Command::new("glab")
            .args(["auth", "status", "-t"])
            .output()
            .await;

        if let Ok(output) = output {
            let stdout = String::from_utf8_lossy(&output.stdout);
            let stderr = String::from_utf8_lossy(&output.stderr);
            let combined = format!("{}{}", stdout, stderr);

            // Parse token from glab output: "✓ Token found: glpat-..." or "Token: glpat-..."
            if let Some(token_match) = combined.lines().find(|l| l.contains("Token")) {
                if let Some(token) = token_match.split_whitespace().last() {
                    // Token should start with glpat- or be a hex string
                    if !token.is_empty()
                        && token != "Token:"
                        && token != "Token"
                        && token != "found:"
                    {
                        return Ok(token.to_string());
                    }
                }
            }
        }

        Err(PlatformError::AuthError(
            "GitLab token not found. Set GITLAB_TOKEN or run 'glab auth login'".to_string(),
        ))
    }

    async fn create_pull_request(
        &self,
        owner: &str,
        repo: &str,
        head: &str,
        base: &str,
        title: &str,
        body: Option<&str>,
        draft: bool,
    ) -> Result<PRCreateResult, PlatformError> {
        let project_id = self.encode_project(owner, repo);
        let mr_title = if draft {
            format!("Draft: {}", title)
        } else {
            title.to_string()
        };

        #[derive(Serialize)]
        struct CreateMR {
            source_branch: String,
            target_branch: String,
            title: String,
            description: String,
        }

        let mr: GitLabMergeRequest = self
            .api_request(
                reqwest::Method::POST,
                &format!("/projects/{}/merge_requests", project_id),
                Some(CreateMR {
                    source_branch: head.to_string(),
                    target_branch: base.to_string(),
                    title: mr_title,
                    description: body.unwrap_or("").to_string(),
                }),
            )
            .await?;

        Ok(PRCreateResult {
            number: mr.iid,
            url: mr.web_url,
        })
    }

    async fn get_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<PullRequest, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        let mr: GitLabMergeRequest = self
            .api_request(
                reqwest::Method::GET,
                &format!("/projects/{}/merge_requests/{}", project_id, pull_number),
                None::<()>,
            )
            .await?;

        // Map GitLab state to our unified state
        let (state, merged) = match mr.state.as_str() {
            "merged" => (PRState::Merged, true),
            "closed" => (PRState::Closed, false),
            _ => (PRState::Open, false),
        };

        // GitLab uses detailed_merge_status for mergeability
        let mergeable = mr.detailed_merge_status.as_deref() == Some("mergeable")
            || mr.merge_status.as_deref() == Some("can_be_merged");

        Ok(PullRequest {
            number: mr.iid,
            url: mr.web_url,
            title: mr.title,
            body: mr.description.unwrap_or_default(),
            state,
            merged,
            mergeable: Some(mergeable),
            head: PRHead {
                ref_name: mr.source_branch,
                sha: mr.sha,
            },
            base: PRBase {
                ref_name: mr.target_branch,
            },
        })
    }

    async fn update_pull_request_body(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        body: &str,
    ) -> Result<(), PlatformError> {
        let project_id = self.encode_project(owner, repo);

        #[derive(Serialize)]
        struct UpdateBody {
            description: String,
        }

        self.api_put(
            &format!("/projects/{}/merge_requests/{}", project_id, pull_number),
            Some(UpdateBody {
                description: body.to_string(),
            }),
        )
        .await
    }

    async fn merge_pull_request(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
        method: Option<MergeMethod>,
        delete_branch: bool,
    ) -> Result<bool, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        #[derive(Serialize)]
        struct MergeParams {
            #[serde(skip_serializing_if = "Option::is_none")]
            squash: Option<bool>,
            #[serde(skip_serializing_if = "Option::is_none")]
            should_remove_source_branch: Option<bool>,
        }

        let params = MergeParams {
            squash: if matches!(method, Some(MergeMethod::Squash)) {
                Some(true)
            } else {
                None
            },
            should_remove_source_branch: if delete_branch { Some(true) } else { None },
        };

        let result = self
            .api_put(
                &format!(
                    "/projects/{}/merge_requests/{}/merge",
                    project_id, pull_number
                ),
                Some(params),
            )
            .await;

        match result {
            Ok(()) => Ok(true),
            Err(_) => Ok(false),
        }
    }

    async fn find_pr_by_branch(
        &self,
        owner: &str,
        repo: &str,
        branch: &str,
    ) -> Result<Option<PRCreateResult>, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        let mrs: Vec<GitLabMergeRequest> = self
            .api_request(
                reqwest::Method::GET,
                &format!(
                    "/projects/{}/merge_requests?source_branch={}&state=opened",
                    project_id,
                    urlencoding::encode(branch)
                ),
                None::<()>,
            )
            .await?;

        if let Some(mr) = mrs.first() {
            Ok(Some(PRCreateResult {
                number: mr.iid,
                url: mr.web_url.clone(),
            }))
        } else {
            Ok(None)
        }
    }

    async fn is_pull_request_approved(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<bool, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        let result: Result<GitLabApproval, _> = self
            .api_request(
                reqwest::Method::GET,
                &format!(
                    "/projects/{}/merge_requests/{}/approvals",
                    project_id, pull_number
                ),
                None::<()>,
            )
            .await;

        match result {
            Ok(approval) => Ok(approval.approved),
            Err(_) => {
                // Approvals API might not be available (requires license)
                Ok(false)
            }
        }
    }

    async fn get_pull_request_reviews(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<Vec<PRReview>, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        let result: Result<GitLabApproval, _> = self
            .api_request(
                reqwest::Method::GET,
                &format!(
                    "/projects/{}/merge_requests/{}/approvals",
                    project_id, pull_number
                ),
                None::<()>,
            )
            .await;

        match result {
            Ok(approval) => Ok(approval
                .approved_by
                .iter()
                .map(|a| PRReview {
                    state: "APPROVED".to_string(),
                    user: a.user.username.clone(),
                })
                .collect()),
            Err(_) => Ok(vec![]),
        }
    }

    async fn get_status_checks(
        &self,
        owner: &str,
        repo: &str,
        ref_name: &str,
    ) -> Result<StatusCheckResult, PlatformError> {
        let project_id = self.encode_project(owner, repo);

        let result: Result<Vec<GitLabPipeline>, _> = self
            .api_request(
                reqwest::Method::GET,
                &format!(
                    "/projects/{}/pipelines?sha={}&per_page=1",
                    project_id, ref_name
                ),
                None::<()>,
            )
            .await;

        match result {
            Ok(pipelines) => {
                if pipelines.is_empty() {
                    return Ok(StatusCheckResult {
                        state: CheckState::Success,
                        statuses: vec![],
                    });
                }

                let pipeline = &pipelines[0];

                let state = match pipeline.status.as_str() {
                    "success" => CheckState::Success,
                    "failed" | "canceled" => CheckState::Failure,
                    _ => CheckState::Pending,
                };

                Ok(StatusCheckResult {
                    state,
                    statuses: vec![StatusCheck {
                        context: "gitlab-pipeline".to_string(),
                        state: pipeline.status.clone(),
                    }],
                })
            }
            Err(_) => Ok(StatusCheckResult {
                state: CheckState::Success,
                statuses: vec![],
            }),
        }
    }

    async fn get_allowed_merge_methods(
        &self,
        _owner: &str,
        _repo: &str,
    ) -> Result<AllowedMergeMethods, PlatformError> {
        // GitLab generally allows merge and squash (rebase depends on project settings)
        Ok(AllowedMergeMethods {
            merge: true,
            squash: true,
            rebase: true,
        })
    }

    async fn get_pull_request_diff(
        &self,
        owner: &str,
        repo: &str,
        pull_number: u64,
    ) -> Result<String, PlatformError> {
        let project_id = self.encode_project(owner, repo);
        let token = self.get_token().await?;

        // Get MR changes
        let url = format!(
            "{}/api/v4/projects/{}/merge_requests/{}/changes",
            self.base_url, project_id, pull_number
        );

        let response = self
            .http_client
            .get(&url)
            .header("Authorization", format!("Bearer {}", token))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            return Err(PlatformError::ApiError(format!(
                "Failed to get MR changes: {}",
                response.status()
            )));
        }

        #[derive(Deserialize)]
        struct Change {
            old_path: String,
            new_path: String,
            diff: String,
        }

        #[derive(Deserialize)]
        struct ChangesResponse {
            changes: Vec<Change>,
        }

        let changes: ChangesResponse = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        let mut diff = String::new();
        for change in &changes.changes {
            diff.push_str(&format!("--- a/{}\n", change.old_path));
            diff.push_str(&format!("+++ b/{}\n", change.new_path));
            diff.push_str(&change.diff);
            diff.push('\n');
        }

        Ok(diff)
    }

    fn parse_repo_url(&self, url: &str) -> Option<ParsedRepoInfo> {
        // SSH format: git@gitlab.com:owner/repo.git or git@gitlab.com:group/subgroup/repo.git
        if url.starts_with("git@") && url.contains("gitlab") {
            let path = url.split(':').nth(1)?;
            let path = path.trim_end_matches(".git");
            let parts: Vec<&str> = path.split('/').collect();
            if parts.len() >= 2 {
                let repo = parts.last()?.to_string();
                let owner = parts[..parts.len() - 1].join("/");
                return Some(ParsedRepoInfo {
                    owner,
                    repo,
                    project: None,
                    platform: Some(PlatformType::GitLab),
                });
            }
        }

        // HTTPS format: https://gitlab.com/owner/repo.git
        if url.contains("gitlab") && url.contains("://") {
            let path = url.split('/').skip(3).collect::<Vec<_>>().join("/");
            let path = path.trim_end_matches(".git");
            let parts: Vec<&str> = path.split('/').collect();
            if parts.len() >= 2 {
                let repo = parts.last()?.to_string();
                let owner = parts[..parts.len() - 1].join("/");
                return Some(ParsedRepoInfo {
                    owner,
                    repo,
                    project: None,
                    platform: Some(PlatformType::GitLab),
                });
            }
        }

        None
    }

    fn matches_url(&self, url: &str) -> bool {
        // Check for gitlab.com
        if url.contains("gitlab.com") {
            return true;
        }

        // Check if URL appears to be GitLab (contains gitlab in hostname)
        if url.contains("://gitlab.") || url.contains("@gitlab.") {
            return true;
        }

        false
    }

    async fn create_repository(
        &self,
        owner: &str,
        name: &str,
        description: Option<&str>,
        private: bool,
    ) -> Result<String, PlatformError> {
        let token = self.get_token().await?;
        let url = format!("{}/api/v4/projects", self.base_url);

        // GitLab visibility levels: private, internal, public
        let visibility = if private { "private" } else { "public" };

        #[derive(Serialize)]
        struct CreateProjectRequest {
            name: String,
            path: String,
            #[serde(skip_serializing_if = "Option::is_none")]
            namespace_id: Option<u64>,
            #[serde(skip_serializing_if = "Option::is_none")]
            description: Option<String>,
            visibility: String,
            initialize_with_readme: bool,
        }

        // Try to get the namespace (group) ID for the owner
        let namespace_id = self.get_namespace_id(owner).await?;

        let response = self
            .http_client
            .post(&url)
            .header("Authorization", format!("Bearer {}", token))
            .header("Content-Type", "application/json")
            .json(&CreateProjectRequest {
                name: name.to_string(),
                path: name.to_string(),
                namespace_id,
                description: description.map(|s| s.to_string()),
                visibility: visibility.to_string(),
                initialize_with_readme: true,
            })
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to create project ({}): {}",
                status, error_text
            )));
        }

        #[derive(Deserialize)]
        struct ProjectResponse {
            ssh_url_to_repo: String,
        }

        let project: ProjectResponse = response
            .json()
            .await
            .map_err(|e| PlatformError::ParseError(e.to_string()))?;

        Ok(project.ssh_url_to_repo)
    }

    async fn delete_repository(&self, owner: &str, name: &str) -> Result<(), PlatformError> {
        let token = self.get_token().await?;
        let project_id = self.encode_project(owner, name);
        let url = format!("{}/api/v4/projects/{}", self.base_url, project_id);

        let response = self
            .http_client
            .delete(&url)
            .header("Authorization", format!("Bearer {}", token))
            .send()
            .await
            .map_err(|e| PlatformError::NetworkError(e.to_string()))?;

        if response.status() == 404 {
            return Err(PlatformError::NotFound(format!(
                "Project {}/{} not found",
                owner, name
            )));
        }

        if !response.status().is_success() {
            let status = response.status();
            let error_text = response.text().await.unwrap_or_default();
            return Err(PlatformError::ApiError(format!(
                "Failed to delete project ({}): {}",
                status, error_text
            )));
        }

        Ok(())
    }

    fn generate_linked_pr_comment(&self, links: &[LinkedPRRef]) -> String {
        if links.is_empty() {
            return String::new();
        }

        let mut comment = String::from("<!-- gitgrip-linked-prs\n");
        for link in links {
            comment.push_str(&format!("{}:{}\n", link.repo_name, link.number));
        }
        comment.push_str("-->");
        comment
    }

    fn parse_linked_pr_comment(&self, body: &str) -> Vec<LinkedPRRef> {
        let start_marker = "<!-- gitgrip-linked-prs";
        let end_marker = "-->";

        let Some(start) = body.find(start_marker) else {
            return Vec::new();
        };

        let content_start = start + start_marker.len();
        let Some(end) = body[content_start..].find(end_marker) else {
            return Vec::new();
        };

        let content = &body[content_start..content_start + end];

        content
            .lines()
            .filter_map(|line| {
                let line = line.trim();
                if line.is_empty() {
                    return None;
                }

                let parts: Vec<&str> = line.splitn(2, ':').collect();
                if parts.len() != 2 {
                    return None;
                }

                let number = parts[1].parse().ok()?;
                Some(LinkedPRRef {
                    repo_name: parts[0].to_string(),
                    number,
                })
            })
            .collect()
    }
}

