    #[test]
    fn test_calculate_delay() {
        let options = RetryOptions {
            initial_delay_ms: 1000,
            max_delay_ms: 30000,
            jitter: 0.0, // No jitter for predictable testing
            ..Default::default()
        };

        // First attempt: 1000ms
        let delay0 = options.calculate_delay(0);
        assert_eq!(delay0.as_millis(), 1000);

        // Second attempt: 2000ms
        let delay1 = options.calculate_delay(1);
        assert_eq!(delay1.as_millis(), 2000);

        // Third attempt: 4000ms
        let delay2 = options.calculate_delay(2);
        assert_eq!(delay2.as_millis(), 4000);
    }

    #[test]
    fn test_max_delay_clamping() {
        let options = RetryOptions {
            initial_delay_ms: 1000,
            max_delay_ms: 5000,
            jitter: 0.0,
            ..Default::default()
        };

        // 1000 * 2^10 = 1024000, should clamp to 5000
        let delay = options.calculate_delay(10);
        assert_eq!(delay.as_millis(), 5000);
    }

    #[test]
    fn test_is_retryable_error() {
        assert!(is_retryable_error("ECONNRESET"));
        assert!(is_retryable_error("connection timeout"));
        assert!(is_retryable_error("HTTP 429 Too Many Requests"));
        assert!(is_retryable_error("HTTP 503 Service Unavailable"));
        assert!(!is_retryable_error("Not found"));
        assert!(!is_retryable_error("HTTP 404"));
        assert!(!is_retryable_error("Invalid token"));
    }

    #[tokio::test]
    async fn test_retry_success_first_try() {
        let options = RetryOptions::default();
        let result: Result<i32, &str> = retry_with_backoff(&options, || async { Ok(42) }).await;
        assert_eq!(result.unwrap(), 42);
    }

    #[tokio::test]
    async fn test_retry_non_retryable_error() {
        let options = RetryOptions {
            max_retries: 3,
            initial_delay_ms: 10,
            ..Default::default()
        };

        let mut attempts = 0;
        let result: Result<i32, String> = retry_with_backoff(&options, || {
            attempts += 1;
            async { Err("Not found".to_string()) }
        })
        .await;

        assert!(result.is_err());
        assert_eq!(attempts, 1); // Should not retry non-retryable errors
    }

    #[test]
    fn test_calculate_delay_with_jitter() {
        let options = RetryOptions {
            initial_delay_ms: 1000,
            max_delay_ms: 30000,
            jitter: 0.5,
            ..Default::default()
        };
        let delay = options.calculate_delay(0);
        // With jitter 0.5, delay should be between 1000 and 1500ms
        assert!(delay.as_millis() >= 1000);
        assert!(delay.as_millis() <= 1500);
    }

    #[test]
    fn test_default_retry_options() {
        let opts = RetryOptions::default();
        assert_eq!(opts.max_retries, 3);
        assert_eq!(opts.initial_delay_ms, 1000);
        assert_eq!(opts.max_delay_ms, 30000);
        assert!((opts.jitter - 0.1).abs() < f64::EPSILON);
    }

    #[test]
    fn test_is_retryable_error_case_insensitive() {
        assert!(is_retryable_error("Connection Reset by peer"));
        assert!(is_retryable_error("TIMEOUT waiting for response"));
        assert!(is_retryable_error("Rate Limit exceeded"));
    }

    #[test]
    fn test_is_retryable_error_http_codes() {
        assert!(is_retryable_error("HTTP 500 Internal Server Error"));
        assert!(is_retryable_error("HTTP 502 Bad Gateway"));
        assert!(is_retryable_error("HTTP 504 Gateway Timeout"));
        assert!(!is_retryable_error("HTTP 401 Unauthorized"));
        assert!(!is_retryable_error("HTTP 403 Forbidden"));
    }

    #[tokio::test]
    async fn test_retry_with_callback_success() {
        let options = RetryOptions::default();
        let result: Result<i32, String> =
            retry_with_callback(&options, || async { Ok(42) }, None).await;
        assert_eq!(result.unwrap(), 42);
    }

    #[tokio::test]
    async fn test_retry_with_callback_invoked() {
        use std::sync::{Arc, Mutex};

        let options = RetryOptions {
            max_retries: 2,
            initial_delay_ms: 1,
            max_delay_ms: 10,
            jitter: 0.0,
        };

        let callback_calls = Arc::new(Mutex::new(Vec::new()));
        let cb_clone = callback_calls.clone();
        let on_retry: OnRetryFn = Box::new(move |attempt, error, _delay| {
            cb_clone
                .lock()
                .unwrap()
                .push((attempt, error.to_string()));
        });

        let mut attempt = 0;
        let _result: Result<i32, String> = retry_with_callback(
            &options,
            || {
                attempt += 1;
                async move { Err("connection timeout".to_string()) }
            },
            Some(on_retry),
        )
        .await;

        let calls = callback_calls.lock().unwrap();
        assert_eq!(calls.len(), 2); // Called on retry 1 and 2
        assert_eq!(calls[0].0, 1);
        assert_eq!(calls[1].0, 2);
    }

    #[tokio::test]
    async fn test_retry_exhausts_max_retries() {
        let options = RetryOptions {
            max_retries: 2,
            initial_delay_ms: 1,
            max_delay_ms: 10,
            jitter: 0.0,
        };

        let mut attempts = 0;
        let result: Result<i32, String> = retry_with_backoff(&options, || {
            attempts += 1;
            async { Err("ECONNRESET".to_string()) }
        })
        .await;

        assert!(result.is_err());
        assert_eq!(attempts, 3); // 1 initial + 2 retries
    }
}

//! Timing and benchmarking utilities
//!
//! Provides tools for measuring performance and comparing with TypeScript version.

use std::time::{Duration, Instant};

/// A timing entry for hierarchical measurements
#[derive(Debug, Clone)]
pub struct TimingEntry {
    /// Label for this timing
    pub label: String,
    /// Duration in milliseconds
    pub duration_ms: f64,
    /// Nested timings
    pub children: Vec<TimingEntry>,
}

impl TimingEntry {
    /// Create a new timing entry
    pub fn new(label: &str, duration: Duration) -> Self {
        Self {
            label: label.to_string(),
            duration_ms: duration.as_secs_f64() * 1000.0,
            children: Vec::new(),
        }
    }

    /// Add a child timing
    pub fn add_child(&mut self, child: TimingEntry) {
        self.children.push(child);
    }
}

/// A complete timing report
#[derive(Debug, Clone)]
pub struct TimingReport {
    /// Total duration in milliseconds
    pub total_ms: f64,
    /// Individual timing entries
    pub entries: Vec<TimingEntry>,
}

impl TimingReport {
    /// Create a new empty report
    pub fn new() -> Self {
        Self {
            total_ms: 0.0,
            entries: Vec::new(),
        }
    }

    /// Add a timing entry
    pub fn add_entry(&mut self, entry: TimingEntry) {
        self.total_ms += entry.duration_ms;
        self.entries.push(entry);
    }

    /// Print a formatted report
    pub fn print(&self) {
        println!("\n--- Timing Report ---");
        for entry in &self.entries {
            print_entry(entry, 0);
        }
        println!("---------------------");
        println!("Total: {:.2}ms", self.total_ms);
    }
}

fn print_entry(entry: &TimingEntry, depth: usize) {
    let indent = "  ".repeat(depth);
    println!("{}{}: {:.2}ms", indent, entry.label, entry.duration_ms);
    for child in &entry.children {
        print_entry(child, depth + 1);
    }
}

impl Default for TimingReport {
    fn default() -> Self {
        Self::new()
    }
}

/// A simple timer for measuring durations
#[derive(Debug)]
pub struct Timer {
    start: Instant,
    label: String,
    checkpoints: Vec<(String, Duration)>,
}

impl Timer {
    /// Create and start a new timer
    pub fn new(label: &str) -> Self {
        Self {
            start: Instant::now(),
            label: label.to_string(),
            checkpoints: Vec::new(),
        }
    }

    /// Start a new timer (alias for new)
    pub fn start(label: &str) -> Self {
        Self::new(label)
    }

    /// Get elapsed time without stopping
    pub fn elapsed(&self) -> Duration {
        self.start.elapsed()
    }

    /// Get elapsed time in milliseconds
    pub fn elapsed_ms(&self) -> f64 {
        self.start.elapsed().as_secs_f64() * 1000.0
    }

    /// Record a checkpoint with the current elapsed time
    pub fn checkpoint(&mut self, label: &str) {
        self.checkpoints
            .push((label.to_string(), self.start.elapsed()));
    }

    /// Stop and return a timing entry
    pub fn stop(self) -> TimingEntry {
        let mut entry = TimingEntry::new(&self.label, self.start.elapsed());
        let mut prev_time = Duration::ZERO;
        for (label, time) in &self.checkpoints {
            let delta = *time - prev_time;
            entry.add_child(TimingEntry::new(label, delta));
            prev_time = *time;
        }
        entry
    }

    /// Stop and print the duration
    pub fn stop_and_print(self) {
        println!("{}: {:.2}ms", self.label, self.elapsed_ms());
        if !self.checkpoints.is_empty() {
            let mut prev_time = Duration::ZERO;
            for (label, time) in &self.checkpoints {
                let delta = *time - prev_time;
                let delta_ms = delta.as_secs_f64() * 1000.0;
                println!("  {}: {:.2}ms", label, delta_ms);
                prev_time = *time;
            }
        }
    }
}

/// Benchmark result for a single operation
#[derive(Debug, Clone)]
pub struct BenchmarkResult {
    /// Benchmark name
    pub name: String,
    /// Number of iterations
    pub iterations: u32,
    /// Minimum duration in milliseconds
    pub min_ms: f64,
    /// Maximum duration in milliseconds
    pub max_ms: f64,
    /// Average duration in milliseconds
    pub avg_ms: f64,
    /// Median (50th percentile)
    pub p50_ms: f64,
    /// 95th percentile
    pub p95_ms: f64,
    /// Standard deviation
    pub std_dev_ms: f64,
}

impl BenchmarkResult {
    /// Print a formatted benchmark result
    pub fn print(&self) {
        println!("\n--- Benchmark: {} ---", self.name);
        println!("Iterations: {}", self.iterations);
        println!("Min:    {:.3}ms", self.min_ms);
        println!("Max:    {:.3}ms", self.max_ms);
        println!("Avg:    {:.3}ms", self.avg_ms);
        println!("P50:    {:.3}ms", self.p50_ms);
        println!("P95:    {:.3}ms", self.p95_ms);
        println!("StdDev: {:.3}ms", self.std_dev_ms);
    }

    /// Format as a comparison-friendly string
    pub fn to_comparison_string(&self) -> String {
        format!(
            "{}: avg={:.3}ms, p50={:.3}ms, p95={:.3}ms (n={})",
            self.name, self.avg_ms, self.p50_ms, self.p95_ms, self.iterations
        )
    }
}

/// Run a benchmark
pub fn benchmark<F>(name: &str, iterations: u32, mut f: F) -> BenchmarkResult
where
    F: FnMut(),
{
    let mut durations: Vec<f64> = Vec::with_capacity(iterations as usize);

    // Warmup
    for _ in 0..3 {
        f();
    }

    // Actual benchmark
    for _ in 0..iterations {
        let start = Instant::now();
        f();
        durations.push(start.elapsed().as_secs_f64() * 1000.0);
    }

    // Sort for percentile calculations
    durations.sort_by(|a, b| a.partial_cmp(b).unwrap());

    let min = durations[0];
    let max = durations[durations.len() - 1];
    let sum: f64 = durations.iter().sum();
    let avg = sum / iterations as f64;

    let p50_idx = (iterations as f64 * 0.50) as usize;
    let p95_idx = (iterations as f64 * 0.95) as usize;
    let p50 = durations[p50_idx.min(durations.len() - 1)];
    let p95 = durations[p95_idx.min(durations.len() - 1)];

    // Standard deviation
    let variance: f64 =
        durations.iter().map(|d| (d - avg).powi(2)).sum::<f64>() / iterations as f64;
    let std_dev = variance.sqrt();

    BenchmarkResult {
        name: name.to_string(),
        iterations,
        min_ms: min,
        max_ms: max,
        avg_ms: avg,
        p50_ms: p50,
        p95_ms: p95,
        std_dev_ms: std_dev,
    }
}

/// Run an async benchmark
pub async fn benchmark_async<F, Fut>(name: &str, iterations: u32, mut f: F) -> BenchmarkResult
where
    F: FnMut() -> Fut,
    Fut: std::future::Future<Output = ()>,
{
    let mut durations: Vec<f64> = Vec::with_capacity(iterations as usize);

    // Warmup
    for _ in 0..3 {
        f().await;
    }

    // Actual benchmark
    for _ in 0..iterations {
        let start = Instant::now();
        f().await;
        durations.push(start.elapsed().as_secs_f64() * 1000.0);
    }

    // Sort for percentile calculations
    durations.sort_by(|a, b| a.partial_cmp(b).unwrap());

    let min = durations[0];
    let max = durations[durations.len() - 1];
    let sum: f64 = durations.iter().sum();
    let avg = sum / iterations as f64;

    let p50_idx = (iterations as f64 * 0.50) as usize;
    let p95_idx = (iterations as f64 * 0.95) as usize;
    let p50 = durations[p50_idx.min(durations.len() - 1)];
    let p95 = durations[p95_idx.min(durations.len() - 1)];

    let variance: f64 =
        durations.iter().map(|d| (d - avg).powi(2)).sum::<f64>() / iterations as f64;
    let std_dev = variance.sqrt();

    BenchmarkResult {
        name: name.to_string(),
        iterations,
        min_ms: min,
        max_ms: max,
        avg_ms: avg,
        p50_ms: p50,
        p95_ms: p95,
        std_dev_ms: std_dev,
    }
}

